class Solution {
public:
    int maxRemovals(string playlist, string favoriteSequence, vector<int>& removableIndices) {
        int n = playlist.length();
        int m = favoriteSequence.length();

        auto canRemove = [&](int k) -> bool {
            set<int> removed;
            for (int i = 0; i < k; i++) {
                removed.insert(removableIndices[i]);
            }

            int j = 0;
            for (int i = 0; i < n && j < m; i++) {
                if (removed.count(i)) continue;
                if (playlist[i] == favoriteSequence[j]) {
                    j++;
                }
            }
            return j == m;
        };

        int left = 0, right = removableIndices.size();
        int result = 0;

        while (left <= right) {
            int mid = (left + right) / 2;
            if (canRemove(mid)) {
                result = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return result;
    }
};

