		for i := 0; i < n && j < m; i++ {
			if !removed[i] && playlist[i] == favoriteSequence[j] {
				j++
			}
		}
		return j == m
	}

	left, right := 0, k
	result := 0

	for left <= right {
		mid := (left + right) / 2
		if canRemove(mid) {
			result = mid
			left = mid + 1
		} else {
			right = mid - 1
		}
	}

	return result
