public class Solution {

    public int maxRemovals(String playlist, String favoriteSequence, int[] removableIndices) {
        int n = playlist.length();
        int m = favoriteSequence.length();

        boolean[] canRemove = new boolean[n];
        for (int idx : removableIndices) {
            canRemove[idx] = true;
        }

        int left = 0, right = removableIndices.length;
        int result = 0;

        while (left <= right) {
            int mid = left + (right - left) / 2;

            boolean[] removed = new boolean[n];
            for (int i = 0; i < mid; i++) {
                removed[removableIndices[i]] = true;
            }

            if (isSubsequence(playlist, favoriteSequence, removed)) {
                result = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return result;
    }

    private boolean isSubsequence(String playlist, String favoriteSequence, boolean[] removed) {
        int i = 0, j = 0;

        while (i < playlist.length() && j < favoriteSequence.length()) {
            if (!removed[i] && playlist.charAt(i) == favoriteSequence.charAt(j)) {
                j++;
            }
            i++;
        }

        return j == favoriteSequence.length();
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        String playlist = br.readLine().trim();
        String favoriteSequence = br.readLine().trim();

        String[] removableStr = br.readLine().trim().split("\\s+");
