        for (int i = 0; i < removableStr.length; i++) {
            removableIndices[i] = Integer.parseInt(removableStr[i]);
        }

        Solution solution = new Solution();
        int result = solution.maxRemovals(playlist, favoriteSequence, removableIndices);
        System.out.println(result);
    }
}

