using namespace std;

class Solution {
public:
    int maxRemovals(string playlist, string favoriteSequence, vector<int>& removableIndices) {
        int n = playlist.length();
        int m = favoriteSequence.length();
        int k = removableIndices.size();

        vector<bool> is_removable(n, false);
        for (int idx : removableIndices) {
            is_removable[idx] = true;
        }

        vector<vector<int>> dp(n + 1, vector<int>(m + 1, -1e9));
        dp[0][0] = 0;

        for (int i = 0; i < n; ++i) {
            for (int j = 0; j <= m; ++j) {
                if (dp[i][j] < 0) continue;

                int cost = is_removable[i] ? 1 : 0;
                dp[i + 1][j] = max(dp[i + 1][j], dp[i][j] + cost);

                if (j < m && playlist[i] == favoriteSequence[j]) {
                    dp[i + 1][j + 1] = max(dp[i + 1][j + 1], dp[i][j]);
                }
            }
        }

        return dp[n][m];
    }
};

