        int n = nums.length;
        int count = 0;

        for (int i = 0; i < n; i++) {
            Map<Integer, Integer> freq = new HashMap<>();
            for (int j = i; j < n; j++) {
                freq.put(nums[j], freq.getOrDefault(nums[j], 0) + 1);

                boolean hasValidElement = false;
                for (int f : freq.values()) {
