using namespace std;

class Solution {
public:
    vector<int> maximumValue(vector<vector<int>>& events) {
        int n = events.size();
        vector<int> indices(n);
        for (int i = 0; i < n; i++) {
            indices[i] = i;
        }

        sort(indices.begin(), indices.end(), [&](int a, int b) {
            return events[a][1] < events[b][1];
        });

        long long maxValue = 0;
        vector<int> result;

        function<void(int, vector<int>&, long long)> backtrack = [&](int pos, vector<int>& current, long long currentValue) {
            if (current.size() == 4 || pos == n) {
                if (currentValue > maxValue || (currentValue == maxValue && isLexSmaller(current, result))) {
                    maxValue = currentValue;
                    result = current;
                }
                return;
            }

            backtrack(pos + 1, current, currentValue);

            int idx = indices[pos];
            bool canAdd = true;
            for (int prevIdx : current) {
                if (!(events[prevIdx][1] < events[idx][0] || events[idx][1] < events[prevIdx][0])) {
                    canAdd = false;
                    break;
                }
            }

            if (canAdd) {
                current.push_back(idx);
                backtrack(pos + 1, current, currentValue + events[idx][2]);
                current.pop_back();
            }
        };

        vector<int> current;
        backtrack(0, current, 0);

        sort(result.begin(), result.end());
        return result;
    }

private:
    bool isLexSmaller(const vector<int>& a, const vector<int>& b) {
        if (b.empty()) return false;
        if (a.empty()) return true;

        vector<int> sortedA = a, sortedB = b;
        sort(sortedA.begin(), sortedA.end());
        sort(sortedB.begin(), sortedB.end());

        return sortedA < sortedB;
    }
};

