		fmt.Scan(&events[i][0], &events[i][1], &events[i][2])
	}

	result := maximumValue(events)
	for i, idx := range result {
		if i > 0 {
			fmt.Print(" ")
		}
		fmt.Print(idx)
	}
	fmt.Println()
}

func maximumValue(events [][]int) []int {
	n := len(events)

	type State struct {
		value int
		indices []int
	}

	var maxValue int
	var bestIndices []int

	var backtrack func(start int, selected []int, totalValue int)
	backtrack = func(start int, selected []int, totalValue int) {
		if len(selected) == 4 || start == n {
			if totalValue > maxValue || (totalValue == maxValue && isLexSmaller(selected, bestIndices)) {
				maxValue = totalValue
				bestIndices = make([]int, len(selected))
				copy(bestIndices, selected)
			}
			return
		}

		backtrack(start+1, selected, totalValue)

		canAdd := true
		for _, idx := range selected {
			if overlaps(events[idx], events[start]) {
				canAdd = false
				break
			}
		}

		if canAdd {
