func isLexSmaller(a, b []int) bool {
	if len(b) == 0 {
		return false
	}
	if len(a) == 0 {
		return true
	}

	minLen := len(a)
	if len(b) < minLen {
		minLen = len(b)
	}

	for i := 0; i < minLen; i++ {
		if a[i] < b[i] {
			return true
		}
		if a[i] > b[i] {
			return false
		}
	}

	return len(a) < len(b)
}

