class Solution:
    def maximumValue(self, events: List[List[int]]) -> List[int]:
        n = len(events)

        def overlaps(i, j):
            return not (events[i][1] < events[j][0] or events[j][1] < events[i][0])

        max_value = 0
        best_indices = []

        def backtrack(start_idx, current_indices, current_value, count):
            nonlocal max_value, best_indices

            if count == 4:
                if current_value > max_value or (current_value == max_value and current_indices < best_indices):
                    max_value = current_value
                    best_indices = current_indices[:]
                return

            if start_idx >= n:
                if current_value > max_value or (current_value == max_value and current_indices < best_indices):
                    max_value = current_value
                    best_indices = current_indices[:]
                return

            for i in range(start_idx, n):
                can_add = True
                for j in current_indices:
                    if overlaps(i, j):
                        can_add = False
                        break

                if can_add:
                    current_indices.append(i)
                    backtrack(i + 1, current_indices, current_value + events[i][2], count + 1)
                    current_indices.pop()

            if current_value > max_value or (current_value == max_value and current_indices < best_indices):
                max_value = current_value
                best_indices = current_indices[:]

        backtrack(0, [], 0, 0)
        return best_indices

