};

struct State {
    long long total_val;
    vector<int> indices;

    bool operator<(const State& other) const {
        if (total_val != other.total_val) return total_val < other.total_val;
        return indices > other.indices;
    }
};

int main() {
    int s, e, v;
    vector<Event> events;
    int idx = 0;
    while (cin >> s >> e >> v) {
        events.push_back({s, e, v, idx++});
    }

    int n = events.size();
    sort(events.begin(), events.end(), [](const Event& a, const Event& b) {
        return a.start < b.start;
    });

    vector<vector<State>> dp(5, vector<State>(n + 1, {0, {}}));

    for (int k = 1; k <= 4; ++k) {
        for (int i = n - 1; i >= 0; --i) {
            dp[k][i] = dp[k][i + 1];

            int low = i + 1, high = n - 1, next_idx = n;
            while (low <= high) {
                int mid = low + (high - low) / 2;
                if (events[mid].start > events[i].end) {
                    next_idx = mid;
                    high = mid - 1;
                } else {
                    low = mid + 1;
                }
            }

            State current;
            current.total_val = (long long)events[i].value + dp[k - 1][next_idx].total_val;
            current.indices = {events[i].original_idx};
            for (int id : dp[k - 1][next_idx].indices) current.indices.push_back(id);
            sort(current.indices.begin(), current.indices.end());

            if (dp[k][i] < current) {
                dp[k][i] = current;
            }
        }
    }

    State best = {0, {}};
    for (int k = 1; k <= 4; ++k) {
        if (best < dp[k][0]) {
            best = dp[k][0];
        }
    }

    for (int i = 0; i < best.indices.size(); ++i) {
        cout << best.indices[i] << (i == best.indices.size() - 1 ? "" : " ");
    }
    cout << endl;

    return 0;
}

