func solve() {
	scanner := bufio.NewScanner(os.Stdin)
	var input string
	for scanner.Scan() {
		input += scanner.Text()
	}

	var eventsRaw [][]int
	json.Unmarshal([]byte(input), &eventsRaw)

	n := len(eventsRaw)
	events := make([]Event, n)
	for i := 0; i < n; i++ {
		events[i] = Event{eventsRaw[i][0], eventsRaw[i][1], eventsRaw[i][2], i}
	}

	sort.Slice(events, func(i, j int) bool {
		return events[i].start < events[j].start
	})

	type State struct {
		val int64
		ids []int
	}

	compare := func(a, b State) bool {
		if a.val != b.val {
			return a.val > b.val
		}
		la, lb := len(a.ids), len(b.ids)
		minL := la
		if lb < minL {
			minL = lb
		}
		for i := 0; i < minL; i++ {
			if a.ids[i] != b.ids[i] {
				return a.ids[i] < b.ids[i]
			}
		}
		return la < lb
	}

	dp := make([][]State, 5)
	for i := 0; i < 5; i++ {
		dp[i] = make([]State, n+1)
	}

	for k := 1; k <= 4; k++ {
		dp[k][n] = State{-1, []int{}}
		for i := n - 1; i >= 0; i-- {
			res1 := dp[k][i+1]

			idx := sort.Search(n, func(j int) bool {
				return events[j].start > events[i].end
			})

			var res2 State
			if dp[k-1][idx].val != -1 {
				newIds := make([]int, len(dp[k-1][idx].ids)+1)
				newIds[0] = events[i].id
				copy(newIds[1:], dp[k-1][idx].ids)
				sort.Ints(newIds)
				res2 = State{int64(events[i].val) + dp[k-1][idx].val, newIds}
			} else {
				res2 = State{int64(events[i].val), []int{events[i].id}}
			}

			if compare(res2, res1) {
				dp[k][i] = res2
			} else {
				dp[k][i] = res1
			}
		}
	}

	best := State{-1, []int{}}
	for k := 1; k <= 4; k++ {
		if compare(dp[k][0], best) {
			best = dp[k][0]
		}
	}

	resJson, _ := json.Marshal(best.ids)
	fmt.Println(string(resJson))
}

