from bisect import bisect_left

class Solution:
    def maximumValue(self, events):
        n = len(events)
        indexed_events = []
        for i in range(n):
            indexed_events.append((events[i][0], events[i][1], events[i][2], i))

        indexed_events.sort()
        starts = [e[0] for e in indexed_events]

        memo = {}

        def solve(idx, count):
            if count == 0 or idx == n:
                return (0, [])

            state = (idx, count)
            if state in memo:
                return memo[state]

            v_skip, res_skip = solve(idx + 1, count)

            next_idx = bisect_left(starts, indexed_events[idx][1] + 1)
            v_take_rest, res_take_rest = solve(next_idx, count - 1)
            v_take = indexed_events[idx][2] + v_take_rest
            res_take = sorted([indexed_events[idx][3]] + res_take_rest)

            if v_take > v_skip:
                ans = (v_take, res_take)
            elif v_skip > v_take:
                ans = (v_skip, res_skip)
            else:
                if res_take < res_skip:
                    ans = (v_take, res_take)
                else:
                    ans = (v_skip, res_skip)

            memo[state] = ans
            return ans

        dp = [[(0, []) for _ in range(5)] for _ in range(n + 1)]

        for i in range(n - 1, -1, -1):
            next_idx = bisect_left(starts, indexed_events[i][1] + 1)
            for j in range(1, 5):
                v_skip, res_skip = dp[i+1][j]

                v_rest, res_rest = dp[next_idx][j-1]
                v_take = indexed_events[i][2] + v_rest
                res_take = sorted([indexed_events[i][3]] + res_rest)

                if v_take > v_skip:
                    dp[i][j] = (v_take, res_take)
                elif v_skip > v_take:
                    dp[i][j] = (v_skip, res_skip)
                else:
                    if res_take < res_skip or not res_skip:
                        dp[i][j] = (v_take, res_take)
                    else:
                        dp[i][j] = (v_skip, res_skip)

        return dp[0][4][1]

