const int MOD = 1000000007;

class Solution {
private:
    unordered_map<string, long long> memo;
    string danceMoves;
    int n;

    string makeKey(int round, char lastMove, int scoreDiff) {
        return to_string(round) + "," + lastMove + "," + to_string(scoreDiff);
    }

    int getPoints(char player1Move, char player2Move) {
        if (player1Move == player2Move) return 0;
        if (player1Move == 'H' && player2Move == 'B') return -1;
        if (player1Move == 'B' && player2Move == 'H') return 1;
        if (player1Move == 'S' && player2Move == 'H') return -1;
        if (player1Move == 'H' && player2Move == 'S') return 1;
        if (player1Move == 'B' && player2Move == 'S') return -1;
        if (player1Move == 'S' && player2Move == 'B') return 1;
        return 0;
    }

    long long solve(int round, char lastMove, int scoreDiff) {
        if (round == n) {
            return scoreDiff > 0 ? 1 : 0;
        }

        string key = makeKey(round, lastMove, scoreDiff);
        if (memo.find(key) != memo.end()) {
            return memo[key];
        }

        long long result = 0;
        vector<char> moves = {'H', 'S', 'B'};

        for (char move : moves) {
            if (round > 0 && move == lastMove) continue;

            int points = getPoints(danceMoves[round], move);
            int newScoreDiff = scoreDiff + points;

            result = (result + solve(round + 1, move, newScoreDiff)) % MOD;
        }

        memo[key] = result;
        return result;
    }

public:
    int countVictorySequences(string danceMoves) {
        this->danceMoves = danceMoves;
        this->n = danceMoves.length();
        memo.clear();
        return solve(0, '\0', 0);
    }
};

