func countVictorySequences(danceMoves string) int {
    n := len(danceMoves)
    memo := make(map[string]int)

    var dp func(pos int, lastMove int, score int) int
    dp = func(pos int, lastMove int, score int) int {
        if pos == n {
            if score > 0 {
                return 1
            }
            return 0
        }

        key := fmt.Sprintf("%d_%d_%d", pos, lastMove, score)
        if val, exists := memo[key]; exists {
            return val
        }

        result := 0
        player1Move := danceMoves[pos]

        for player2Move := 0; player2Move < 3; player2Move++ {
            if player2Move == lastMove {
                continue
            }

            newScore := score
            if getWinner(player1Move, player2Move) == 2 {
                newScore++
            } else if getWinner(player1Move, player2Move) == 1 {
                newScore--
            }

            result = (result + dp(pos+1, player2Move, newScore)) % MOD
        }

        memo[key] = result
        return result
    }

    return dp(0, -1, 0)
}

func getWinner(p1Move byte, p2Move int) int {
    p1 := charToInt(p1Move)

    if p1 == p2Move {
        return 0
    }

    if (p1 == 0 && p2Move == 2) || (p1 == 1 && p2Move == 0) || (p1 == 2 && p2Move == 1) {
        return 1
    }

    return 2
}

func charToInt(c byte) int {
    if c == 'H' {
        return 0
    } else if c == 'S' {
        return 1
    }
    return 2
}

