public class Solution {
    private static final int MOD = 1000000007;
    private Map<String, Long> memo;
    private String danceMoves;
    private int n;

    public long countVictorySequences(String danceMoves) {
        this.danceMoves = danceMoves;
        this.n = danceMoves.length();
        this.memo = new HashMap<>();

        long result = 0;
        result = (result + dp(0, 'H', 0)) % MOD;
        result = (result + dp(0, 'S', 0)) % MOD;
        result = (result + dp(0, 'B', 0)) % MOD;

        return result;
    }

    private long dp(int pos, char lastMove, int scoreDiff) {
        if (pos == n) {
            return scoreDiff > 0 ? 1 : 0;
        }

        String key = pos + "," + lastMove + "," + scoreDiff;
        if (memo.containsKey(key)) {
            return memo.get(key);
        }

        long result = 0;
        char player1Move = danceMoves.charAt(pos);

        for (char player2Move : new char[]{'H', 'S', 'B'}) {
            if (pos > 0 && player2Move == lastMove) {
                continue;
            }

            int points = getPoints(player1Move, player2Move);
            int newScoreDiff = scoreDiff + points;

            result = (result + dp(pos + 1, player2Move, newScoreDiff)) % MOD;
        }

        memo.put(key, result);
        return result;
    }

    private int getPoints(char player1, char player2) {
        if (player1 == player2) return 0;

        if ((player1 == 'H' && player2 == 'B') ||
            (player1 == 'S' && player2 == 'H') ||
            (player1 == 'B' && player2 == 'S')) {
            return -1;
        } else {
            return 1;
        }
    }

