class Solution:
    def countVictorySequences(self, danceMoves: str) -> int:
        MOD = 10**9 + 7
        n = len(danceMoves)

        def wins(p1_move, p2_move):
            if p1_move == p2_move:
                return 0
            if (p1_move == 'H' and p2_move == 'B') or \
               (p1_move == 'S' and p2_move == 'H') or \
               (p1_move == 'B' and p2_move == 'S'):
                return 1
            return -1

        moves = ['H', 'S', 'B']
        memo = {}

        def dp(round_idx, last_move, score_diff):
            if round_idx == n:
                return 1 if score_diff < 0 else 0

            if (round_idx, last_move, score_diff) in memo:
                return memo[(round_idx, last_move, score_diff)]

            result = 0
            for move in moves:
                if move != last_move:
                    point_change = wins(danceMoves[round_idx], move)
                    new_score_diff = score_diff + point_change
                    result = (result + dp(round_idx + 1, move, new_score_diff)) % MOD

            memo[(round_idx, last_move, score_diff)] = result
            return result

        return dp(0, None, 0)

