                if (p2 == 1) return 1;
                if (p2 == 2) return -1;
            } else if (p1 == 'S') {
                if (p2 == 2) return 1;
                if (p2 == 0) return -1;
            } else if (p1 == 'B') {
                if (p2 == 0) return 1;
                if (p2 == 1) return -1;
            }
            return 0;
        };

        for (int j = 0; j < 3; ++j) {
            int s = get_score(danceMoves[0], j);
            dp[j][j][s + offset] = 1;
        }

        for (int i = 1; i < n; ++i) {
            vector<vector<vector<long long>>> next_dp(3, vector<vector<long long>>(3, vector<long long>(2 * n + 1, 0)));
            for (int curr = 0; curr < 3; ++curr) {
                int s_inc = get_score(danceMoves[i], curr);
                for (int prev = 0; prev < 3; ++prev) {
                    if (curr == prev) continue;
                    for (int first = 0; first < 3; ++first) {
                        for (int s = 0; s <= 2 * n; ++s) {
                            if (dp[prev][first][s] == 0) continue;
                            int next_s = s + s_inc;
                            if (next_s >= 0 && next_s <= 2 * n) {
                                next_dp[curr][first][next_s] = (next_dp[curr][first][next_s] + dp[prev][first][s]) % MOD;
                            }
                        }
                    }
                }
            }
            dp = move(next_dp);
        }

        long long total = 0;
        for (int last = 0; last < 3; ++last) {
            for (int first = 0; first < 3; ++first) {
                for (int s = offset + 1; s <= 2 * n; ++s) {
                    total = (total + dp[last][first][s]) % MOD;
                }
            }
        }
        return (int)total;
    }
};

