func solve() {
	var s string
	_, err := fmt.Scan(&s)
	if err != nil && err != io.EOF {
		return
	}
	if s == "" {
		return
	}

	n := len(s)
	mod := 1000000007

	moveMap := make([]int, n)
	for i := 0; i < n; i++ {
		if s[i] == 'H' {
			moveMap[i] = 0
		} else if s[i] == 'S' {
			moveMap[i] = 1
		} else {
			moveMap[i] = 2
		}
	}

	getScore := func(p2, p1 int) int {
		if p2 == p1 {
			return 0
		}
		if (p2 == 0 && p1 == 2) || (p2 == 1 && p1 == 0) || (p2 == 2 && p1 == 1) {
			return 1
		}
		return -1
	}

	dp := make([][]int, 2*n+1)
	for i := range dp {
		dp[i] = make([]int, 3)
	}

	for j := 0; j < 3; j++ {
		score := getScore(j, moveMap[0])
		dp[score+n][j] = 1
	}

	for i := 1; i < n; i++ {
		nextDp := make([][]int, 2*n+1)
		for k := range nextDp {
			nextDp[k] = make([]int, 3)
		}
		p1Move := moveMap[i]
		for sIdx := 0; sIdx <= 2*n; sIdx++ {
			for prevMove := 0; prevMove < 3; prevMove++ {
				if dp[sIdx][prevMove] == 0 {
					continue
				}
				for currMove := 0; currMove < 3; currMove++ {
					if currMove == prevMove {
						continue
					}
					gain := getScore(currMove, p1Move)
					newS := sIdx + gain
					if newS >= 0 && newS <= 2*n {
						nextDp[newS][currMove] = (nextDp[newS][currMove] + dp[sIdx][prevMove]) % mod
					}
				}
			}
		}
		dp = nextDp
	}

	ans := 0
	for sIdx := n + 1; sIdx <= 2*n; sIdx++ {
		for j := 0; j < 3; j++ {
			ans = (ans + dp[sIdx][j]) % mod
		}
	}
	fmt.Println(ans)
}

