class Solution {
    public int countVictorySequences(String danceMoves) {
        int n = danceMoves.length();
        int MOD = 1000000007;
        int offset = n;
        int[][][] dp = new int[3][2 * n + 1][3];

        int[] moves = new int[n];
        for (int i = 0; i < n; i++) {
            char c = danceMoves.charAt(i);
            if (c == 'H') moves[i] = 0;
            else if (c == 'S') moves[i] = 1;
            else moves[i] = 2;
        }

        for (int j = 0; j < 3; j++) {
            int score = getScore(j, moves[0]);
            dp[0][offset + score][j] = 1;
        }

        for (int i = 1; i < n; i++) {
            int curr = i % 3;
            int prev = (i - 1) % 3;
            for (int s = 0; s <= 2 * n; s++) {
                Arrays.fill(dp[curr][s], 0);
            }

            int p1Move = moves[i];
            for (int s = 0; s <= 2 * n; s++) {
                for (int lastMove = 0; lastMove < 3; lastMove++) {
                    if (dp[prev][s][lastMove] == 0) continue;

                    for (int currMove = 0; currMove < 3; currMove++) {
                        if (currMove == lastMove) continue;

                        int score = getScore(currMove, p1Move);
                        int nextS = s + score;
                        if (nextS >= 0 && nextS <= 2 * n) {
                            dp[curr][nextS][currMove] = (dp[curr][nextS][currMove] + dp[prev][s][lastMove]) % MOD;
                        }
                    }
                }
            }
        }

        long total = 0;
        int lastIdx = (n - 1) % 3;
        for (int s = offset + 1; s <= 2 * n; s++) {
            for (int j = 0; j < 3; j++) {
                total = (total + dp[lastIdx][s][j]) % MOD;
            }
        }

        return (int) total;
    }

    private int getScore(int p2, int p1) {
        if (p2 == p1) return 0;
        if ((p2 == 0 && p1 == 2) || (p2 == 1 && p1 == 0) || (p2 == 2 && p1 == 1)) return 1;
        return -1;
    }
}

