class Solution:
    def countVictorySequences(self, danceMoves: str) -> int:
        n = len(danceMoves)
        MOD = 10**9 + 7

        move_map = {'H': 0, 'S': 1, 'B': 2}
        p1_moves = [move_map[c] for c in danceMoves]

        dp = {}

        def get_score(p1, p2):
            if (p2 == 0 and p1 == 2) or (p2 == 1 and p1 == 0) or (p2 == 2 and p1 == 1):
                return 1
            if (p1 == 0 and p2 == 2) or (p1 == 1 and p2 == 0) or (p1 == 2 and p2 == 1):
                return -1
            return 0

        dp = [[0] * (2 * n + 1) for _ in range(4)]
        dp[3][n] = 1

        for i in range(n):
            new_dp = [[0] * (2 * n + 1) for _ in range(4)]
            p1 = p1_moves[i]
            for prev_p2 in range(4):
                for diff in range(2 * n + 1):
                    if dp[prev_p2][diff] == 0:
                        continue

                    for p2 in range(3):
                        if p2 == prev_p2:
                            continue

                        score = get_score(p1, p2)
                        new_diff = diff + score
                        if 0 <= new_diff <= 2 * n:
                            new_dp[p2][new_diff] = (new_dp[p2][new_diff] + dp[prev_p2][diff]) % MOD
            dp = new_dp

        ans = 0
        for p2 in range(3):
            for diff in range(n + 1, 2 * n + 1):
                ans = (ans + dp[p2][diff]) % MOD
        return ans

