    public int rotateCost(String g, String h, int[] forwardCost, int[] backwardCost) {
        int totalCost = 0;

        for (int i = 0; i < g.length(); i++) {
            char from = g.charAt(i);
            char to = h.charAt(i);

            if (from == to) {
                continue;
            }

            int forwardSteps = (to - from + 26) % 26;
            int backwardSteps = (from - to + 26) % 26;

            int forwardTotalCost = 0;
            char current = from;
            for (int step = 0; step < forwardSteps; step++) {
                forwardTotalCost += forwardCost[current - 'a'];
                current = (char)((current - 'a' + 1) % 26 + 'a');
            }

            int backwardTotalCost = 0;
            current = from;
            for (int step = 0; step < backwardSteps; step++) {
                backwardTotalCost += backwardCost[current - 'a'];
                current = (char)((current - 'a' - 1 + 26) % 26 + 'a');
            }

            totalCost += Math.min(forwardTotalCost, backwardTotalCost);
        }

        return totalCost;
    }

