class Solution {
public:
    long long rotateCost(string g, string h, vector<int>& forwardCost, vector<int>& backwardCost) {
        vector<vector<long long>> dist(26, vector<long long>(26, -1));
        for (int i = 0; i < 26; ++i) {
            priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;
            pq.push({0, i});
            dist[i][i] = 0;
            while (!pq.empty()) {
                long long d = pq.top().first;
                int u = pq.top().second;
                pq.pop();
                if (d > dist[i][u] && dist[i][u] != -1) continue;
                int v_f = (u + 1) % 26;
                long long cost_f = (long long)forwardCost[u];
                if (dist[i][v_f] == -1 || dist[i][v_f] > d + cost_f) {
                    dist[i][v_f] = d + cost_f;
                    pq.push({dist[i][v_f], v_f});
                }
                int v_b = (u - 1 + 26) % 26;
                long long cost_b = (long long)backwardCost[u];
                if (dist[i][v_b] == -1 || dist[i][v_b] > d + cost_b) {
                    dist[i][v_b] = d + cost_b;
                    pq.push({dist[i][v_b], v_b});
                }
            }
        }
        long long totalCost = 0;
        for (int i = 0; i < g.length(); ++i) {
            totalCost += dist[g[i] - 'a'][h[i] - 'a'];
        }
        return totalCost;
    }
};

