long long gcd(long long a, long long b) {
    while (b) {
        a %= b;
        swap(a, b);
    }
    return a;
}

long long lcm(long long a, long long b) {
    return a / gcd(a, b) * b;
}

long long calculateGCD(const vector<int>& nums) {
    if (nums.empty()) return 0;
    long long result = nums[0];
    for (int i = 1; i < nums.size(); i++) {
        result = gcd(result, nums[i]);
    }
    return result;
}

long long calculateLCM(const vector<int>& nums) {
    if (nums.empty()) return 0;
    long long result = nums[0];
    for (int i = 1; i < nums.size(); i++) {
        result = lcm(result, nums[i]);
    }
    return result;
}

long long calculateMaximumCompositeStrength(vector<int>& strengths) {
    int n = strengths.size();
    if (n == 0) return 0;

    long long maxStrength = 0;


    long long g = calculateGCD(strengths);
    long long l = calculateLCM(strengths);
    maxStrength = max(maxStrength, g * l);


    for (int i = 0; i < n; i++) {
        vector<int> temp;
        for (int j = 0; j < n; j++) {
            if (i != j) {
                temp.push_back(strengths[j]);
            }
        }

        if (temp.empty()) {
            maxStrength = max(maxStrength, 0LL);
        } else {
            g = calculateGCD(temp);
            l = calculateLCM(temp);
            maxStrength = max(maxStrength, g * l);
        }
    }

    return maxStrength;
}

