func gcd(a, b int) int {
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

func lcm(a, b int) int {
	return a * b / gcd(a, b)
}

func gcdArray(arr []int) int {
	if len(arr) == 0 {
		return 0
	}
	result := arr[0]
	for i := 1; i < len(arr); i++ {
		result = gcd(result, arr[i])
	}
	return result
}

func lcmArray(arr []int) int {
	if len(arr) == 0 {
		return 0
	}
	result := arr[0]
	for i := 1; i < len(arr); i++ {
		result = lcm(result, arr[i])
	}
	return result
}

func calculateMaximumCompositeStrength(strengths []int) int {
	n := len(strengths)
	if n == 0 {
		return 0
	}

	maxStrength := 0


	g := gcdArray(strengths)
	l := lcmArray(strengths)
	composite := g * l
	if composite > maxStrength {
		maxStrength = composite
	}


	for i := 0; i < n; i++ {
		remaining := make([]int, 0, n-1)
		for j := 0; j < n; j++ {
			if j != i {
				remaining = append(remaining, strengths[j])
			}
		}

		if len(remaining) == 0 {
			composite = 0
		} else {
			g = gcdArray(remaining)
			l = lcmArray(remaining)
			composite = g * l
		}

		if composite > maxStrength {
			maxStrength = composite
		}
	}

	return maxStrength
}

