class Solver:
    def calculateMaximumCompositeStrength(self, strengths: List[int]) -> int:
        def gcd_list(nums):
            if not nums:
                return 0
            result = nums[0]
            for i in range(1, len(nums)):
                result = math.gcd(result, nums[i])
            return result

        def lcm_list(nums):
            if not nums:
                return 0
            result = nums[0]
            for i in range(1, len(nums)):
                result = (result * nums[i])
            return result

        def composite_strength(nums):
            if not nums:
                return 0
            if len(nums) == 1:
                return nums[0] * nums[0]
            return gcd_list(nums) * lcm_list(nums)

        n = len(strengths)
        max_strength = composite_strength(strengths)

        for i in range(n):
            remaining = strengths[:i] + strengths[i+1:]
            strength = composite_strength(remaining)
            max_strength = max(max_strength, strength)

        return max_strength

