        if (subset.empty()) return 0;
        long long g = subset[0];
        long long l = subset[0];
        for (size_t i = 1; i < subset.size(); ++i) {
            g = gcd(g, (long long)subset[i]);
            l = lcm(l, (long long)subset[i]);
        }
        return g * l;
    };

    long long max_strength = get_strength(nums);

    for (int i = 0; i < n; ++i) {
        std::vector<int> subset;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            subset.push_back(nums[j]);
        }
        max_strength = std::max(max_strength, get_strength(subset));
    }

    std::cout << max_strength << std::endl;

    return 0;
