func gcd(a, b *big.Int) *big.Int {
	res := new(big.Int)
	res.GCD(nil, nil, a, b)
	return res
}

func lcm(a, b *big.Int) *big.Int {
	if a.Sign() == 0 || b.Sign() == 0 {
		return big.NewInt(0)
	}
	res := new(big.Int).Mul(a, b)
	res.Abs(res)
	g := gcd(a, b)
	res.Div(res, g)
	return res
}

func calculate(nums []int) *big.Int {
	if len(nums) == 0 {
		return big.NewInt(0)
	}
	g := big.NewInt(int64(nums[0]))
	l := big.NewInt(int64(nums[0]))
	for i := 1; i < len(nums); i++ {
		val := big.NewInt(int64(nums[i]))
		g = gcd(g, val)
		l = lcm(l, val)
	}
	return new(big.Int).Mul(g, l)
}

