class Solver {
    public long calculateMaximumCompositeStrength(int[] strengths) {
        int n = strengths.length;
        if (n == 0) return 0;

        BigInteger maxStrength = calculate(strengths);

        if (n > 1) {
            for (int i = 0; i < n; i++) {
                int[] subset = new int[n - 1];
                int idx = 0;
                for (int j = 0; j < n; j++) {
                    if (i == j) continue;
                    subset[idx++] = strengths[j];
                }
                BigInteger current = calculate(subset);
                if (current.compareTo(maxStrength) > 0) {
                    maxStrength = current;
                }
            }
        } else {
            maxStrength = calculate(strengths);
        }

        return maxStrength.longValue();
    }

    private BigInteger calculate(int[] arr) {
        if (arr.length == 0) return BigInteger.ZERO;
        BigInteger g = BigInteger.valueOf(arr[0]);
        BigInteger l = BigInteger.valueOf(arr[0]);
        for (int i = 1; i < arr.length; i++) {
            BigInteger val = BigInteger.valueOf(arr[i]);
            g = g.gcd(val);
            l = l.multiply(val).divide(l.gcd(val));
        }
        return g.multiply(l);
    }
}

