class Solution {
public:
    int findMaximumAnomaly(vector<int>& values) {
        int n = values.size();
        int maxAnomaly = INT_MIN;

        for (int i = 0; i < n; i++) {
            int anomaly = values[i];
            vector<int> remaining;

            for (int j = 0; j < n; j++) {
                if (j != i) {
                    remaining.push_back(values[j]);
                }
            }

            unordered_map<int, int> count;
            for (int val : remaining) {
                count[val]++;
            }

            for (auto& p : count) {
                int sum = p.first;
                int sumCount = p.second;

                if (sumCount > 0) {
                    unordered_map<int, int> tempCount = count;
                    tempCount[sum]--;

                    int totalSum = 0;
                    int standardCount = 0;

                    for (auto& q : tempCount) {
                        totalSum += q.first * q.second;
                        standardCount += q.second;
                    }

                    if (standardCount == n - 2 && totalSum == sum) {
                        maxAnomaly = max(maxAnomaly, anomaly);
                        break;
                    }
                }
            }
        }

        return maxAnomaly;
    }
};

