func findMaximumAnomaly(values []int) int {
    n := len(values)
    maxAnomaly := -1001

    for i := 0; i < n; i++ {
        anomaly := values[i]
        remaining := make([]int, 0, n-1)

        for j := 0; j < n; j++ {
            if j != i {
                remaining = append(remaining, values[j])
            }
        }

        if isValidConfiguration(remaining) {
            if anomaly > maxAnomaly {
                maxAnomaly = anomaly
            }
        }
    }

    return maxAnomaly
}

func isValidConfiguration(remaining []int) bool {
    n := len(remaining)

    for i := 0; i < n; i++ {
        sum := remaining[i]
        others := make([]int, 0, n-1)

        for j := 0; j < n; j++ {
            if j != i {
                others = append(others, remaining[j])
            }
        }

        if canFormSum(others, sum) {
            return true
        }
    }

    return false
}

func canFormSum(arr []int, target int) bool {
    total := 0
    for _, val := range arr {
        total += val
    }
    return total == target
}

