        int maxAnomaly = Integer.MIN_VALUE;

        for (int i = 0; i < n; i++) {
            int candidateAnomaly = values[i];

            for (int j = 0; j < n; j++) {
                if (i == j) continue;

                int candidateAggregate = values[j];

                int sum = 0;
                int count = 0;
                for (int k = 0; k < n; k++) {
                    if (k != i && k != j) {
                        sum += values[k];
                        count++;
                    }
                }

                if (count == n - 2 && sum == candidateAggregate) {
                    maxAnomaly = Math.max(maxAnomaly, candidateAnomaly);
                }
            }
        }

