using namespace std;

class Solution {
public:
    vector<bool> findResult(vector<int>& supervisor, string t) {
        int n = supervisor.size();
        vector<vector<int>> children(n);


        for (int i = 1; i < n; i++) {
            children[supervisor[i]].push_back(i);
        }


        for (int i = 0; i < n; i++) {
            sort(children[i].begin(), children[i].end());
        }

        vector<bool> result(n);

        for (int i = 0; i < n; i++) {
            string traversalStr = "";
            traverse(i, children, t, traversalStr);
            result[i] = isPalindrome(traversalStr);
        }

        return result;
    }

private:
    void traverse(int x, vector<vector<int>>& children, string& t, string& traversalStr) {

        for (int y : children[x]) {
            traverse(y, children, t, traversalStr);
        }

        traversalStr += t[x];
    }

    bool isPalindrome(const string& s) {
        int left = 0, right = s.length() - 1;
        while (left < right) {
            if (s[left] != s[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
};

int main() {
