func main() {
	var n int
	fmt.Scan(&n)

	supervisor := make([]int, n)
	for i := 0; i < n; i++ {
		fmt.Scan(&supervisor[i])
	}

	var t string
	fmt.Scan(&t)

	result := findResult(supervisor, t)

	for i, val := range result {
		if i > 0 {
			fmt.Print(" ")
		}
		if val {
			fmt.Print("true")
		} else {
			fmt.Print("false")
		}
	}
	fmt.Println()
}

func findResult(supervisor []int, t string) []bool {
	n := len(supervisor)

	children := make([][]int, n)
	for i := 1; i < n; i++ {
		sup := supervisor[i]
		children[sup] = append(children[sup], i)
	}

	for i := 0; i < n; i++ {
		sort.Ints(children[i])
	}

	result := make([]bool, n)

	for i := 0; i < n; i++ {
		var traversalStr strings.Builder
		traverse(i, children, t, &traversalStr)
		str := traversalStr.String()
		result[i] = isPalindrome(str)
	}

	return result
}

func traverse(x int, children [][]int, t string, traversalStr *strings.Builder) {
	for _, y := range children[x] {
		traverse(y, children, t, traversalStr)
	}
	traversalStr.WriteByte(t[x])
}

func isPalindrome(s string) bool {
	n := len(s)
	for i := 0; i < n/2; i++ {
		if s[i] != s[n-1-i] {
			return false
		}
	}
	return true
}

import java.util.*;
import java.io.*;

public class Solution {
    private List<List<Integer>> children;
    private String t;
    private StringBuilder traversalStr;

    public boolean[] findResult(int[] supervisor, String t) {
        int n = supervisor.length;
        this.t = t;
        this.children = new ArrayList<>();

        for (int i = 0; i < n; i++) {
            children.add(new ArrayList<>());
        }

        for (int i = 1; i < n; i++) {
            children.get(supervisor[i]).add(i);
        }

        for (int i = 0; i < n; i++) {
            Collections.sort(children.get(i));
        }

        boolean[] result = new boolean[n];

        for (int i = 0; i < n; i++) {
            traversalStr = new StringBuilder();
            traverse(i);
            String str = traversalStr.toString();
            result[i] = isPalindrome(str);
        }

        return result;
    }

