            pref[i + 1] = (mul(pref[i], BASE) + (flat[i] - 'a' + 1)) % MOD;
        }
        for (int i = n - 1; i >= 0; i--) {
            suff[i] = (mul(suff[i + 1], BASE) + (flat[i] - 'a' + 1)) % MOD;
        }

