        for (int k = 1; k <= Math.min(n, x); k++) {
            long waysToPartition = dp[k][n];
            long waysToChooseTeams = nCr[x][k];
            long waysToAssignRatings = yPow[k];

            long current = (waysToPartition * waysToChooseTeams) % MOD;
            current = (current * waysToAssignRatings) % MOD;

            total = (total + current) % MOD;
        }

        return total;
    }
}

