public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        line = line.replace("[", "").replace("]", "").trim();
        if (line.isEmpty()) {
            System.out.println(0);
            return;
        }
        String[] parts = line.split(",");
        int[] items = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            items[i] = Integer.parseInt(parts[i].trim());
        }
        System.out.println(solve(items));
    }

    private static int solve(int[] items) {
        int n = items.length;
        if (n <= 1) return 0;

        int maxVal = 0;
        for (int x : items) if (x > maxVal) maxVal = x;

        int[] minPrime = new int[maxVal + 1];
        for (int i = 2; i <= maxVal; i++) {
            if (minPrime[i] == 0) {
                for (int j = i; j <= maxVal; j += i) {
                    if (minPrime[j] == 0) minPrime[j] = i;
                }
            }
        }

        int steps = 0;
        for (int i = n - 2; i >= 0; i--) {
            while (items[i] > items[i + 1]) {
                int gpd = getGPD(items[i], minPrime);
                if (gpd == -1) return -1;
                items[i] /= gpd;
                steps++;
            }
        }
        return steps;
    }

    private static int getGPD(int n, int[] minPrime) {
        if (n <= 1) return -1;
        int p = minPrime[n];
        if (p == 0) return -1;
        int gpd = n / p;
        if (gpd == 0) return -1;
        return gpd;
    }
}

