        int n = ship_sizes.length;
        Map<Integer, Integer> gcdCount = new HashMap<>();


        for (int mask = 1; mask < (1 << n); mask++) {
            int currentGcd = 0;
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    currentGcd = gcd(currentGcd, ship_sizes[i]);
                }
