        }

        long result = 0;
        for (int count : gcdCount.values()) {
            result = (result + (long) count * (count - 1) / 2) % MOD;
        }

        return (int) result;
    }

    private static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
