public class Solution {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String line = scanner.nextLine();
        String[] parts = line.split("sales = \\[");
        String[] salesStr = parts[1].split("\\]")[0].split(",");
        int[] sales = new int[salesStr.length];
        for (int i = 0; i < salesStr.length; i++) {
            sales[i] = Integer.parseInt(salesStr[i].trim());
        }
        int k = Integer.parseInt(scanner.nextLine().split("k = ")[1].split(",")[0].trim());
        int x = Integer.parseInt(scanner.nextLine().split("x = ")[1].trim());

        int[] result = solve(sales, k, x);
        System.out.print("[");
        for (int i = 0; i < result.length; i++) {
            System.out.print(result[i] + (i == result.length - 1 ? "" : ","));
        }
        System.out.println("]");
    }

    public static int[] solve(int[] sales, int k, int x) {
        int n = sales.length;
        int[] result = new int[n - k + 1];
        for (int i = 0; i <= n - k; i++) {
            Map<Integer, Integer> counts = new HashMap<>();
            for (int j = i; j < i + k; j++) {
                counts.put(sales[j], counts.getOrDefault(sales[j], 0) + 1);
            }

            List<Element> list = new ArrayList<>();
            for (Map.Entry<Integer, Integer> entry : counts.entrySet()) {
                list.add(new Element(entry.getKey(), entry.getValue()));
            }

            Collections.sort(list, new Comparator<Element>() {
                @Override
                public int compare(Element a, Element b) {
                    if (a.count != b.count) {
                        return b.count - a.count;
                    }
                    return b.val - a.val;
                }
            });

            int sum = 0;
            int limit = Math.min(x, list.size());
            for (int j = 0; j < limit; j++) {
                sum += list.get(j).val * list.get(j).count;
            }
            result[i] = sum;
        }
        return result;
    }

    static class Element {
        int val;
        int count;

        Element(int val, int count) {
            this.val = val;
            this.count = count;
        }
    }
}

