using namespace std;

double findMaxConversion(const string& start, const string& target, const vector<vector<string>>& pairs, const vector<double>& rates) {
    if (start == target) return 1.0;

    unordered_map<string, vector<pair<string, double>>> graph;

    for (int i = 0; i < pairs.size(); i++) {
        string from = pairs[i][0];
        string to = pairs[i][1];
        double rate = rates[i];

        graph[from].push_back({to, rate});
        graph[to].push_back({from, 1.0 / rate});
    }

    unordered_map<string, double> maxRate;
    queue<string> q;

    maxRate[start] = 1.0;
    q.push(start);

    while (!q.empty()) {
        string curr = q.front();
        q.pop();

        for (auto& edge : graph[curr]) {
            string next = edge.first;
            double rate = edge.second;
            double newRate = maxRate[curr] * rate;

            if (maxRate.find(next) == maxRate.end() || newRate > maxRate[next]) {
                maxRate[next] = newRate;
                q.push(next);
            }
        }
    }

    return maxRate.find(target) != maxRate.end() ? maxRate[target] : 0.0;
}

double solve(const string& initialResource, const vector<vector<string>>& pairs1, const vector<double>& rates1, const vector<vector<string>>& pairs2, const vector<double>& rates2) {
    unordered_map<string, bool> allResources;
    allResources[initialResource] = true;

    for (const auto& pair : pairs1) {
        allResources[pair[0]] = true;
        allResources[pair[1]] = true;
    }
    for (const auto& pair : pairs2) {
        allResources[pair[0]] = true;
        allResources[pair[1]] = true;
    }

    double maxResult = 1.0;

    for (const auto& resource : allResources) {
        string intermediate = resource.first;

        double day1Rate = findMaxConversion(initialResource, intermediate, pairs1, rates1);
        double day2Rate = findMaxConversion(intermediate, initialResource, pairs2, rates2);

        double totalRate = day1Rate * day2Rate;
        maxResult = max(maxResult, totalRate);
    }

    return maxResult;
}

