func getMaxConversion(graph map[string]map[string]float64, start, end string) float64 {
	if start == end {
		return 1.0
	}

	visited := make(map[string]bool)
	return dfs(graph, start, end, visited)
}

func dfs(graph map[string]map[string]float64, current, target string, visited map[string]bool) float64 {
	if current == target {
		return 1.0
	}

	visited[current] = true
	maxRate := 0.0

	if neighbors, exists := graph[current]; exists {
		for next, rate := range neighbors {
			if !visited[next] {
				result := dfs(graph, next, target, visited)
				if result > 0 {
					totalRate := rate * result
					if totalRate > maxRate {
						maxRate = totalRate
					}
				}
			}
		}
	}

	visited[current] = false
	return maxRate
}

