class Solution:
    def maxResources(self, initialResource: str, pairs1: List[List[str]], rates1: List[float], pairs2: List[List[str]], rates2: List[float]) -> float:
        def build_graph(pairs, rates):
            graph = defaultdict(list)
            for i, (start, target) in enumerate(pairs):
                rate = rates[i]
                graph[start].append((target, rate))
                graph[target].append((start, 1.0 / rate))
            return graph

        def get_max_conversion(graph, start_resource, all_resources):
            max_amounts = {resource: 0.0 for resource in all_resources}
            max_amounts[start_resource] = 1.0

            changed = True
            while changed:
                changed = False
                for resource in all_resources:
                    if max_amounts[resource] > 0:
                        for target, rate in graph[resource]:
                            new_amount = max_amounts[resource] * rate
                            if new_amount > max_amounts[target]:
                                max_amounts[target] = new_amount
                                changed = True

            return max_amounts

        graph1 = build_graph(pairs1, rates1)
        graph2 = build_graph(pairs2, rates2)

        all_resources = set([initialResource])
        for pair in pairs1:
            all_resources.update(pair)
