using namespace std;

class Solution {
public:
    unordered_map<string, double> get_max_rates(string start, const vector<vector<string>>& pairs, const vector<double>& rates) {
        unordered_map<string, vector<pair<string, double>>> adj;
        for (int i = 0; i < pairs.size(); ++i) {
            adj[pairs[i][0]].push_back({pairs[i][1], rates[i]});
            adj[pairs[i][1]].push_back({pairs[i][0], 1.0 / rates[i]});
        }

        unordered_map<string, double> max_rates;
        max_rates[start] = 1.0;
        queue<string> q;
        q.push(start);

        while (!q.empty()) {
            string curr = q.front();
            q.pop();

            if (adj.count(curr)) {
                for (auto& edge : adj[curr]) {
                    if (max_rates.find(edge.first) == max_rates.end()) {
                        max_rates[edge.first] = max_rates[curr] * edge.second;
                        q.push(edge.first);
                    }
                }
            }
        }
        return max_rates;
    }

    double maxResources(string initialResource, vector<vector<string>>& pairs1, vector<double>& rates1, vector<vector<string>>& pairs2, vector<double>& rates2) {
        unordered_map<string, double> day1 = get_max_rates(initialResource, pairs1, rates1);
        double max_res = 1.0;

        for (auto const& [res, amount] : day1) {
            unordered_map<string, double> day2 = get_max_rates(res, pairs2, rates2);
            if (day2.count(initialResource)) {
                max_res = max(max_res, amount * day2[initialResource]);
            }
        }

        return max_res;
    }
};

