        for (int i = 0; i < m; i++) {
            rates2[i] = sc.nextDouble();
        }

        System.out.printf("%.5f\n", solve(initialResource, pairs1, rates1, pairs2, rates2));
    }

    public static double solve(String initialResource, String[][] pairs1, double[] rates1, String[][] pairs2, double[] rates2) {
        Map<String, Double> day1Rates = getMaxRates(initialResource, pairs1, rates1);
        double maxInitial = 0.0;

        for (Map.Entry<String, Double> entry : day1Rates.entrySet()) {
            String resource = entry.getKey();
            double amount = entry.getValue();
            Map<String, Double> day2Rates = getMaxRates(resource, pairs2, rates2);
            if (day2Rates.containsKey(initialResource)) {
                maxInitial = Math.max(maxInitial, amount * day2Rates.get(initialResource));
            }
        }

        return maxInitial;
    }

    private static Map<String, Double> getMaxRates(String startNode, String[][] pairs, double[] rates) {
        Map<String, List<Edge>> adj = new HashMap<>();
        for (int i = 0; i < pairs.length; i++) {
            adj.computeIfAbsent(pairs[i][0], k -> new ArrayList<>()).add(new Edge(pairs[i][1], rates[i]));
            adj.computeIfAbsent(pairs[i][1], k -> new ArrayList<>()).add(new Edge(pairs[i][0], 1.0 / rates[i]));
        }

        Map<String, Double> maxRates = new HashMap<>();
        maxRates.put(startNode, 1.0);
        Queue<String> queue = new LinkedList<>();
        queue.add(startNode);

        while (!queue.isEmpty()) {
            String curr = queue.poll();
            double currRate = maxRates.get(curr);
            if (!adj.containsKey(curr)) continue;
            for (Edge edge : adj.get(curr)) {
                if (!maxRates.containsKey(edge.to)) {
                    maxRates.put(edge.to, currRate * edge.rate);
                    queue.add(edge.to);
                }
            }
        }
        return maxRates;
    }

    static class Edge {
        String to;
        double rate;
        Edge(String to, double rate) {
            this.to = to;
            this.rate = rate;
        }
    }
}

