class Solution {
public:
    long long originalMessageCount(std::string message) {
        int n = message.length();
        if (n == 0) return 0;

        std::vector<std::pair<char, int>> groups;
        int count = 1;
        for (int i = 1; i <= n; ++i) {
            if (i < n && message[i] == message[i-1]) {
                count++;
            } else {
                groups.push_back({message[i-1], count});
                count = 1;
            }
        }

        long long totalWays = 1;
        for (auto& group : groups) {
