            std::vector<long long> dp(k + 1, 0);
            dp[0] = 1;
            for (int i = 1; i <= k; ++i) {
                dp[i] = dp[i-1];
                if (i >= 2) {
                    dp[i] += dp[i-2];
                }
            }
            totalWays *= dp[k];
        }

        return totalWays;
    }
};

