    public static long countOriginalMessages(String message) {
        if (message == null || message.length() == 0) return 0;

        long totalWays = 1;
        int n = message.length();
        int i = 0;

        while (i < n) {
            int j = i;
            while (j < n && message.charAt(j) == message.charAt(i)) {
                j++;
            }
            int count = j - i;
            totalWays *= getWays(count);
            i = j;
        }

        return totalWays;
    }

    private static long getWays(int n) {
        if (n <= 0) return 1;
        long[] dp = new long[n + 1];
        dp[0] = 1;
        dp[1] = 1;
        for (int i = 2; i <= n; i++) {
            dp[i] = dp[i - 1] + dp[i - 2];
        }
        return dp[n];
    }
}

