class Solution {
public:
    int maxOccurrence(vector<int>& items, int m, int operationCount) {
        sort(items.begin(), items.end());
        int n = items.size();
        int max_freq = 0;

        map<int, int> freq_map;
        for (int x : items) freq_map[x]++;

        vector<int> unique_vals;
        for (auto const& [val, freq] : freq_map) {
            unique_vals.push_back(val);
        }

        for (int target : unique_vals) {
            int L = lower_bound(items.begin(), items.end(), target - m) - items.begin();
            int R = upper_bound(items.begin(), items.end(), target + m) - items.begin() - 1;
            int total_in_range = R - L + 1;
            int original_count = freq_map[target];
            int others = total_in_range - original_count;
            int can_change = min(others, operationCount);
            max_freq = max(max_freq, original_count + can_change);
        }

        vector<int> candidates;
        for (int x : items) {
            candidates.push_back(x - m);
            candidates.push_back(x + m);
        }
        sort(candidates.begin(), candidates.end());
        candidates.erase(unique(candidates.begin(), candidates.end()), candidates.end());

        for (int target : candidates) {
            if (freq_map.count(target)) continue;
            int L = lower_bound(items.begin(), items.end(), target - m) - items.begin();
            int R = upper_bound(items.begin(), items.end(), target + m) - items.begin() - 1;
            int total_in_range = R - L + 1;
            max_freq = max(max_freq, min(total_in_range, operationCount));
        }

        return max_freq;
    }
};

