func maxOccurrence(items []int, m int, operationCount int) int {
	sort.Ints(items)
	n := len(items)
	freq := make(map[int]int)
	for _, x := range items {
		freq[x]++
	}

	allPointsMap := make(map[int]struct{})
	for _, x := range items {
		allPointsMap[x] = struct{}{}
		allPointsMap[x-m] = struct{}{}
		allPointsMap[x+m] = struct{}{}
	}
	allPoints := make([]int, 0, len(allPointsMap))
	for k := range allPointsMap {
		allPoints = append(allPoints, k)
	}
	sort.Ints(allPoints)

	maxFreq := 0
	left := 0
	right := 0

	for _, v := range allPoints {
		for left < n && items[left] < v-m {
			left++
		}
		for right < n && items[right] <= v+m {
			right++
		}

		countInRange := right - left
		f := freq[v]
		others := countInRange - f

		canUse := others
		if canUse > operationCount {
			canUse = operationCount
		}

		current := f + canUse
		if current > maxFreq {
			maxFreq = current
		}
	}

	return maxFreq
}

