public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;

        String itemsStr = line.substring(line.indexOf("[") + 1, line.lastIndexOf("]")).trim();
        int[] items;
        if (itemsStr.isEmpty()) {
            items = new int[0];
        } else {
            String[] parts = itemsStr.split(",");
            items = new int[parts.length];
            for (int i = 0; i < parts.length; i++) {
                items[i] = Integer.parseInt(parts[i].trim());
            }
        }

        int m = 0, operationCount = 0;
        String nextLine;
        while ((nextLine = br.readLine()) != null) {
            if (nextLine.contains("m =")) {
                m = Integer.parseInt(nextLine.split("=")[1].trim().split(",")[0].trim());
            }
            if (nextLine.contains("operationCount =")) {
                operationCount = Integer.parseInt(nextLine.split("=")[1].trim());
            }
        }

        System.out.println(solve(items, m, operationCount));
    }

    private static int solve(int[] items, int m, int operationCount) {
        Arrays.sort(items);
        int n = items.length;
        Map<Integer, Integer> counts = new HashMap<>();
        for (int x : items) counts.put(x, counts.getOrDefault(x, 0) + 1);

        TreeSet<Integer> candidates = new TreeSet<>();
        for (int x : items) {
            candidates.add(x);
            candidates.add(x - m);
            candidates.add(x + m);
        }

        int maxFreq = 0;
        for (int x : candidates) {
            int L = x - m;
            int R = x + m;

            int leftIdx = lowerBound(items, L);
            int rightIdx = upperBound(items, R) - 1;
            int totalInRange = rightIdx - leftIdx + 1;

            int alreadyX = counts.getOrDefault(x, 0);
            int othersInRange = totalInRange - alreadyX;

            int canConvert = Math.min(othersInRange, operationCount);
            maxFreq = Math.max(maxFreq, alreadyX + canConvert);
        }

        return maxFreq;
    }

    private static int lowerBound(int[] arr, int target) {
        int low = 0, high = arr.length;
        while (low < high) {
            int mid = (low + high) / 2;
            if (arr[mid] >= target) high = mid;
            else low = mid + 1;
        }
        return low;
    }

    private static int upperBound(int[] arr, int target) {
        int low = 0, high = arr.length;
        while (low < high) {
            int mid = (low + high) / 2;
            if (arr[mid] > target) high = mid;
            else low = mid + 1;
        }
        return low;
    }
}

