class PathFinder {
public:
    int minimumTime(vector<vector<int>>& accessTime) {
        int n = accessTime.size();
        int m = accessTime[0].size();

        if (accessTime[0][1] > 1 && accessTime[1][0] > 1) {
            return -1;
        }

        vector<vector<int>> dist(n, vector<int>(m, INT_MAX));
        priority_queue<vector<int>, vector<vector<int>>, greater<vector<int>>> pq;

        dist[0][0] = 0;
        pq.push({0, 0, 0});

        int dx[] = {-1, 1, 0, 0};
        int dy[] = {0, 0, -1, 1};

        while (!pq.empty()) {
            vector<int> curr = pq.top();
            pq.pop();

            int time = curr[0];
            int x = curr[1];
            int y = curr[2];

            if (x == n - 1 && y == m - 1) {
                return time;
            }

            if (time > dist[x][y]) {
                continue;
            }

            for (int i = 0; i < 4; i++) {
                int nx = x + dx[i];
                int ny = y + dy[i];

                if (nx >= 0 && nx < n && ny >= 0 && ny < m) {
                    int nextTime = time + 1;

                    if (nextTime < accessTime[nx][ny]) {
                        int wait = accessTime[nx][ny] - nextTime;
                        if (wait % 2 == 1) {
                            nextTime = accessTime[nx][ny] + 1;
                        } else {
                            nextTime = accessTime[nx][ny];
                        }
                    }

                    if (nextTime < dist[nx][ny]) {
                        dist[nx][ny] = nextTime;
                        pq.push({nextTime, nx, ny});
                    }
                }
            }
        }

        return -1;
    }
};

