type State struct {
    time, row, col int
}

type PriorityQueue []*State

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool { return pq[i].time < pq[j].time }
func (pq PriorityQueue) Swap(i, j int) { pq[i], pq[j] = pq[j], pq[i] }

func (pq *PriorityQueue) Push(x interface{}) {
    *pq = append(*pq, x.(*State))
}

func (pq *PriorityQueue) Pop() interface{} {
    old := *pq
    n := len(old)
    item := old[n-1]
    *pq = old[0 : n-1]
    return item
}

func minimumTime(accessTime [][]int) int {
    n, m := len(accessTime), len(accessTime[0])

    if accessTime[0][1] > 1 && accessTime[1][0] > 1 {
        return -1
    }

    directions := [][]int{{0, 1}, {1, 0}, {0, -1}, {-1, 0}}
    visited := make([][]bool, n)
    for i := range visited {
        visited[i] = make([]bool, m)
    }

    pq := &PriorityQueue{}
    heap.Init(pq)
    heap.Push(pq, &State{0, 0, 0})

    for pq.Len() > 0 {
        current := heap.Pop(pq).(*State)

        if current.row == n-1 && current.col == m-1 {
            return current.time
        }

        if visited[current.row][current.col] {
            continue
        }
        visited[current.row][current.col] = true

        for _, dir := range directions {
            newRow, newCol := current.row+dir[0], current.col+dir[1]

            if newRow >= 0 && newRow < n && newCol >= 0 && newCol < m && !visited[newRow][newCol] {
                newTime := current.time + 1

                if newTime < accessTime[newRow][newCol] {
                    wait := accessTime[newRow][newCol] - newTime
                    if wait%2 == 1 {
                        newTime = accessTime[newRow][newCol]
                    } else {
                        newTime = accessTime[newRow][newCol] + 1
                    }
                }

                heap.Push(pq, &State{newTime, newRow, newCol})
            }
        }
    }

    return -1
}

