func solve(c string, k int) int {
	const mod = 1000000007
	memo := make([]int, k+1)

	for i := 0; i <= k; i++ {
		if i < 13 {
			memo[i] = 1
		} else if i == 13 {
			memo[i] = 2
		} else {
			memo[i] = (memo[i-13] + memo[i-12]) % mod
		}
	}

	total := 0
	for i := 0; i < len(c); i++ {
		charVal := int(c[i] - 'a')
		distToM := 12 - charVal

		if k <= distToM {
			total = (total + 1) % mod
		} else {
			remainingK := k - (distToM + 1)
			total = (total + memo[remainingK]) % mod
		}
	}

	return total
}

