func countKReducibleElements(t string, k int) int {
	n := len(t)


	isKReducible := make([]bool, n+1)
	for bits := 1; bits <= n; bits++ {
		steps := 0
		curr := bits
		for curr > 1 && steps < k {
			curr = popcount(curr)
			steps++
		}
		isKReducible[bits] = (curr == 1 && steps <= k)
	}


	memo := make(map[string]int)

	var dp func(pos int, tight bool, bits int) int
	dp = func(pos int, tight bool, bits int) int {
		if pos == n {
			if bits > 0 && isKReducible[bits] {
				return 1
			}
			return 0
		}

		key := fmt.Sprintf("%d_%t_%d", pos, tight, bits)
		if val, exists := memo[key]; exists {
			return val
		}

		limit := 1
		if tight && t[pos] == '0' {
			limit = 0
		}

		result := 0
		for digit := 0; digit <= limit; digit++ {
			newTight := tight && (digit == int(t[pos]-'0'))
			newBits := bits + digit
			result = (result + dp(pos+1, newTight, newBits)) % MOD
		}

		memo[key] = result
		return result
	}

	return dp(0, true, 0)
}

func popcount(x int) int {
	count := 0
	for x > 0 {
		count += x & 1
		x >>= 1
	}
	return count
}

