public class Solution {
    private static final int MOD = 1000000007;

    public int countKReducibleElements(String t, int k) {
        int n = t.length();
        int[] reducible = new int[n + 1];

        for (int i = 1; i <= n; i++) {
            int steps = 0;
            int curr = i;
            while (curr != 1 && steps <= k) {
                curr = Integer.bitCount(curr);
                steps++;
            }
            reducible[i] = (curr == 1 && steps <= k) ? steps : -1;
        }

        long[][][] dp = new long[n + 1][n + 1][2];
        dp[0][0][1] = 1;

        for (int pos = 0; pos < n; pos++) {
            int digit = t.charAt(pos) - '0';

            for (int bits = 0; bits <= pos; bits++) {
                for (int tight = 0; tight <= 1; tight++) {
                    if (dp[pos][bits][tight] == 0) continue;

                    int limit = tight == 1 ? digit : 1;

                    for (int d = 0; d <= limit; d++) {
                        int newBits = bits + d;
                        int newTight = (tight == 1 && d == digit) ? 1 : 0;

                        dp[pos + 1][newBits][newTight] = (dp[pos + 1][newBits][newTight] + dp[pos][bits][tight]) % MOD;
                    }
                }
            }
        }

        long result = 0;
        for (int bits = 1; bits <= n; bits++) {
            if (reducible[bits] != -1 && reducible[bits] <= k) {
                result = (result + dp[n][bits][0] + dp[n][bits][1]) % MOD;
            }
        }

        return (int) result;
    }

