public class Solution {
    public int calculateReflectionScore(String t) {
        int n = t.length();
        boolean[] marked = new boolean[n];
        int score = 0;

        for (int i = 0; i < n; i++) {
            if (marked[i]) continue;

            char currentChar = t.charAt(i);
            char reflection = getReflection(currentChar);

            int closestJ = -1;
            for (int j = i - 1; j >= 0; j--) {
                if (!marked[j] && t.charAt(j) == reflection) {
                    closestJ = j;
                    break;
                }
            }

            if (closestJ != -1) {
                marked[i] = true;
                marked[closestJ] = true;
                score += i - closestJ;
            }
        }

        return score;
    }

    private char getReflection(char c) {
        return (char)('a' + 'z' - c);
    }

