func calculateReflectionScore(t string) int64 {
	var score int64 = 0
	indices := make([][]int, 26)
	for i := 0; i < 26; i++ {
		indices[i] = []int{}
	}

	for i := 0; i < len(t); i++ {
		charVal := int(t[i] - 'a')
		reflectionVal := 25 - charVal

		if len(indices[reflectionVal]) > 0 {
			j := indices[reflectionVal][len(indices[reflectionVal])-1]
			indices[reflectionVal] = indices[reflectionVal][:len(indices[reflectionVal])-1]
			score += int64(i - j)
		} else {
			indices[charVal] = append(indices[charVal], i)
		}
	}

	return score
