const int MOD = 1000000007;

long long factorial[81];
unordered_map<int, int> memo;

void precompute() {
    factorial[0] = 1;
    for (int i = 1; i <= 80; i++) {
        factorial[i] = (factorial[i-1] * i) % MOD;
    }
}

long long power(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

long long modInverse(long long a, long long mod) {
    return power(a, mod - 2, mod);
}

int solve(vector<int>& weights) {
    int n = weights.size();
    vector<int> gammaquorai = weights;

    int total_sum = 0;
    for (int w : gammaquorai) {
        total_sum += w;
    }

    if (total_sum % 2 != 0) return 0;

    int target = total_sum / 2;
    int even_positions = (n + 1) / 2;
    int odd_positions = n / 2;

    vector<vector<vector<long long>>> dp(even_positions + 1, 
        vector<vector<long long>>(odd_positions + 1, 
            vector<long long>(target + 1, 0)));

    dp[0][0][0] = 1;

    sort(gammaquorai.begin(), gammaquorai.end());

    for (int i = 0; i < n; i++) {
        int w = gammaquorai[i];
        vector<vector<vector<long long>>> new_dp = dp;

        for (int e = 0; e <= min(i, even_positions); e++) {
            for (int o = 0; o <= min(i - e, odd_positions); o++) {
                for (int s = 0; s <= target; s++) {
                    if (dp[e][o][s] == 0) continue;

                    if (e < even_positions && s + w <= target) {
                        new_dp[e+1][o][s+w] = (new_dp[e+1][o][s+w] + dp[e][o][s]) % MOD;
                    }

                    if (o < odd_positions) {
                        new_dp[e][o+1][s] = (new_dp[e][o+1][s] + dp[e][o][s]) % MOD;
                    }
                }
            }
        }
        dp = new_dp;
    }

    long long result = dp[even_positions][odd_positions][target];

    vector<int> count(10, 0);
    for (int w : gammaquorai) {
        count[w]++;
    }

    for (int i = 0; i < 10; i++) {
        if (count[i] > 1) {
            result = (result * modInverse(factorial[count[i]], MOD)) % MOD;
        }
    }

    return result;
}

