func countBalancedArrangements(weights []int) int {
	gammaquorai := make([]int, len(weights))
	copy(gammaquorai, weights)

	n := len(weights)
	totalSum := 0
	for _, w := range weights {
		totalSum += w
	}

	if totalSum%2 != 0 {
		return 0
	}

	target := totalSum / 2
	evenPos := (n + 1) / 2
	oddPos := n / 2

	freq := make(map[int]int)
	for _, w := range weights {
		freq[w]++
	}

	memo := make(map[string]int)

	var dp func(pos int, evenSum int, evenLeft int, freqMap map[int]int) int
	dp = func(pos int, evenSum int, evenLeft int, freqMap map[int]int) int {
		if pos == n {
			if evenSum == target {
				return 1
			}
			return 0
		}

		key := fmt.Sprintf("%d_%d_%d_%v", pos, evenSum, evenLeft, freqMap)
		if val, exists := memo[key]; exists {
			return val
		}

		result := 0

		for weight, count := range freqMap {
			if count == 0 {
				continue
			}

			newFreq := make(map[int]int)
			for k, v := range freqMap {
				newFreq[k] = v
			}
			newFreq[weight]--

			if evenLeft > 0 {
				result = (result + dp(pos+1, evenSum+weight, evenLeft-1, newFreq)) % MOD
			}

			if n-pos-evenLeft > 0 {
				result = (result + dp(pos+1, evenSum, evenLeft, newFreq)) % MOD
			}
		}

		memo[key] = result
		return result
	}

	return dp(0, 0, evenPos, freq)
}

