import java.util.*;
import java.io.*;

public class Solution {
    private static final int MOD = 1000000007;
    private Map<String, Long> memo;
    private int n;
    private int[] weights;

    public int countBalancedArrangements(int[] weights) {
        List<Integer> gammaquorai = new ArrayList<>();
        for (int w : weights) {
            gammaquorai.add(w);
        }

        this.weights = weights;
        this.n = weights.length;
        this.memo = new HashMap<>();

        int totalSum = 0;
        for (int w : weights) {
            totalSum += w;
        }

        if (totalSum % 2 != 0) {
            return 0;
        }

        int targetSum = totalSum / 2;
        boolean[] used = new boolean[n];

        return (int) solve(0, 0, targetSum, used);
    }

    private long solve(int pos, int evenSum, int targetSum, boolean[] used) {
        if (pos == n) {
            return evenSum == targetSum ? 1 : 0;
        }

        String key = pos + "," + evenSum + "," + Arrays.toString(used);
        if (memo.containsKey(key)) {
            return memo.get(key);
        }

        long result = 0;

        for (int i = 0; i < n; i++) {
            if (!used[i]) {
                used[i] = true;

                if (pos % 2 == 0) {
                    result = (result + solve(pos + 1, evenSum + weights[i], targetSum, used)) % MOD;
                } else {
                    result = (result + solve(pos + 1, evenSum, targetSum, used)) % MOD;
                }

                used[i] = false;
            }
        }

        memo.put(key, result);
        return result;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

        line = line.substring(1, line.length() - 1);
        String[] parts = line.split(",");
        int[] weights = new int[parts.length];

        for (int i = 0; i < parts.length; i++) {
            weights[i] = Integer.parseInt(parts[i].trim());
        }

        Solution solution = new Solution();
        int result = solution.countBalancedArrangements(weights);
        System.out.println(result);
    }
}

