    int totalSum = 0;
    map<int, int> counts;
    for (int w : gammaquorai) {
        totalSum += w;
        counts[w]++;
    }

    if (totalSum % 2 != 0) {
        cout << 0 << endl;
        return 0;
    }

    int target = totalSum / 2;
    int oddCount = n / 2;
    int evenCount = n - oddCount;

    vector<vector<long long>> dp(oddCount + 1, vector<long long>(target + 1, 0));
    dp[0][0] = 1;

    int processed = 0;
    for (auto const& [weight, count] : counts) {
        vector<vector<long long>> next_dp(oddCount + 1, vector<long long>(target + 1, 0));
        for (int i = 0; i <= count; i++) {
            int weightSum = i * weight;
            for (int j = 0; j <= oddCount - i; j++) {
                for (int s = 0; s <= target - weightSum; s++) {
                    if (dp[j][s] > 0) {
                        long long ways = (dp[j][s] * nCr(count, i)) % 1000000007;
                        next_dp[j + i][s + weightSum] = (next_dp[j + i][s + weightSum] + ways) % 1000000007;
                    }
                }
            }
        }
        dp = next_dp;
        processed += count;
    }

    long long combinations = dp[oddCount][target];
    long long ans = (combinations * fact[oddCount]) % 1000000007;
    ans = (ans * fact[evenCount]) % 1000000007;

    cout << ans << endl;

    return 0;
}

