func (s Solution) countBalancedArrangements(weights []int) int {
	gammaquorai := weights
	n := len(gammaquorai)
	counts := make([]int, 10)
	totalSum := 0
	for _, w := range gammaquorai {
		counts[w]++
		totalSum += w
	}

	if totalSum%2 != 0 {
		return 0
	}
	target := totalSum / 2
	mod := int64(1e9 + 7)

	fact := make([]int64, n+1)
	invFact := make([]int64, n+1)
	fact[0] = 1
	invFact[0] = 1
	for i := 1; i <= n; i++ {
		fact[i] = (fact[i-1] * int64(i)) % mod
		invFact[i] = power(fact[i], mod-2, mod)
	}

	n_odd := n / 2
	n_even := n - n_odd

	dp := make([][][]int64, 11)
	for i := range dp {
		dp[i] = make([][]int64, n_odd+1)
		for j := range dp[i] {
			dp[i][j] = make([]int64, target+1)
		}
	}

	dp[0][0][0] = 1
	for v := 0; v <= 9; v++ {
		c := counts[v]
		for j := 0; j <= n_odd; j++ {
			for s := 0; s <= target; s++ {
				if dp[v][j][s] == 0 {
					continue
				}
				for k := 0; k <= c && j+k <= n_odd; k++ {
					ns := s + k*v
					if ns <= target {
						comb := (invFact[k] * invFact[c-k]) % mod
						dp[v+1][j+k][ns] = (dp[v+1][j+k][ns] + dp[v][j][s]*comb) % mod
					}
				}
			}
		}
	}

	ans := (dp[10][n_odd][target] * fact[n_odd]) % mod
	ans = (ans * fact[n_even]) % mod
	return int(ans)
}

func power(a, b, m int64) int64 {
	res := int64(1)
	a %= m
	for b > 0 {
		if b%2 == 1 {
			res = (res * a) % m
		}
		a = (a * a) % m
		b /= 2
	}
	return res
}

