        int currentTotalCount = 0;
        for (int digit = 0; digit <= 9; digit++) {
            if (counts[digit] == 0) continue;
            long[][][] nextDp = new long[nOdd + 1][target + 1][1];
            for (int i = 0; i <= nOdd; i++) {
                for (int s = 0; s <= target; s++) {
                    if (dp[i][s][0] == 0) continue;
                    for (int take = 0; take <= counts[digit] && i + take <= nOdd; take++) {
                        int nextSum = s + take * digit;
                        if (nextSum <= target) {
                            long ways = (dp[i][s][0] * nCr(counts[digit], take)) % MOD;
                            nextDp[i + take][nextSum][0] = (nextDp[i + take][nextSum][0] + ways) % MOD;
