                ncrTable[i][j] = (ncrTable[i - 1][j - 1] + ncrTable[i - 1][j]) % MOD;
            }
        }
    }

    private static long nCr(int n, int r) {
        if (r < 0 || r > n) return 0;
        return ncrTable[n][r];
    }

    private static long factorial(int n) {
        long res = 1;
        for (int i = 2; i <= n; i++) res = (res * i) % MOD;
        return res;
    }
