            c = counts[w]
            next_dp = {}
            for (curr_odd_count, curr_odd_sum), ways in dp.items():
                for i in range(max(0, c - n_even + (n - n_odd - (sum(counts[k] for k in distinct_weights if k < w) - curr_odd_count))), min(c, n_odd - curr_odd_count) + 1):
                    new_odd_count = curr_odd_count + i
                    new_odd_sum = curr_odd_sum + i * w
                    if new_odd_count <= n_odd and new_odd_sum <= target:
                        comb = (nCr_mod(c, i) * ways) % MOD
                        state = (new_odd_count, new_odd_sum)
                        next_dp[state] = (next_dp.get(state, 0) + comb) % MOD
            dp = next_dp

        ways_to_split = dp.get((n_odd, target), 0)

        if ways_to_split == 0:
            return 0

        ans = (ways_to_split * fact[n_odd]) % MOD
        ans = (ans * fact[n_even]) % MOD

        denom = 1
        for w in distinct_weights:
            denom = (denom * fact[counts[w]]) % MOD

        return (ans * pow(denom, MOD - 2, MOD)) % MOD

