        List<int[]> opList = new ArrayList<>();
        int i = 0;
        while (i < opStr.length()) {
            if (opStr.charAt(i) == '[') {
                int start = i + 1;
                int end = opStr.indexOf(']', start);
                if (end == -1) break;
                String pair = opStr.substring(start, end);
                if (pair.contains(",")) {
                    String[] parts = pair.split(",");
                    opList.add(new int[]{Integer.parseInt(parts[0]), Integer.parseInt(parts[1])});
                }
                i = end + 1;
            } else {
                i++;
            }
        }

        int[][] operations = opList.toArray(new int[0][]);
        Solution sol = new Solution();
        System.out.println(sol.canConvertToZero(quantities, operations));
    }
}

