class Solution:
    def canConvertToZero(self, quantities: list[int], operations: list[list[int]]) -> bool:
        n = len(quantities)
        diff = [0] * (n + 1)
        for start, end in operations:
            diff[start] += 1
            if end + 1 < n:
                diff[end + 1] -= 1

        current_max_reduction = 0
        for i in range(n):
            current_max_reduction += diff[i]
            if current_max_reduction < quantities[i]:
                return False
        return True

