public class Solution {

    public int maxRemoval(int[] stock, int[][] operations) {
        int n = stock.length;
        int m = operations.length;


        Arrays.sort(operations, (a, b) -> a[0] - b[0]);


        PriorityQueue<Integer> available = new PriorityQueue<>((a, b) -> b - a);


        PriorityQueue<Integer> used = new PriorityQueue<>();

        int opIndex = 0;
        int usedCount = 0;

        for (int i = 0; i < n; i++) {

            while (opIndex < m && operations[opIndex][0] == i) {
                available.offer(operations[opIndex][1]);
                opIndex++;
            }


            while (!used.isEmpty() && used.peek() < i) {
                used.poll();
            }

            int currentCoverage = used.size();
            int needed = stock[i];


            while (currentCoverage < needed && !available.isEmpty()) {
                int endPos = available.poll();
                if (endPos >= i) {
                    used.offer(endPos);
                    currentCoverage++;
                    usedCount++;
                }
            }


            if (currentCoverage < needed) {
                return -1;
            }
        }

        return m - usedCount;
    }

