class Solution {
    public int maxCollectedResources(int[][] resources) {
        int n = resources.length;
        int[][] dp1 = new int[n][n];
        int[][] dp2 = new int[n][n];
        int[][] dp3 = new int[n][n];

        for (int i = 0; i < n; i++) {
            Arrays.fill(dp1[i], -1);
            Arrays.fill(dp2[i], -1);
            Arrays.fill(dp3[i], -1);
        }

        dp1[0][0] = resources[0][0];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (dp1[i][j] == -1 || (i == n - 1 && j == n - 1)) continue;
                int[][] moves = {{i + 1, j + 1}, {i + 1, j}, {i, j + 1}};
                for (int[] m : moves) {
                    if (m[0] < n && m[1] < n && m[0] >= i && m[1] >= j) {
                        dp1[m[0]][m[1]] = Math.max(dp1[m[0]][m[1]], dp1[i][j] + resources[m[0]][m[1]]);
                    }
                }
            }
        }

        dp2[0][n - 1] = resources[0][n - 1];
        for (int i = 0; i < n; i++) {
            for (int j = n - 1; j >= 0; j--) {
                if (dp2[i][j] == -1 || (i == n - 1 && j == n - 1)) continue;
                int[][] moves = {{i + 1, j - 1}, {i + 1, j}, {i + 1, j + 1}};
                for (int[] m : moves) {
                    if (m[0] < n && m[1] >= 0 && m[1] < n) {
                        dp2[m[0]][m[1]] = Math.max(dp2[m[0]][m[1]], dp2[i][j] + resources[m[0]][m[1]]);
                    }
                }
            }
        }

        dp3[n - 1][0] = resources[n - 1][0];
        for (int j = 0; j < n; j++) {
            for (int i = n - 1; i >= 0; i--) {
                if (dp3[i][j] == -1 || (i == n - 1 && j == n - 1)) continue;
                int[][] moves = {{i - 1, j + 1}, {i, j + 1}, {i + 1, j + 1}};
                for (int[] m : moves) {
                    if (m[0] >= 0 && m[0] < n && m[1] < n) {
                        dp3[m[0]][m[1]] = Math.max(dp3[m[0]][m[1]], dp3[i][j] + resources[m[0]][m[1]]);
                    }
                }
            }
        }

        int total = dp1[n - 1][n - 1] + dp2[n - 1][n - 1] + dp3[n - 1][n - 1];
        return total - 2 * resources[n - 1][n - 1];
    }
}

