func computeMinimumTime(difficulty []int, M int) int {
	n := len(difficulty)
	minTime := math.MaxInt32

	perm := make([]int, n)
	for i := 0; i < n; i++ {
		perm[i] = i
	}

	for {
		time := simulate(difficulty, perm, M)
		if time < minTime {
			minTime = time
		}

		if !nextPermutation(perm) {
			break
		}
	}

	return minTime
}

func simulate(difficulty []int, order []int, M int) int {
	time := 0
	energy := 0
	Y := 1

	for _, idx := range order {
		target := difficulty[idx]

		for energy < target {
			time++
			energy += Y
		}

		energy = 0
		Y += M
	}

	return time
}

func nextPermutation(nums []int) bool {
	i := len(nums) - 2
	for i >= 0 && nums[i] >= nums[i+1] {
		i--
	}

	if i < 0 {
		return false
	}

	j := len(nums) - 1
	for nums[j] <= nums[i] {
		j--
	}

	nums[i], nums[j] = nums[j], nums[i]

	reverse(nums[i+1:])

	return true
}

func reverse(nums []int) {
	for i, j := 0, len(nums)-1; i < j; i, j = i+1, j-1 {
		nums[i], nums[j] = nums[j], nums[i]
	}
}

