    private static int solve(int[] difficulty, int m) {
        int n = difficulty.length;
        int[] p = new int[n];
        for (int i = 0; i < n; i++) p[i] = i;

        int minTotalTime = Integer.MAX_VALUE;

        do {
            int currentTime = 0;
            int currentY = 1;
            for (int i = 0; i < n; i++) {
                int target = difficulty[p[i]];
                int timeNeeded = (target + currentY - 1) / currentY;
                currentTime += timeNeeded;
                currentY += m;
            }
            minTotalTime = Math.min(minTotalTime, currentTime);
        } while (nextPermutation(p));

        return minTotalTime;
    }

    private static boolean nextPermutation(int[] array) {
        int i = array.length - 2;
        while (i >= 0 && array[i] >= array[i + 1]) i--;
        if (i < 0) return false;
        int j = array.length - 1;
        while (array[j] <= array[i]) j--;
        int temp = array[i];
        array[i] = array[j];
        array[j] = temp;
        int left = i + 1, right = array.length - 1;
        while (left < right) {
            temp = array[left];
            array[left] = array[right];
            array[right] = temp;
            left++;
            right--;
        }
        return true;
    }
}

