class Solution {
public:
    vector<int> circularNavigation(vector<int>& nums) {
        int n = nums.size();
        vector<int> destinations(n);

        for (int i = 0; i < n; i++) {
            if (nums[i] == 0) {
                destinations[i] = nums[i];
            } else if (nums[i] > 0) {
                int newIndex = (i + nums[i]) % n;
                destinations[i] = newIndex;
            } else {
                int steps = abs(nums[i]);
                int newIndex = ((i - steps) % n + n) % n;
                destinations[i] = newIndex;
            }
        }

        return destinations;
    }
};

