func minimumTotalEffort(efforts []int, k int, op1 int, op2 int) int {
    n := len(efforts)
    memo := make(map[string]int)

    var dp func(int, int, int) int
    dp = func(idx, remainingOp1, remainingOp2 int) int {
        if idx == n {
            return 0
        }

        key := fmt.Sprintf("%d,%d,%d", idx, remainingOp1, remainingOp2)
        if val, exists := memo[key]; exists {
            return val
        }

        current := efforts[idx]
        minSum := math.MaxInt32


        minSum = min(minSum, current + dp(idx+1, remainingOp1, remainingOp2))


        if remainingOp1 > 0 {
            newVal := (current + 1) / 2
            minSum = min(minSum, newVal + dp(idx+1, remainingOp1-1, remainingOp2))
        }


        if remainingOp2 > 0 && current >= k {
            newVal := current - k
            minSum = min(minSum, newVal + dp(idx+1, remainingOp1, remainingOp2-1))
        }


        if remainingOp1 > 0 && remainingOp2 > 0 {
            afterOp1 := (current + 1) / 2
            if afterOp1 >= k {
                newVal := afterOp1 - k
                minSum = min(minSum, newVal + dp(idx+1, remainingOp1-1, remainingOp2-1))
            }
        }


        if remainingOp1 > 0 && remainingOp2 > 0 && current >= k {
            afterOp2 := current - k
            newVal := (afterOp2 + 1) / 2
            minSum = min(minSum, newVal + dp(idx+1, remainingOp1-1, remainingOp2-1))
        }

        memo[key] = minSum
        return minSum
    }

    return dp(0, op1, op2)
}

