                    if (j + 1 <= op1) {
                        int nextVal = (val + 1) / 2;
                        dp[i + 1][j + 1][l] = Math.min(dp[i + 1][j + 1][l], dp[i][j][l] + nextVal);
                    }

                    if (l + 1 <= op2 && val >= k) {
                        int nextVal = val - k;
                        dp[i + 1][j][l + 1] = Math.min(dp[i + 1][j][l + 1], dp[i][j][l] + nextVal);
