int minOperations(int x, int y) {
    if (isPrime(x) || isPrime(y)) return -1;
    if (x == y) return x;

    queue<pair<int, int>> q;
    unordered_set<int> visited;

    q.push({x, x});
    visited.insert(x);

    while (!q.empty()) {
        auto [curr, cost] = q.front();
        q.pop();

        vector<int> next = {curr - 1, curr + 1};

        for (int nextVal : next) {
            if (nextVal < 0 || nextVal > 10000) continue;
            if (visited.count(nextVal)) continue;
            if (isPrime(nextVal)) continue;

            int newCost = cost + nextVal;

            if (nextVal == y) {
                return newCost;
            }

            visited.insert(nextVal);
            q.push({nextVal, newCost});
        }
    }

    return -1;
}

