public class Main {

    static boolean[] isPrime;

    static void sieve(int n) {
        isPrime = new boolean[n + 1];
        Arrays.fill(isPrime, true);
        isPrime[0] = isPrime[1] = false;

        for (int i = 2; i * i <= n; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= n; j += i) {
                    isPrime[j] = false;
                }
            }
        }
    }

    static int minOperations(int x, int y) {
        if (isPrime[x] || isPrime[y]) {
            return -1;
        }

        if (x == y) {
            return x;
        }

        int[] dist = new int[10000];
        Arrays.fill(dist, Integer.MAX_VALUE);

        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> Integer.compare(a[1], b[1]));

        dist[x] = x;
        pq.offer(new int[]{x, x});

        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            int num = curr[0];
            int cost = curr[1];

            if (num == y) {
                return cost;
            }

            if (cost > dist[num]) {
                continue;
            }

            if (num > 0) {
                int next = num - 1;
                if (!isPrime[next]) {
                    int newCost = cost + next;
                    if (newCost < dist[next]) {
                        dist[next] = newCost;
                        pq.offer(new int[]{next, newCost});
                    }
                }
            }

            if (num < 9999) {
                int next = num + 1;
                if (!isPrime[next]) {
                    int newCost = cost + next;
                    if (newCost < dist[next]) {
                        dist[next] = newCost;
                        pq.offer(new int[]{next, newCost});
                    }
                }
            }
        }

        return -1;
    }

