from collections import deque

class Solution:
    def minOperations(self, x: int, y: int) -> int:
        if self.is_prime(y):
            return -1

        if x == y:
            return x

        if self.is_prime(x):
            return -1

        visited = set()
        queue = deque([(x, x)])
        visited.add(x)

        while queue:
            curr, cost = queue.popleft()

            if curr == y:
                return cost


            curr_str = str(curr)
            for i in range(len(curr_str)):
                digit = int(curr_str[i])


                if digit < 9:
                    new_digit = digit + 1
                    new_num_str = curr_str[:i] + str(new_digit) + curr_str[i+1:]
                    new_num = int(new_num_str)

                    if new_num not in visited and not self.is_prime(new_num):
                        visited.add(new_num)
                        queue.append((new_num, cost + new_num))


                if digit > 0:
                    new_digit = digit - 1
                    new_num_str = curr_str[:i] + str(new_digit) + curr_str[i+1:]
                    new_num = int(new_num_str)

                    if new_num not in visited and not self.is_prime(new_num):
                        visited.add(new_num)
                        queue.append((new_num, cost + new_num))

        return -1

    def is_prime(self, n):
        if n < 2:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        for i in range(3, int(n**0.5) + 1, 2):
            if n % i == 0:
                return False
        return True

