func (pq PriorityQueue) Less(i, j int) bool { return pq[i].cost < pq[j].cost }
func (pq PriorityQueue) Swap(i, j int)      { pq[i], pq[j] = pq[j], pq[i] }

func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(State))
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func isPrime(n int) bool {
	if n < 2 {
		return false
	}
	for i := 2; i*i <= n; i++ {
		if n%i == 0 {
			return false
		}
	}
	return true
}

func solve() {
	var xStr, yStr string
	if _, err := fmt.Scan(&xStr, &yStr); err != nil {
		return
	}

	x, _ := strconv.Atoi(xStr)
	y, _ := strconv.Atoi(yStr)

	if isPrime(x) || isPrime(y) {
		fmt.Println("-1")
		return
	}

	limit := 1
	for i := 0; i < len(xStr); i++ {
		limit *= 10
	}

	dist := make(map[int]int)
	pq := &PriorityQueue{}
	heap.Init(pq)

	dist[x] = x
	heap.Push(pq, State{val: x, cost: x})

	for pq.Len() > 0 {
		curr := heap.Pop(pq).(State)

		if curr.val == y {
			fmt.Println(curr.cost)
			return
		}

		if curr.cost > dist[curr.val] {
			continue
		}

		s := fmt.Sprintf("%0*d", len(xStr), curr.val)
		for i := 0; i < len(s); i++ {
			digit := int(s[i] - '0')

			if digit < 9 {
				nextStr := s[:i] + strconv.Itoa(digit+1) + s[i+1:]
				nextVal, _ := strconv.Atoi(nextStr)
				if !isPrime(nextVal) {
					newCost := curr.cost + nextVal
					if v, ok := dist[nextVal]; !ok || newCost < v {
						dist[nextVal] = newCost
						heap.Push(pq, State{val: nextVal, cost: newCost})
					}
				}
			}

			if digit > 0 {
				nextStr := s[:i] + strconv.Itoa(digit-1) + s[i+1:]
				nextVal, _ := strconv.Atoi(nextStr)
				if !isPrime(nextVal) {
					newCost := curr.cost + nextVal
					if v, ok := dist[nextVal]; !ok || newCost < v {
						dist[nextVal] = newCost
						heap.Push(pq, State{val: nextVal, cost: newCost})
					}
				}
			}
		}
	}

	fmt.Println("-1")
}

