public class Solution {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;
        int x = sc.nextInt();
        if (!sc.hasNextInt()) return;
        int y = sc.nextInt();
        System.out.println(solve(x, y));
    }

    public static long solve(int x, int y) {
        if (isPrime(x) || isPrime(y)) return -1;
        if (x == y) return 0;

        int numDigits = String.valueOf(x).length();
        int limit = (int) Math.pow(10, numDigits);

        PriorityQueue<Node> pq = new PriorityQueue<>(Comparator.comparingLong(n -> n.cost));
        Map<Integer, Long> minCost = new HashMap<>();

        pq.add(new Node(x, 0));
        minCost.put(x, 0L);

        while (!pq.isEmpty()) {
            Node current = pq.poll();

            if (current.cost > minCost.getOrDefault(current.val, Long.MAX_VALUE)) continue;
            if (current.val == y) return current.cost;

            int[] digits = getDigits(current.val, numDigits);
            for (int i = 0; i < numDigits; i++) {
                int originalDigit = digits[i];

                if (originalDigit < 9) {
                    digits[i]++;
                    int nextVal = compose(digits);
                    if (!isPrime(nextVal)) {
                        long nextCost = current.cost + nextVal;
                        if (nextCost < minCost.getOrDefault(nextVal, Long.MAX_VALUE)) {
                            minCost.put(nextVal, nextCost);
                            pq.add(new Node(nextVal, nextCost));
                        }
                    }
                    digits[i] = originalDigit;
                }

                if (originalDigit > 0) {
                    digits[i]--;
                    int nextVal = compose(digits);
                    if (!isPrime(nextVal)) {
                        long nextCost = current.cost + nextVal;
                        if (nextCost < minCost.getOrDefault(nextVal, Long.MAX_VALUE)) {
                            minCost.put(nextVal, nextCost);
                            pq.add(new Node(nextVal, nextCost));
                        }
                    }
                    digits[i] = originalDigit;
                }
            }
        }

        return -1;
    }

    private static boolean isPrime(int n) {
        if (n < 2) return false;
        if (n == 2 || n == 3) return true;
        if (n % 2 == 0 || n % 3 == 0) return false;
        for (int i = 5; i * i <= n; i += 6) {
            if (n % i == 0 || n % (i + 2) == 0) return false;
        }
        return true;
    }

    private static int[] getDigits(int val, int n) {
        int[] res = new int[n];
        for (int i = n - 1; i >= 0; i--) {
            res[i] = val % 10;
            val /= 10;
        }
        return res;
    }

    private static int compose(int[] digits) {
        int res = 0;
        for (int d : digits) {
            res = res * 10 + d;
        }
        return res;
    }

    static class Node {
        int val;
        long cost;

        Node(int val, long cost) {
            this.val = val;
            this.cost = cost;
        }
    }
}

