        def is_prime(n):
            if n < 2: return False
            if n == 2: return True
            if n % 2 == 0: return False
            for i in range(3, int(n**0.5) + 1, 2):
                if n % i == 0:
                    return False
            return True

        if is_prime(x) or is_prime(y):
            return -1

        if x == y:
            return x

        num_digits = len(str(x))
        limit = 10**num_digits

        pq = [(x, x)]
        visited = {x: x}

        while pq:
            cost, current = heapq.heappop(pq)

            if current == y:
                return cost

            if cost > visited.get(current, float('inf')):
                continue

            s_current = str(current).zfill(num_digits)
            for i in range(num_digits):
                digit = int(s_current[i])

                if digit < 9:
                    next_val = current + 10**(num_digits - 1 - i)
                    if not is_prime(next_val):
                        new_cost = cost + next_val
                        if new_cost < visited.get(next_val, float('inf')):
                            visited[next_val] = new_cost
                            heapq.heappush(pq, (new_cost, next_val))

                if digit > 0:
                    next_val = current - 10**(num_digits - 1 - i)
                    if not is_prime(next_val):
                        new_cost = cost + next_val
                        if new_cost < visited.get(next_val, float('inf')):
                            visited[next_val] = new_cost
                            heapq.heappush(pq, (new_cost, next_val))

        return -1

