class Solution {
public:
    bool checkValidDividers(int m, vector<vector<int>>& plots) {
        return check(plots, 0, 2) || check(plots, 1, 3);
    }

private:
    bool check(vector<vector<int>>& plots, int start_idx, int end_idx) {
        int n = plots.size();
        vector<pair<int, int>> intervals;
        for (const auto& p : plots) {
            intervals.push_back({p[start_idx], p[end_idx]});
        }
        sort(intervals.begin(), intervals.end());

        int count = 0;
        int current_max_end = 0;
        int i = 0;
        while (i < n) {
            count++;
            current_max_end = intervals[i].second;
            int j = i + 1;
            while (j < n && intervals[j].first < current_max_end) {
                current_max_end = max(current_max_end, intervals[j].second);
                j++;
            }
            i = j;
            if (count >= 3) return true;
        }
        return count >= 3;
    }
};

