func check(m int, plots [][]int, startIdx int, endIdx int) bool {
	n := len(plots)
	type Interval struct {
		low, high int
	}
	intervals := make([]Interval, n)
	for i := 0; i < n; i++ {
		intervals[i] = Interval{plots[i][startIdx], plots[i][endIdx]}
	}

	sort.Slice(intervals, func(i, j int) bool {
		if intervals[i].low != intervals[j].low {
			return intervals[i].low < intervals[j].low
		}
		return intervals[i].high < intervals[j].high
	})

	dividers := 0
	currentMax := intervals[0].high
	for i := 1; i < n; i++ {
		if intervals[i].low >= currentMax {
			dividers++
			currentMax = intervals[i].high
		} else {
			if intervals[i].high > currentMax {
				currentMax = intervals[i].high
			}
		}
	}

	return dividers >= 2
}

