    public boolean checkValidDividers(int m, int[][] plots) {
        return check(plots, 0, 2) || check(plots, 1, 3);
    }

    private boolean check(int[][] plots, int startIdx, int endIdx) {
        int n = plots.length;
        int[][] sorted = new int[n][2];
        for (int i = 0; i < n; i++) {
            sorted[i][0] = plots[i][startIdx];
            sorted[i][1] = plots[i][endIdx];
        }
        Arrays.sort(sorted, (a, b) -> Integer.compare(a[0], b[0]));

        int[] maxEndPrefix = new int[n];
        maxEndPrefix[0] = sorted[0][1];
        for (int i = 1; i < n; i++) {
            maxEndPrefix[i] = Math.max(maxEndPrefix[i - 1], sorted[i][1]);
        }

        List<Integer> gaps = new ArrayList<>();
        for (int i = 0; i < n - 1; i++) {
            if (maxEndPrefix[i] <= sorted[i + 1][0]) {
                gaps.add(i);
            }
        }

        return gaps.size() >= 2;
    }
}

