bool check(int d, const vector<int>& elevations) {
    int n = elevations.size();
    int min_val = -2e9, max_val = 2e9;

    for (int i = 0; i < n; ++i) {
        if (elevations[i] != -1) {
            if (i > 0 && elevations[i-1] != -1) {
                if (abs(elevations[i] - elevations[i-1]) > d) return false;
            }
        }
    }

    vector<pair<int, int>> ranges;
    int i = 0;
    while (i < n) {
        if (elevations[i] == -1) {
            int start = i;
            while (i < n && elevations[i] == -1) i++;
            int end = i - 1;

            int L = -2e9, R = 2e9;
            if (start > 0) {
                L = max(L, elevations[start-1] - d);
                R = min(R, elevations[start-1] + d);
            }
            if (end < n - 1) {
                L = max(L, elevations[end+1] - d);
                R = min(R, elevations[end+1] + d);
            }

            if (L > R) return false;
            ranges.push_back({L, R});
        } else {
            i++;
        }
    }

    if (ranges.empty()) return true;

    int common_L = -2e9, common_R = 2e9;
    for (auto& p : ranges) {
        common_L = max(common_L, p.first);
        common_R = min(common_R, p.second);
    }
    if (common_L <= common_R) return true;

    int S1 = 2e9, T1 = -2e9;
    for (auto& p : ranges) {
        S1 = min(S1, p.second);
        T1 = max(T1, p.first);
    }

    if (T1 - S1 <= d) return true;

    for (auto& p : ranges) {
        bool okS1 = (S1 >= p.first && S1 <= p.second);
        bool okT1 = (T1 >= p.first && T1 <= p.second);
        if (!okS1 && !okT1) return false;
    }

    return true;
}

