void dfs(int u, int p) {
    vector<long long> diffs;
    long long base_sum = 0;

    for (auto& edge : adj[u]) {
        int v = edge.to;
        int w = edge.weight;
        if (v == p) continue;
        dfs(v, u);

        base_sum += dp[v][0];
        long long gain = (long long)w + dp[v][1] - dp[v][0];
        if (gain > 0) {
            diffs.push_back(gain);
        }
    }

    sort(diffs.rbegin(), diffs.rend());

    for (int i = 0; i < 2; ++i) {
        int limit = K - i;
        long long current_sum = base_sum;
        for (int j = 0; j < (int)diffs.size() && j < limit; ++j) {
            current_sum += diffs[j];
        }
        dp[u][i] = current_sum;
    }
}

