func newDSU(n int) *DSU {
	parent := make([]int, n)
	for i := range parent {
		parent[i] = i
	}
	return &DSU{parent: parent, size: n}
}

func (d *DSU) find(i int) int {
	if d.parent[i] == i {
		return i
	}
	d.parent[i] = d.find(d.parent[i])
	return d.parent[i]
}

func (d *DSU) union(i, j int) {
	rootI := d.find(i)
	rootJ := d.find(j)
	if rootI != rootJ {
		d.parent[rootI] = rootJ
		d.size--
	}
}

func gcd(a, b int) int {
	for b != 0 {
		a %= b
		a, b = b, a
	}
	return a
}

func lcm(a, b int) int {
	if a == 0 || b == 0 {
		return 0
	}
	res := (a / gcd(a, b)) * b
	return res
}

func solve() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Split(bufio.ScanWords)

	var elements []int
	if !scanner.Scan() {
		return
	}
	n, _ := strconv.Atoi(scanner.Text())
	elements = make([]int, n)
	for i := 0; i < n; i++ {
		scanner.Scan()
		elements[i], _ = strconv.Atoi(scanner.Text())
	}
	scanner.Scan()
	limit, _ := strconv.Atoi(scanner.Text())

	dsu := newDSU(n)
	valToIndex := make(map[int]int)
	for i, v := range elements {
		valToIndex[v] = i
	}

	minNodeForMultiple := make([]int, limit+1)
	for i := range minNodeForMultiple {
		minNodeForMultiple[i] = -1
	}

	for i, v := range elements {
		if v > limit {
			continue
		}
		for g := 1; g*g <= v; g++ {
			if v%g == 0 {
				factors := []int{g, v / g}
				for _, f := range factors {
					if minNodeForMultiple[f] == -1 {
						minNodeForMultiple[f] = i
					} else {
						prevIdx := minNodeForMultiple[f]
						if lcm(elements[prevIdx], v) <= limit {
							dsu.union(prevIdx, i)
						}
						if v < elements[prevIdx] {
							minNodeForMultiple[f] = i
						}
					}
				}
			}
		}
	}

	for g := 1; g <= limit; g++ {
		first := -1
		for m := g; m <= limit; m += g {
			if idx, ok := valToIndex[m]; ok {
				if first == -1 {
					first = idx
				} else {
					if (int64(elements[first])/int64(g))*int64(elements[idx]) <= int64(limit) {
						dsu.union(first, idx)
					}
				}
			}
		}
	}

	fmt.Println(dsu.size)
}

