class Solution {
    public int countGroups(int[] elements, int limit) {
        int n = elements.length;
        DSU dsu = new DSU(n);
        int[] minValForMultiple = new int[limit + 1];
        Arrays.fill(minValForMultiple, -1);

        List<Integer> validIndices = new ArrayList<>();
        int disconnectedCount = 0;

        for (int i = 0; i < n; i++) {
            if (elements[i] > limit) {
                disconnectedCount++;
                continue;
            }
            validIndices.add(i);
            for (int j = elements[i]; j <= limit; j += elements[i]) {
                if (minValForMultiple[j] == -1 || elements[i] < elements[minValForMultiple[j]]) {
                    minValForMultiple[j] = i;
                }
            }
        }

        for (int i : validIndices) {
            long valI = elements[i];
            for (long m = valI; m <= limit; m += valI) {
                int j = minValForMultiple[(int)m];
                if (j != -1 && j != i) {
                    if (lcm(valI, (long)elements[j]) <= (long)limit) {
                        dsu.union(i, j);
                    }
                }
            }
        }

        Set<Integer> roots = new HashSet<>();
        for (int i : validIndices) {
            roots.add(dsu.find(i));
        }

        return roots.size() + disconnectedCount;
    }

    private long gcd(long a, long b) {
        while (b > 0) {
            a %= b;
            long tmp = a;
            a = b;
            b = tmp;
        }
        return a;
    }

    private long lcm(long a, long b) {
        if (a == 0 || b == 0) return 0;
        return (a / gcd(a, b)) * b;
    }

    class DSU {
        int[] parent;
        DSU(int n) {
            parent = new int[n];
            for (int i = 0; i < n; i++) parent[i] = i;
        }
        int find(int i) {
            if (parent[i] == i) return i;
            return parent[i] = find(parent[i]);
        }
        void union(int i, int j) {
            int rootI = find(i);
            int rootJ = find(j);
            if (rootI != rootJ) parent[rootI] = rootJ;
        }
    }
}

