    int largestParallelogramArea(vector<vector<int>>& locations) {
        int n = locations.size();
        if (n < 4) return -1;

        set<pair<int, int>> points;
        for (const auto& loc : locations) {
            points.insert({loc[0], loc[1]});
        }

        long long maxArea = -1;

        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                for (int k = 0; k < n; ++k) {
                    if (k == i || k == j) continue;
                    for (int l = 0; l < n; ++l) {
                        if (l == i || l == j || l == k) continue;

                        int x1 = locations[i][0], y1 = locations[i][1];
                        int x2 = locations[j][0], y2 = locations[j][1];
                        int x3 = locations[k][0], y3 = locations[k][1];
                        int x4 = locations[l][0], y4 = locations[l][1];

                        int minX = min({x1, x2, x3, x4});
                        int maxX = max({x1, x2, x3, x4});
                        int minY = min({y1, y2, y3, y4});
                        int maxY = max({y1, y2, y3, y4});

                        set<pair<int, int>> rectPoints = {{x1, y1}, {x2, y2}, {x3, y3}, {x4, y4}};
                        if (rectPoints.size() != 4) continue;

                        if (!((rectPoints.count({minX, minY}) && rectPoints.count({minX, maxY}) && 
                               rectPoints.count({maxX, minY}) && rectPoints.count({maxX, maxY})))) {
                            continue;
                        }

                        if (minX == maxX || minY == maxY) continue;

                        bool empty = true;
                        for (const auto& p : points) {
                            if (rectPoints.count(p)) continue;
                            if (p.first >= minX && p.first <= maxX && p.second >= minY && p.second <= maxY) {
                                empty = false;
                                break;
                            }
                        }

                        if (empty) {
                            long long area = (long long)(maxX - minX) * (maxY - minY);
                            if (area > maxArea) maxArea = area;
                        }
                    }
                }
            }
        }

        return (int)maxArea;
    }
