class Solution {
    public int largestParallelogramArea(int[][] locations) {
        int n = locations.length;
        int maxArea = -1;

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                for (int k = j + 1; k < n; k++) {
                    for (int l = k + 1; l < n; l++) {
                        int[][] p = {locations[i], locations[j], locations[k], locations[l]};

                        int minX = Integer.MAX_VALUE, maxX = Integer.MIN_VALUE;
                        int minY = Integer.MAX_VALUE, maxY = Integer.MIN_VALUE;
                        Set<String> set = new HashSet<>();
                        for (int[] pt : p) {
                            minX = Math.min(minX, pt[0]);
                            maxX = Math.max(maxX, pt[0]);
                            minY = Math.min(minY, pt[1]);
                            maxY = Math.max(maxY, pt[1]);
                            set.add(pt[0] + "," + pt[1]);
                        }

                        if (set.size() == 4 && 
                            set.contains(minX + "," + minY) &&
                            set.contains(minX + "," + maxY) &&
                            set.contains(maxX + "," + minY) &&
                            set.contains(maxX + "," + maxY)) {

                            int area = (maxX - minX) * (maxY - minY);
                            if (area <= 0) continue;

                            boolean valid = true;
                            for (int m = 0; m < n; m++) {
                                int px = locations[m][0];
                                int py = locations[m][1];
                                if (set.contains(px + "," + py)) continue;
                                if (px >= minX && px <= maxX && py >= minY && py <= maxY) {
                                    valid = false;
                                    break;
                                }
                            }

                            if (valid) {
                                maxArea = Math.max(maxArea, area);
                            }
                        }
                    }
                }
            }
        }
        return maxArea;
    }
}

