        points = sorted([(p[0], p[1]) for p in locations])
        point_set = set(points)
        max_area = -1

        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    for l in range(k + 1, n):
                        rect_points = [points[i], points[j], points[k], points[l]]
                        xs = sorted(list(set(p[0] for p in rect_points)))
                        ys = sorted(list(set(p[1] for p in rect_points)))

                        if len(xs) == 2 and len(ys) == 2:
                            x1, x2 = xs
                            y1, y2 = ys

                            valid_rect = True
                            for x in xs:
                                for y in ys:
                                    if (x, y) not in rect_points:
                                        valid_rect = False
                                        break
                                if not valid_rect: break

                            if valid_rect:
                                area = (x2 - x1) * (y2 - y1)
                                contains_other = False
                                for p in points:
                                    if p in rect_points:
                                        continue
                                    if x1 <= p[0] <= x2 and y1 <= p[1] <= y2:
                                        contains_other = True
                                        break

                                if not contains_other:
                                    if area > max_area:
                                        max_area = area
        return max_area

