class Solution {
public:
    string computeLargestString(string sequence, int numAgents) {
        vector<string> allSubstrings;
        vector<int> cuts;
        generateDivisions(sequence, numAgents, 0, cuts, allSubstrings);

        string result = "";
        for (const string& s : allSubstrings) {
            if (s > result) {
                result = s;
            }
        }
        return result;
    }

private:
    void generateDivisions(const string& sequence, int remaining, int start, vector<int>& cuts, vector<string>& allSubstrings) {
        if (remaining == 1) {
            cuts.push_back(sequence.length());

            int prev = 0;
            for (int cut : cuts) {
                allSubstrings.push_back(sequence.substr(prev, cut - prev));
                prev = cut;
            }

            cuts.pop_back();
            return;
        }

        int maxEnd = sequence.length() - remaining + 1;
        for (int end = start + 1; end <= maxEnd; end++) {
            cuts.push_back(end);
            generateDivisions(sequence, remaining - 1, end, cuts, allSubstrings);
            cuts.pop_back();
        }
    }
};

