func computeLargestString(sequence string, numAgents int) string {
    var allSubstrings []string

    var generateDivisions func(start int, parts []string, remaining int)
    generateDivisions = func(start int, parts []string, remaining int) {
        if remaining == 1 {
            parts = append(parts, sequence[start:])
            for _, part := range parts {
                allSubstrings = append(allSubstrings, part)
            }
            return
        }

        for i := start + 1; i <= len(sequence)-(remaining-1); i++ {
            newParts := make([]string, len(parts))
            copy(newParts, parts)
            newParts = append(newParts, sequence[start:i])
            generateDivisions(i, newParts, remaining-1)
        }
    }

    generateDivisions(0, []string{}, numAgents)

    maxString := ""
    for _, s := range allSubstrings {
        if strings.Compare(s, maxString) > 0 {
            maxString = s
        }
    }

    return maxString
}

