public class Solution {

    public String computeLargestString(String sequence, int numAgents) {
        Set<String> container = new HashSet<>();
        generateDivisions(sequence, numAgents, 0, new ArrayList<>(), container);

        String largest = "";
        for (String s : container) {
            if (s.compareTo(largest) > 0) {
                largest = s;
            }
        }
        return largest;
    }

    private void generateDivisions(String sequence, int remaining, int start, List<String> current, Set<String> container) {
        if (remaining == 1) {
            current.add(sequence.substring(start));
            container.addAll(current);
            current.remove(current.size() - 1);
            return;
        }

        for (int i = start + 1; i <= sequence.length() - remaining + 1; i++) {
            current.add(sequence.substring(start, i));
            generateDivisions(sequence, remaining - 1, i, current, container);
            current.remove(current.size() - 1);
        }
    }

