    if (arr.empty()) return 0;

    long long maxSum = arr[0];
    long long currentSum = arr[0];

    for (int i = 1; i < arr.size(); i++) {
        currentSum = max((long long)arr[i], currentSum + arr[i]);
        maxSum = max(maxSum, currentSum);
    }

    return maxSum;
}

