func kadane(arr []int) int {
    if len(arr) == 0 {
        return math.MinInt32
    }

    maxSoFar := arr[0]
    maxEndingHere := arr[0]

    for i := 1; i < len(arr); i++ {
        maxEndingHere = max(arr[i], maxEndingHere+arr[i])
        maxSoFar = max(maxSoFar, maxEndingHere)
    }

    return maxSoFar
}

func max(a, b int) int {
    if a > b {
        return a
    }
    return b
}

func findMaxConsecutiveSum(sales []int) int {

    uniqueValues := make(map[int]bool)
    for _, val := range sales {
        uniqueValues[val] = true
    }

    maxSum := kadane(sales)


    for valueToRemove := range uniqueValues {

        newArray := make([]int, 0)
        for _, val := range sales {
            if val != valueToRemove {
                newArray = append(newArray, val)
            }
        }


        if len(newArray) > 0 {
            currentSum := kadane(newArray)
            maxSum = max(maxSum, currentSum)
        }
    }

    return maxSum
}

