public class Solution {

    public int findMaxConsecutiveSum(int[] sales) {
        Set<Integer> uniqueValues = new HashSet<>();
        for (int val : sales) {
            uniqueValues.add(val);
        }

        int maxSum = kadane(sales);

        for (int valueToRemove : uniqueValues) {
            List<Integer> filtered = new ArrayList<>();
            for (int val : sales) {
                if (val != valueToRemove) {
                    filtered.add(val);
                }
            }

            if (!filtered.isEmpty()) {
                int[] filteredArray = filtered.stream().mapToInt(i -> i).toArray();
                maxSum = Math.max(maxSum, kadane(filteredArray));
            }
        }

        return maxSum;
    }

    private int kadane(int[] arr) {
        if (arr.length == 0) return 0;

        int maxSoFar = arr[0];
        int maxEndingHere = arr[0];

        for (int i = 1; i < arr.length; i++) {
            maxEndingHere = Math.max(arr[i], maxEndingHere + arr[i]);
            maxSoFar = Math.max(maxSoFar, maxEndingHere);
        }

        return maxSoFar;
    }

