using namespace std;

class Solution {
public:
    long long findMaxConsecutiveSum(vector<int>& sales) {
        int n = sales.size();
        long long max_sum = -2e18;
        for (int x : sales) max_sum = max(max_sum, (long long)x);
        if (max_sum <= 0) return max_sum;

        auto get_kadane = [&](const vector<int>& arr) {
            long long cur = 0, best = 0;
            for (int x : arr) {
                cur += x;
                if (cur < 0) cur = 0;
                best = max(best, cur);
            }
            return best;
        };

        long long ans = get_kadane(sales);
        map<int, vector<int>> indices;
        for (int i = 0; i < n; ++i) {
            indices[sales[i]].push_back(i);
        }

        vector<long long> pref(n + 1, 0);
        for (int i = 0; i < n; ++i) pref[i + 1] = pref[i] + sales[i];

        for (auto const& [val, idx_list] : indices) {
            if (val >= 0) continue;

            long long current_max = 0;
            long long min_prev = 0;
            long long val_contribution = 0;

            int last_idx = -1;
            for (int idx : idx_list) {
                long long segment_sum = pref[idx] - pref[last_idx + 1];
                val_contribution += segment_sum;
                current_max = max(current_max, val_contribution - min_prev);
                min_prev = min(min_prev, val_contribution);
                last_idx = idx;
            }

            val_contribution += pref[n] - pref[last_idx + 1];
            current_max = max(current_max, val_contribution - min_prev);
            ans = max(ans, current_max);
        }

        return ans;
    }
};

