public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        String line = reader.readLine();
        if (line == null) return;

        String content = line.trim();
        if (content.startsWith("sales = ")) {
            content = content.substring(8);
        }
        content = content.replaceAll("[\\[\\] ]", "");
        if (content.isEmpty()) return;
        String[] parts = content.split(",");
        int[] sales = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            sales[i] = Integer.parseInt(parts[i]);
        }

        System.out.println(solve(sales));
    }

    private static long solve(int[] sales) {
        int n = sales.length;
        long maxOverall = Long.MIN_VALUE;
        for (int x : sales) maxOverall = Math.max(maxOverall, (long)x);

        long currentMax = 0;
        for (int x : sales) {
            currentMax += x;
            maxOverall = Math.max(maxOverall, currentMax);
            if (currentMax < 0) currentMax = 0;
        }

        Map<Integer, List<Integer>> indicesMap = new HashMap<>();
        for (int i = 0; i < n; i++) {
            indicesMap.computeIfAbsent(sales[i], k -> new ArrayList<>()).add(i);
        }

        if (indicesMap.size() <= 1) return maxOverall;

        long[] prefixSum = new long[n + 1];
        for (int i = 0; i < n; i++) prefixSum[i + 1] = prefixSum[i] + sales[i];

        for (Map.Entry<Integer, List<Integer>> entry : indicesMap.entrySet()) {
            int y = entry.getKey();
            List<Integer> indices = entry.getValue();

            if (indices.size() == n) continue;

            long minPrev = 0;
            long currentSum = 0;
            long lastYSum = 0;

            for (int i = 0; i < indices.size(); i++) {
                int currIdx = indices.get(i);
                int prevIdx = (i == 0) ? -1 : indices.get(i - 1);

                if (currIdx > prevIdx + 1) {
                    long segmentSum = prefixSum[currIdx] - prefixSum[prevIdx + 1];

                    long temp = lastYSum + segmentSum;
                    maxOverall = Math.max(maxOverall, temp - minPrev);

                    long localCurrent = 0;
                    for (int k = prevIdx + 1; k < currIdx; k++) {
                        localCurrent += sales[k];
                        maxOverall = Math.max(maxOverall, localCurrent);
                        if (localCurrent < 0) localCurrent = 0;
                    }

                    lastYSum += segmentSum;
                    minPrev = Math.min(minPrev, lastYSum - segmentSum);
                }
            }

            int lastIdx = indices.get(indices.size() - 1);
            if (lastIdx < n - 1) {
                long segmentSum = prefixSum[n] - prefixSum[lastIdx + 1];
                maxOverall = Math.max(maxOverall, lastYSum + segmentSum - minPrev);

                long localCurrent = 0;
                for (int k = lastIdx + 1; k < n; k++) {
                    localCurrent += sales[k];
                    maxOverall = Math.max(maxOverall, localCurrent);
                    if (localCurrent < 0) localCurrent = 0;
                }
            }
        }

        return maxOverall;
    }
}

