public class Solution {
    public int minConsecutiveLength(String s, int maxChanges) {
        int n = s.length();
        int left = 1, right = n;
        int result = n;

        while (left <= right) {
            int mid = (left + right) / 2;
            if (canAchieve(s, maxChanges, mid)) {
                result = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }

        return result;
    }

    private boolean canAchieve(String s, int maxChanges, int target) {
        int n = s.length();
        char[] arr = s.toCharArray();
        int changes = 0;

        int i = 0;
        while (i < n) {
            int j = i;
            while (j < n && arr[j] == arr[i]) {
                j++;
            }

            int len = j - i;
            if (len > target) {
                int needed = len - target;
                changes += (needed + 1) / 2;
                if (changes > maxChanges) {
                    return false;
                }
            }

            i = j;
        }

        return true;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int maxChanges = sc.nextInt();

        Solution solution = new Solution();
        System.out.println(solution.minConsecutiveLength(s, maxChanges));
    }
}

