public class Solution {
    public int minConsecutiveLength(String s, int maxChanges) {
        int n = s.length();
        int left = 1, right = n;
        int ans = n;

        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (canAchieve(s, mid, maxChanges)) {
                ans = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return ans;
    }

    private boolean canAchieve(String s, int k, int maxChanges) {
        int n = s.length();
        if (k == 1) {
            int cost1 = 0; 
            int cost2 = 0; 
            for (int i = 0; i < n; i++) {
                char target1 = (i % 2 == 0) ? 'A' : 'B';
                char target2 = (i % 2 == 0) ? 'B' : 'A';
                if (s.charAt(i) != target1) cost1++;
                if (s.charAt(i) != target2) cost2++;
            }
            return Math.min(cost1, cost2) <= maxChanges;
