        for (int i = 1; i < n; i++) {
            if (s.charAt(i) == s.charAt(i - 1)) {
                count++;
            } else {
                totalChanges += count / (k + 1);
                count = 1;
            }
        }
        totalChanges += count / (k + 1);
        return totalChanges <= maxChanges;
    }

