class Solution {
public:
    long long countBalancedQuadruplets(vector<int>& plants) {
        int n = plants.size();
        long long total = 0;
        vector<map<pair<int, int>, int>> left_counts(n);

        for (int b = 2; b < n - 4; ++b) {
            int a = b - 2;
            for (int i = 0; i <= a; ++i) {
                int g = gcd(plants[i], plants[b]);
                left_counts[b][{plants[i] / g, plants[b] / g}]++;
            }
        }

        for (int c = 4; c < n - 2; ++c) {
            map<pair<int, int>, int> current_left;
            for (int b = 2; b <= c - 2; ++b) {
                for (auto const& [ratio, count] : left_counts[b]) {
                    current_left[ratio] += count;
                }
            }

            for (int d = c + 2; d < n; ++d) {
                int g = gcd(plants[c], plants[d]);
                pair<int, int> target = {plants[d] / g, plants[c] / g};
                if (current_left.count(target)) {
                    total += current_left[target];
                }
            }
        }
        return total;
    }

private:
    int gcd(int a, int b) {
        while (b) {
            a %= b;
            swap(a, b);
        }
        return a;
    }
};

