class Solution {
public:
    int countSubsequencesWithCentralMode(vector<int>& elements) {
        int n = elements.size();
        long long result = 0;

        for (int i = 2; i < n - 2; i++) {
            int central = elements[i];

            for (int j = 0; j < i; j++) {
                for (int k = j + 1; k < i; k++) {
                    for (int l = i + 1; l < n; l++) {
                        for (int m = l + 1; m < n; m++) {
                            vector<int> subseq = {elements[j], elements[k], central, elements[l], elements[m]};

                            unordered_map<int, int> freq;
                            for (int val : subseq) {
                                freq[val]++;
                            }

                            int maxFreq = 0;
                            for (auto& p : freq) {
                                maxFreq = max(maxFreq, p.second);
                            }

                            int modeCount = 0;
                            bool centralIsMode = false;
                            for (auto& p : freq) {
                                if (p.second == maxFreq) {
                                    modeCount++;
                                    if (p.first == central) {
                                        centralIsMode = true;
                                    }
                                }
                            }

                            if (modeCount == 1 && centralIsMode) {
                                result = (result + 1) % MOD;
                            }
                        }
                    }
                }
            }
        }

        return result;
    }
};

