class Solution {
    long long MOD = 1e9 + 7;
    long long nCr[1001][6];

    void precompute() {
        for (int i = 0; i <= 1000; i++) {
            nCr[i][0] = 1;
            for (int j = 1; j <= min(i, 5); j++) {
                nCr[i][j] = (nCr[i - 1][j - 1] + nCr[i - 1][j]) % MOD;
            }
        }
    }

public:
    int countSubsequencesWithCentralMode(vector<int>& elements) {
        precompute();
        int n = elements.size();
        map<int, int> total_counts;
        for (int x : elements) total_counts[x]++;

        map<int, int> left_counts;
        long long ans = 0;

        for (int i = 0; i < n; i++) {
            int x = elements[i];
            int right_total = n - 1 - i;
            int left_total = i;

            int tr = total_counts[x];
            int lr = left_counts[x];
            int rr = tr - lr - 1;

            long long total_ways = nCr[left_total][2] * nCr[right_total][2] % MOD;

            long long bad = 0;

            for (auto const& [val, count] : total_counts) {
                if (val == x) continue;
                int l = left_counts[val];
                int r = count - l;

                bad = (bad + nCr[l][2] * nCr[right_total - r][2]) % MOD;
                bad = (bad + nCr[r][2] * nCr[left_total - l][2]) % MOD;
                bad = (bad - nCr[l][2] * nCr[r][2]) % MOD;

                bad = (bad + (long long)l * r % MOD * (left_total - l) % MOD * (right_total - r)) % MOD;
                bad = (bad + (long long)l * r % MOD * nCr[left_total - l][2]) % MOD;
                bad = (bad + (long long)l * r % MOD * nCr[right_total - r][2]) % MOD;
            }

            ans = (ans + total_ways - bad + MOD) % MOD;
            left_counts[x]++;
        }

        return (int)ans;
    }
};

