const MOD = 1000000007

func nCr(n, r int) int64 {
	if r < 0 || r > n {
		return 0
	}
	if r == 0 || r == n {
		return 1
	}
	if r > n/2 {
		r = n - r
	}
	res := int64(1)
	for i := 1; i <= r; i++ {
		res = res * int64(n-i+1) / int64(i)
	}
	return res
}

func solve() {
	scanner := bufio.NewScanner(os.Stdin)
