	if n < 5 {
		fmt.Println(0)
		return
	}

	totalFreq := make(map[int]int)
	for _, x := range elements {
		totalFreq[x]++
	}

	leftFreq := make(map[int]int)
	rightFreq := make(map[int]int)
	for _, x := range elements {
		rightFreq[x]++
	}

	var totalCount int64 = 0
	allWays := nCr(n, 5)

	for i := 0; i < n; i++ {
		x := elements[i]
		rightFreq[x]--

		l := leftFreq[x]
		r := rightFreq[x]

		l_other := i - l
		r_other := (n - 1 - i) - r

		bad := int64(0)

		bad = (bad + nCr(l_other, 2)*nCr(r_other, 2)) % MOD

		for val, lf := range leftFreq {
			if val == x {
				continue
			}
			rf := rightFreq[val]

			bad = (bad + nCr(lf, 2)*nCr(rf, 1)*int64(r_other-rf)) % MOD
			bad = (bad + nCr(lf, 1)*nCr(rf, 2)*int64(l_other-lf)) % MOD
			bad = (bad + nCr(lf, 2)*nCr(rf, 2)) % MOD

			bad = (bad + nCr(lf, 2)*int64(r)*int64(r_other-rf)) % MOD
			bad = (bad + nCr(lf, 2)*int64(r)*int64(rf)) % MOD
			bad = (bad + int64(l)*nCr(rf, 2)*int64(l_other-lf)) % MOD
			bad = (bad + int64(l)*nCr(rf, 2)*int64(lf)) % MOD
		}

		totalCount = (totalCount + (nCr(i, 2)*nCr(n-1-i, 2)%MOD - bad + MOD)) % MOD

		leftFreq[x]++
	}

	fmt.Println(totalCount)
