long long calculateGCD(const vector<int>& arr, int start, int end) {
    long long result = arr[start];
    for (int i = start + 1; i <= end; i++) {
        result = gcd(result, arr[i]);
    }
    return result;
}

long long calculateLCM(const vector<int>& arr, int start, int end) {
    long long result = arr[start];
    for (int i = start + 1; i <= end; i++) {
        result = lcm(result, arr[i]);
    }
    return result;
}

long long calculateProduct(const vector<int>& arr, int start, int end) {
    long long result = 1;
    for (int i = start; i <= end; i++) {
        result *= arr[i];
    }
    return result;
}

