public class Solution {
    public long maximumEnergy(int[][] energy, int k) {
        Arrays.sort(energy, (a, b) -> Integer.compare(a[0], b[0]));

        Set<Integer> boundaries = new TreeSet<>();
        for (int[] seg : energy) {
            boundaries.add(seg[0]);
            boundaries.add(seg[1] + 1);
        }

        List<Integer> boundaryList = new ArrayList<>(boundaries);
        Map<Integer, Integer> energyMap = new HashMap<>();

        for (int[] seg : energy) {
            energyMap.put(seg[0], seg[2]);
        }

        long maxEnergy = 0;
        long currentSum = 0;
        int left = 0;
        int currentPos = boundaryList.get(0);

        for (int right = 0; right < boundaryList.size() - 1; right++) {
            int start = boundaryList.get(right);
            int end = boundaryList.get(right + 1) - 1;
            int segmentLength = end - start + 1;
            int energyValue = energyMap.getOrDefault(start, 0);

            currentSum += (long) segmentLength * energyValue;
            currentPos = end + 1;

            while (currentPos - boundaryList.get(left) >= k) {
                int leftStart = boundaryList.get(left);
                int leftEnd = boundaryList.get(left + 1) - 1;
                int leftLength = leftEnd - leftStart + 1;
                int leftEnergy = energyMap.getOrDefault(leftStart, 0);

                int removeLength = leftLength;
                if (currentPos - boundaryList.get(left) > k) {
                    removeLength = (currentPos - boundaryList.get(left)) - k;
                    removeLength = Math.min(removeLength, leftLength);
                }

                currentSum -= (long) removeLength * leftEnergy;

                if (removeLength == leftLength) {
                    left++;
                } else {
                    break;
                }
            }

            if (currentPos - boundaryList.get(left) == k) {
                maxEnergy = Math.max(maxEnergy, currentSum);
            }
        }

        return maxEnergy;
    }

