                    right = mid - 1;
                }
            }

            long long current_e = prefix_sum[idx] - prefix_sum[i];
            long long overlap_end = min((long long)energy[idx][1], R);
            current_e += (overlap_end - energy[idx][0] + 1) * energy[idx][2];
            max_e = max(max_e, current_e);
        }

        for (int i = 0; i < n; ++i) {
            long long R = energy[i][1];
            long long L = R - k + 1;

            int left = 0, right = i, idx = i;
            while (left <= right) {
                int mid = left + (right - left) / 2;
                if (energy[mid][1] >= L) {
                    idx = mid;
                    right = mid - 1;
                } else {
                    left = mid + 1;
                }
            }

            long long current_e = prefix_sum[i + 1] - prefix_sum[idx + 1];
            long long overlap_start = max((long long)energy[idx][0], L);
            current_e += (energy[idx][1] - overlap_start + 1) * energy[idx][2];
            max_e = max(max_e, current_e);
        }

        return max_e;
    }
