func longestHeightSubsequence(heights []int) int {
	n := len(heights)
	memo := make(map[string]int)

	var dp func(int, int, int) int
	dp = func(pos, prev, prevDiff int) int {
		if pos == n {
			return 0
		}

		key := fmt.Sprintf("%d,%d,%d", pos, prev, prevDiff)
		if val, exists := memo[key]; exists {
			return val
		}


		result := dp(pos+1, prev, prevDiff)


		if prev == -1 {

			result = max(result, 1+dp(pos+1, pos, -1))
		} else {
			currDiff := abs(heights[pos] - heights[prev])
			if prevDiff == -1 || currDiff <= prevDiff {
				result = max(result, 1+dp(pos+1, pos, currDiff))
			}
		}

		memo[key] = result
		return result
	}

	return dp(0, -1, -1)
