public class Solution {
    private Map<String, Integer> memo = new HashMap<>();

    public int longestHeightSubsequence(int[] heights) {
        return solve(heights, 0, -1, Integer.MAX_VALUE);
    }

    private int solve(int[] heights, int idx, int prevIdx, int prevDiff) {
        if (idx == heights.length) {
            return 0;
        }

        String key = idx + "," + prevIdx + "," + prevDiff;
        if (memo.containsKey(key)) {
            return memo.get(key);
        }

        int result = solve(heights, idx + 1, prevIdx, prevDiff);

        if (prevIdx == -1) {
            result = Math.max(result, 1 + solve(heights, idx + 1, idx, Integer.MAX_VALUE));
        } else {
            int currentDiff = Math.abs(heights[idx] - heights[prevIdx]);
            if (currentDiff <= prevDiff) {
                result = Math.max(result, 1 + solve(heights, idx + 1, idx, currentDiff));
            }
        }

        memo.put(key, result);
        return result;
    }

