    public int longestHeightSubsequence(int[] heights) {
        int n = heights.length;
        int maxH = 0;
        for (int h : heights) maxH = Math.max(maxH, h);

        int[][] dp = new int[maxH + 1][maxH + 1];
        for (int i = 0; i <= maxH; i++) {
            Arrays.fill(dp[i], 1);
        }

        int result = 0;
        for (int i = 0; i < n; i++) {
            int curr = heights[i];
            for (int prev = 1; prev <= maxH; prev++) {
                int diff = Math.abs(curr - prev);
