public class Main {
    static class Point {
        double x, y;
        Point(double x, double y) {
            this.x = x;
            this.y = y;
        }
        double dist(Point other) {
            return Math.sqrt((x - other.x) * (x - other.x) + (y - other.y) * (y - other.y));
        }
    }

    static class Segment {
        Point p1, p2;
        double length;
        Segment(double x1, double y1, double x2, double y2) {
            p1 = new Point(x1, y1);
            p2 = new Point(x2, y2);
            length = p1.dist(p2);
        }
    }

    static int N;
    static double S, T;
