}

type Segment struct {
	p1, p2 Point
	dist   float64
}

func dist(a, b Point) float64 {
	return math.Sqrt((a.x-b.x)*(a.x-b.x) + (a.y-b.y)*(a.y-b.y))
}

func main() {
	var n int
	var s, t float64
	if _, err := fmt.Scan(&n, &s, &t); err != nil {
		return
	}

	segments := make([]Segment, n)
	for i := 0; i < n; i++ {
		fmt.Scan(&segments[i].p1.x, &segments[i].p1.y, &segments[i].p2.x, &segments[i].p2.y)
		segments[i].dist = dist(segments[i].p1, segments[i].p2)
	}

	perm := make([]int, n)
	for i := 0; i < n; i++ {
		perm[i] = i
	}

	minTotalTime := math.MaxFloat64

	var generatePermutations func(int)
	generatePermutations = func(k int) {
		if k == n {
			for i := 0; i < (1 << n); i++ {
				currentTime := 0.0
				currentPos := Point{0, 0}
				for j := 0; j < n; j++ {
					idx := perm[j]
					var start, end Point
					if (i>>j)&1 == 0 {
						start = segments[idx].p1
						end = segments[idx].p2
					} else {
						start = segments[idx].p2
						end = segments[idx].p1
					}
					currentTime += dist(currentPos, start) / s
					currentTime += segments[idx].dist / t
					currentPos = end
				}
				if currentTime < minTotalTime {
					minTotalTime = currentTime
				}
			}
			return
		}

		for i := k; i < n; i++ {
			perm[k], perm[i] = perm[i], perm[k]
			generatePermutations(k + 1)
			perm[k], perm[i] = perm[i], perm[k]
		}
	}

	generatePermutations(0)
	fmt.Printf("%.12f\n", minTotalTime)
}

import java.util.*;

public class Main {
    static int N;
    static double S, T;
    static double[][] segments;
    static double minTime = Double.MAX_VALUE;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;
        N = sc.nextInt();
        S = sc.nextDouble();
        T = sc.nextDouble();
        segments = new double[N][4];
        for (int i = 0; i < N; i++) {
            segments[i][0] = sc.nextDouble();
            segments[i][1] = sc.nextDouble();
            segments[i][2] = sc.nextDouble();
            segments[i][3] = sc.nextDouble();
        }

        int[] p = new int[N];
        for (int i = 0; i < N; i++) p[i] = i;
        permute(p, 0);

        System.out.printf("%.12f\n", minTime);
    }

    static void permute(int[] p, int k) {
        if (k == N) {
            solve(p);
            return;
        }
        for (int i = k; i < N; i++) {
            int temp = p[k];
            p[k] = p[i];
            p[i] = temp;
            permute(p, k + 1);
            temp = p[k];
            p[k] = p[i];
            p[i] = temp;
        }
    }

    static void solve(int[] p) {
        for (int i = 0; i < (1 << N); i++) {
            double currentTime = 0;
            double curX = 0;
            double curY = 0;
            for (int j = 0; j < N; j++) {
                int idx = p[j];
                double x1, y1, x2, y2;
                if (((i >> j) & 1) == 0) {
                    x1 = segments[idx][0];
                    y1 = segments[idx][1];
                    x2 = segments[idx][2];
                    y2 = segments[idx][3];
                } else {
                    x1 = segments[idx][2];
                    y1 = segments[idx][3];
                    x2 = segments[idx][0];
                    y2 = segments[idx][1];
                }
                double distToStart = Math.sqrt(Math.pow(x1 - curX, 2) + Math.pow(y1 - curY, 2));
                double distSketch = Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2));
                currentTime += distToStart / S;
                currentTime += distSketch / T;
                curX = x2;
                curY = y2;
            }
            if (currentTime < minTime) {
                minTime = currentTime;
            }
        }
    }
}

using namespace std;

long long minCostForCapacity(int C, int D, int E, int F, long long target) {
    if (target == 0) return 0;

    long long minCost = LLONG_MAX;


    long long unitsR = (target + C - 1) / C;
    if (unitsR <= 1e7) {
        minCost = min(minCost, unitsR * D);
    }


    long long unitsM = (target + E - 1) / E;
    if (unitsM <= 1e7) {
        minCost = min(minCost, unitsM * F);
    }


    long long maxUnitsR = min(1000000LL, target / C + 1);
    for (long long r = 0; r <= maxUnitsR; r++) {
        long long remaining = target - r * C;
        if (remaining <= 0) {
            minCost = min(minCost, r * (long long)D);
        } else {
            long long unitsM = (remaining + E - 1) / E;
            if (unitsM <= 1e7) {
                minCost = min(minCost, r * (long long)D + unitsM * (long long)F);
            }
        }
    }

    long long maxUnitsM = min(1000000LL, target / E + 1);
    for (long long m = 0; m <= maxUnitsM; m++) {
        long long remaining = target - m * E;
        if (remaining <= 0) {
            minCost = min(minCost, m * (long long)F);
        } else {
            long long unitsR = (remaining + C - 1) / C;
            if (unitsR <= 1e7) {
                minCost = min(minCost, m * (long long)F + unitsR * (long long)D);
            }
        }
    }

    return minCost;
