	for i := 1; i <= n; i++ {
		scanner.Scan()
		x, _ := strconv.ParseFloat(scanner.Text(), 64)
		scanner.Scan()
		y, _ := strconv.ParseFloat(scanner.Text(), 64)
		points[i] = [2]float64{x, y}
	}
	points[n+1] = [2]float64{0, 0}

	var totalExpense float64 = 0
	for i := 0; i <= n; i++ {
		dx := points[i+1][0] - points[i][0]
		dy := points[i+1][1] - points[i][1]
		totalExpense += math.Sqrt(dx*dx + dy*dy)
	}

	fmt.Printf("%.20f\n", totalExpense)
}

