func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var M int
	fmt.Fscanf(reader, "%d\n", &M)

	grid := make([][]byte, M)
	for i := 0; i < M; i++ {
		line, _ := reader.ReadString('\n')
		grid[i] = []byte(line[:M])
	}

	result := make([][]byte, M)
	for i := 0; i < M; i++ {
		result[i] = make([]byte, M)
	}

	for r := 0; r < M; r++ {
		for c := 0; c < M; c++ {
			u := r + 1
			v := c + 1

			distTop := u
			distBottom := M + 1 - u
			distLeft := v
			distRight := M + 1 - v

			minDist := distTop
			if distBottom < minDist {
				minDist = distBottom
			}
			if distLeft < minDist {
				minDist = distLeft
			}
			if distRight < minDist {
				minDist = distRight
			}

			rotations := (M/2 - minDist + 1) % 4

			currU, currV := u, v
			for k := 0; k < rotations; k++ {
				nextU, nextV := currV, M+1-currU
				currU, currV = nextU, nextV
			}
			result[currU-1][currV-1] = grid[u-1][v-1]
		}
	}

	for i := 0; i < M; i++ {
		writer.Write(result[i])
		writer.WriteByte('\n')
	}
}

