        for (int i = 0; i < M; i++) {
            for (int j = 0; j < M; j++) {
                int layer = getLayer(i, j, M);
                int rotations = (M / 2) - layer;
                int r = i, c = j;
                for (int k = 0; k < (rotations % 4); k++) {
                    int nextR = c;
                    int nextC = M - 1 - r;
                    r = nextR;
                    c = nextC;
                }
                result[r][c] = grid[i][j];
            }
        }

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < M; i++) {
            sb.append(result[i]).append('\n');
        }
        System.out.print(sb);
    }

    private static int getLayer(int r, int c, int M) {
        int distTop = r;
        int distBottom = M - 1 - r;
        int distLeft = c;
        int distRight = M - 1 - c;
        return Math.min(Math.min(distTop, distBottom), Math.min(distLeft, distRight));
    }
