type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(*Item))
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func dijkstra(graph [][]Edge, start, end int) int {
	n := len(graph)
	dist := make([]int, n)
	for i := range dist {
		dist[i] = 1e9 + 1
	}
	dist[start] = 0

	pq := &PriorityQueue{}
	heap.Init(pq)
	heap.Push(pq, &Item{node: start, cost: 0})

	for pq.Len() > 0 {
		current := heap.Pop(pq).(*Item)

		if current.node == end {
			return current.cost
		}

		if current.cost > dist[current.node] {
			continue
		}

		for _, edge := range graph[current.node] {
			newCost := current.cost
			if edge.cost > newCost {
				newCost = edge.cost
			}

			if newCost < dist[edge.to] {
				dist[edge.to] = newCost
				heap.Push(pq, &Item{node: edge.to, cost: newCost})
			}
		}
	}

	if dist[end] == 1e9+1 {
		return -1
	}
	return dist[end]
}

