    cin >> N >> M >> Q;

    vector<Edge> edges(M + 1);
    for (int i = 1; i <= M; ++i) {
        cin >> edges[i].u >> edges[i].v >> edges[i].w;
        edges[i].active = true;
    }

    vector<Query> queries(Q);
    for (int i = 0; i < Q; ++i) {
        cin >> queries[i].type;
        if (queries[i].type == 1) {
            cin >> queries[i].a;
            edges[queries[i].a].active = false;
        } else {
            cin >> queries[i].a >> queries[i].b;
        }
    }

    vector<vector<long long>> dist(N + 1, vector<long long>(N + 1, INF));
    for (int i = 1; i <= N; ++i) dist[i][i] = 0;

    for (int i = 1; i <= M; ++i) {
        if (edges[i].active) {
            int u = edges[i].u;
            int v = edges[i].v;
            long long w = edges[i].w;
            dist[u][v] = min(dist[u][v], w);
            dist[v][u] = min(dist[v][u], w);
        }
    }

    auto run_floyd = [&]() {
        for (int k = 1; k <= N; ++k) {
            for (int i = 1; i <= N; ++i) {
                if (dist[i][k] == INF) continue;
                for (int j = 1; j <= N; ++j) {
                    if (dist[k][j] < INF) {
                        dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]);
                    }
                }
            }
        }
    };

    run_floyd();

    vector<long long> results;
    for (int q = Q - 1; q >= 0; --q) {
        if (queries[q].type == 2) {
            long long res = dist[queries[q].a][queries[q].b];
            results.push_back(res >= INF ? -1 : res);
        } else {
            int idx = queries[q].a;
            int u = edges[idx].u;
            int v = edges[idx].v;
