func dijkstra(n int, adj [][]Edge, start int) []int64 {
	dist := make([]int64, n+1)
	for i := range dist {
		dist[i] = -1
	}
	pq := &PriorityQueue{}
	heap.Init(pq)
	dist[start] = 0
	heap.Push(pq, Item{node: start, dist: 0})
	for pq.Len() > 0 {
		curr := heap.Pop(pq).(Item)
		if curr.dist > dist[curr.node] && dist[curr.node] != -1 {
			continue
		}
