			if dist[e.to] == -1 || dist[e.to] > curr.dist+int64(e.weight) {
				dist[e.to] = curr.dist + int64(e.weight)
				heap.Push(pq, Item{node: e.to, dist: dist[e.to]})
			}
		}
	}
	return dist
