int minDistance(int from, int to, int n, int blocked) {
    if (from == to) return 0;


    int clockwise = (to - from + n) % n;

    int counterclockwise = (from - to + n) % n;


    bool clockwiseBlocked = false;
    int curr = from;
    for (int i = 0; i < clockwise; i++) {
        curr = curr % n + 1;
        if (curr == blocked) {
            clockwiseBlocked = true;
            break;
        }
    }


    bool counterclockwiseBlocked = false;
    curr = from;
    for (int i = 0; i < counterclockwise; i++) {
        curr = (curr - 2 + n) % n + 1;
        if (curr == blocked) {
            counterclockwiseBlocked = true;
            break;
        }
    }


    if (clockwiseBlocked && counterclockwiseBlocked) {
        return -1;
    } else if (clockwiseBlocked) {
        return counterclockwise;
    } else if (counterclockwiseBlocked) {
        return clockwise;
    } else {
        return min(clockwise, counterclockwise);
    }
}

