type Tool struct {
	D, E int
}

type MinHeap []int

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x interface{}) {
	*h = append(*h, x.(int))
}
func (h *MinHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve() {
	reader := bufio.NewReader(os.Stdin)
	var T int
	fmt.Fscan(reader, &T)

	for t := 0; t < T; t++ {
		var N, K int
		fmt.Fscan(reader, &N, &K)

		tools := make([]Tool, N)
		for i := 0; i < N; i++ {
			fmt.Fscan(reader, &tools[i].D)
		}
		for i := 0; i < N; i++ {
			fmt.Fscan(reader, &tools[i].E)
		}

		sort.Slice(tools, func(i, j int) bool {
			return tools[i].D < tools[j].D
		})

		h := &MinHeap{}
		heap.Init(h)
		var currentSum int64 = 0
		var minVal int64 = -1

		for i := 0; i < N; i++ {
			heap.Push(h, tools[i].E)
			currentSum += int64(tools[i].E)

			if h.Len() > K {
				removed := heap.Pop(h).(int)
				currentSum -= int64(removed)
			}

			if h.Len() == K {
				val := int64(tools[i].D) * currentSum
				if minVal == -1 || val < minVal {
					minVal = val
				}
			}
		}
		fmt.Println(minVal)
	}
}

