typedef long long ll;

const int MOD = 998244353;

ll power(ll base, ll exp) {
    ll res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

ll modInverse(ll n) {
    return power(n, MOD - 2);
}

struct Node {
    ll a, sz;
    int id;
    bool operator<(const Node& other) const {
        return a * other.sz < other.a * sz;
    }
};

void solve() {
    int N;
    if (!(cin >> N)) return;
    vector<int> p(N + 1);
    vector<ll> a(N + 1);
    ll sum_a = 0;
    for (int i = 1; i <= N; ++i) cin >> p[i];
    for (int i = 1; i <= N; ++i) {
        cin >> a[i];
        sum_a += a[i];
    }

    vector<ll> cur_a(N + 1), cur_sz(N + 1);
    vector<int> parent(N + 1), dsu(N + 1);
    for (int i = 0; i <= N; ++i) {
        cur_a[i] = (i == 0 ? 0 : a[i]);
        cur_sz[i] = 1;
        parent[i] = p[i];
        dsu[i] = i;
    }

    auto find_dsu = [&](auto self, int i) -> int {
        return dsu[i] == i ? i : dsu[i] = self(self, dsu[i]);
    };

    priority_queue<Node> pq;
    vector<bool> in_pq(N + 1, false);
    for (int i = 1; i <= N; ++i) {
        pq.push({cur_a[i], cur_sz[i], i});
        in_pq[i] = true;
    }

    ll ans = 0;
    vector<int> next_node(N + 1, -1);
    vector<int> tail(N + 1);
    for (int i = 0; i <= N; ++i) tail[i] = i;

    while (!pq.empty()) {
        Node top = pq.top();
        pq.pop();
        int u = top.id;
        if (!in_pq[u] || cur_a[u] != top.a || cur_sz[u] != top.sz) continue;

        int root_p = find_dsu(find_dsu, parent[u]);
        ans = (ans + (cur_a[u] % MOD) * (cur_sz[root_p] % MOD)) % MOD;

        next_node[tail[root_p]] = u;
        tail[root_p] = tail[u];
        cur_a[root_p] += cur_a[u];
        cur_sz[root_p] += cur_sz[u];
        dsu[u] = root_p;
        in_pq[u] = false;

        if (root_p != 0) {
            pq.push({cur_a[root_p], cur_sz[root_p], root_p});
            in_pq[root_p] = true;
        }
    }

    ans = (ans + sum_a) % MOD;
    ans = (ans * modInverse(sum_a % MOD)) % MOD;
    cout << ans << "\n";
}

