    public static void main(String[] args) throws IOException {
        FastReader fr = new FastReader(System.in);
        int T = fr.nextInt();
        while (T-- > 0) {
            int N = fr.nextInt();
            int[] p = new int[N + 1];
            for (int i = 1; i <= N; i++) {
                p[i] = fr.nextInt();
            }
            long[] a = new long[N + 1];
            long totalA = 0;
            for (int i = 1; i <= N; i++) {
                a[i] = fr.nextInt();
                totalA += a[i];
            }

            long[] subtreeSum = new long[N + 1];
            for (int i = N; i >= 1; i--) {
                subtreeSum[i] += a[i];
                if (p[i] != 0) {
                    subtreeSum[p[i]] += subtreeSum[i];
                }
            }

            long totalExpected = 0;
            long invTotalA = power(totalA % MOD, MOD - 2);

            for (int i = 1; i <= N; i++) {
                long prob = (subtreeSum[i] % MOD * invTotalA) % MOD;
                totalExpected = (totalExpected + prob) % MOD;
            }

            System.out.println((totalExpected + 1) % MOD);
        }
    }

    static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean hasNextByte() {
            if (pointer < bufferLength) return true;
            pointer = 0;
            try {
                bufferLength = in.read(buffer);
            } catch (IOException e) {
                return false;
            }
            return bufferLength > 0;
        }

        private int readByte() {
            return hasNextByte() ? buffer[pointer++] : -1;
        }

        public int nextInt() {
            int b = readByte();
            while (b != -1 && b <= 32) b = readByte();
            if (b == -1) return 0;
            int res = 0;
            while (b > 32) {
                res = res * 10 + (b - '0');
                b = readByte();
            }
            return res;
        }
    }
