            if (b < minB[a]) {
                minB[a] = b;
            }
        }

        int[] f = new int[C + 1];
        int currentMin = C + 1;
        for (int x = C; x >= 1; x--) {
            if (minB[x] < currentMin) {
                currentMin = minB[x];
            }
            f[x] = currentMin;
        }

        long count = 0;
        for (int x = 1; x <= C; x++) {
            int limit = f[x];
            if (limit > x) {
                count += (limit - x);
            }
        }

        System.out.println(count);
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean hasNextByte() {
            if (pointer < bufferLength) return true;
            pointer = 0;
            try {
                bufferLength = in.read(buffer);
            } catch (IOException e) {
                return false;
            }
            return bufferLength > 0;
        }

        private int readByte() {
            return hasNextByte() ? buffer[pointer++] : -1;
        }

        public int nextInt() {
            int n = 0;
            int b = readByte();
            while (b != -1 && (b < '0' || b > '9')) b = readByte();
            if (b == -1) return -1;
            while (b >= '0' && b <= '9') {
                n = n * 10 + (b - '0');
                b = readByte();
            }
            return n;
        }
    }
}

