        for (int k = 0; k < N; k++) {
            String current = D[k];
            int n = current.length();
            int ans = n;

            TrieNode curr = root;
            for (int i = 0; i < n; i++) {
                if (curr.minDepth != Integer.MAX_VALUE) {
                    ans = Math.min(ans, (n - i) + curr.minDepth);
                }
                int charIdx = current.charAt(i) - 'a';
                if (curr.children[charIdx] == null) {
                    break;
                }
                curr = curr.children[charIdx];
                if (i == n - 1) {
                    if (curr.minDepth != Integer.MAX_VALUE) {
                        ans = Math.min(ans, curr.minDepth);
                    }
                }
            }

            sb.append(ans).append("\n");

            curr = root;
            for (int i = 0; i < n; i++) {
                int charIdx = current.charAt(i) - 'a';
                if (curr.children[charIdx] == null) {
                    curr.children[charIdx] = new TrieNode();
                }
                curr = curr.children[charIdx];
                curr.minDepth = Math.min(curr.minDepth, n - (i + 1));
            }
        }
        System.out.print(sb.toString());
    }
}

