def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    docs = input_data[1:]

    class TrieNode:
        __slots__ = ['children', 'min_depth']
        def __init__(self):
            self.children = {}
            self.min_depth = float('inf')

    root = TrieNode()
    results = []

    for k in range(n):
        s = docs[k]
        l = len(s)

        if k == 0:
            results.append(l)
        else:
            ans = l
            curr = root
            for i, char in enumerate(s):
                if char in curr.children:
                    curr = curr.children[char]
                    ans = min(ans, (l - (i + 1)) + curr.min_depth)
                else:
                    break
            results.append(ans)

        curr = root
        for i, char in enumerate(s):
            if char not in curr.children:
                curr.children[char] = TrieNode()
            curr = curr.children[char]
            curr.min_depth = min(curr.min_depth, l - (i + 1))

    sys.stdout.write('\n'.join(map(str, results)) + '\n')

