func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	var k int64
	fmt.Fscan(reader, &n, &k)

	b := make([]int64, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &b[i])
	}

	prefixSums := make([]int64, n+1)
	for i := 0; i < n; i++ {
		prefixSums[i+1] = (prefixSums[i] + b[i]) % k
	}

	count := make([]int64, k)
	var totalSumOfPrefix int64 = 0
	var result int64 = 0

	bit := make([]int64, k+1)
	update := func(idx int64, val int64) {
		idx++
		for idx <= k {
			bit[idx] += val
			idx += idx & -idx
		}
	}
	query := func(idx int64) int64 {
		idx++
		var s int64 = 0
		for idx > 0 {
			s += bit[idx]
			idx -= idx & -idx
		}
		return s
	}

	for j := 1; j <= n; j++ {
		pj := prefixSums[j]
		update(prefixSums[j-1], 1)
		totalSumOfPrefix += prefixSums[j-1]

		c := int64(j)
		smallerOrEqualCount := query(pj)

		term1 := c * pj
		term2 := totalSumOfPrefix
		term3 := (c - smallerOrEqualCount) * k

		result += term1 - term2 + term3
	}

	fmt.Println(result)
}

