        long[] B = new long[N];
        for (int i = 0; i < N; i++) {
            B[i] = fr.nextLong();
        }

        long[] P = new long[N + 1];
        for (int i = 0; i < N; i++) {
            P[i + 1] = (P[i] + B[i]) % K;
        }

        long totalSum = 0;
        long sumP = 0;
        long[] count = new long[(int) K];

        for (int y = 1; y <= N; y++) {
            sumP += P[y];
            count[(int) P[y]]++;
        }

        long currentLessCount = 0;
        for (int x = 0; x < N; x++) {
            totalSum += sumP - (long) (N - x) * P[x];

            currentLessCount += count[(int) P[x]];
            totalSum += (long) (N - x - currentLessCount) * K;

            sumP -= P[x + 1];
            count[(int) P[x + 1]]--;
            currentLessCount -= count[(int) P[x]];
        }

        System.out.println(totalSum);
    }
}

