func findPath(adj [][]int, start, end, N int) []int {
	visited := make([]bool, N+1)
	parent := make([]int, N+1)
	queue := []int{start}
	visited[start] = true
	parent[start] = -1

	for len(queue) > 0 {
		node := queue[0]
		queue = queue[1:]

		if node == end {

			path := []int{}
			current := end
			for current != -1 {
				path = append([]int{current}, path...)
				current = parent[current]
			}
			return path
		}

		for _, neighbor := range adj[node] {
			if !visited[neighbor] {
				visited[neighbor] = true
				parent[neighbor] = node
				queue = append(queue, neighbor)
			}
		}
	}

	return nil
}

