    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int N = Integer.parseInt(line.trim());
        adj = new ArrayList[N + 1];
        degree = new int[N + 1];
        for (int i = 1; i <= N; i++) adj[i] = new ArrayList<>();
        for (int i = 0; i < N - 1; i++) {
            String[] parts = br.readLine().split(" ");
            int u = Integer.parseInt(parts[0]);
            int v = Integer.parseInt(parts[1]);
            adj[u].add(v);
            adj[v].add(u);
            degree[u]++;
            degree[v]++;
        }

        List<Integer> targets = new ArrayList<>();
        for (int i = 1; i <= N; i++) {
            if (degree[i] == 1 || degree[i] == 2) {
                targets.add(i);
            } else if (degree[i] >= 4) {
                System.out.println(0);
                return;
            }
        }

        if (targets.isEmpty()) {
            System.out.println(0);
            return;
        }

        long count = 0;
        int m = targets.size();
        for (int i = 0; i < m; i++) {
            int u = targets.get(i);
            int[] dist = new int[N + 1];
            Arrays.fill(dist, -1);
            Queue<Integer> q = new LinkedList<>();
            q.add(u);
            dist[u] = 0;
            while (!q.isEmpty()) {
                int curr = q.poll();
                for (int v : adj[curr]) {
                    if (dist[v] == -1) {
                        dist[v] = dist[curr] + 1;
                        q.add(v);
                    }
                }
            }

            for (int j = i + 1; j < m; j++) {
                int v = targets.get(j);
                if (dist[v] <= 1) continue;
                if (degree[u] + 1 != 3 || degree[v] + 1 != 3) continue;

                boolean ok = true;
                int curr = v;
                while (curr != u) {
                    int next = -1;
                    for (int neighbor : adj[curr]) {
                        if (dist[neighbor] == dist[curr] - 1) {
                            next = neighbor;
                            break;
                        }
                    }
                    if (next != u) {
                        if (degree[next] != 3) {
                            ok = false;
                            break;
                        }
                    }
                    curr = next;
                }
                if (ok) count++;
            }
        }
        System.out.println(count);
    }
}

