typedef long long ll;

ll power(ll base, ll exp, ll mod) {
    ll res = 1;
    base %= mod;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % mod;
        base = (base * base) % mod;
        exp /= 2;
    }
    return res;
}

ll modInverse(ll n, ll mod) {
    return power(n, mod - 2, mod);
}

ll determinant(vector<vector<ll>>& mat, int n, ll mod) {
    ll det = 1;
    for (int i = 0; i < n; ++i) {
        int pivot = i;
        while (pivot < n && mat[pivot][i] == 0) pivot++;
        if (pivot == n) return 0;
        swap(mat[i], mat[pivot]);
        if (pivot != i) det = (mod - det) % mod;
        det = (det * mat[i][i]) % mod;
        ll inv = modInverse(mat[i][i], mod);
        for (int j = i + 1; j < n; ++j) {
            ll factor = (mat[j][i] * inv) % mod;
            for (int k = i; k < n; ++k) {
                mat[j][k] = (mat[j][k] - factor * mat[i][k] % mod + mod) % mod;
            }
        }
    }
    return det;
}

