func power(a, b int64) int64 {
	res := int64(1)
	a %= K
	for b > 0 {
		if b%2 == 1 {
			res = (res * a) % K
		}
		a = (a * a) % K
		b /= 2
	}
	return res
}

func inverse(n int64) int64 {
	return power(n, K-2)
}

func precompute(n int) {
	fact = make([]int64, n+1)
	inv = make([]int64, n+1)
	fact[0] = 1
	for i := 1; i <= n; i++ {
		fact[i] = (fact[i-1] * int64(i)) % K
	}
	inv[n] = inverse(fact[n])
	for i := n - 1; i >= 0; i-- {
		inv[i] = (inv[i+1] * int64(i+1)) % K
	}
}

func det(matrix [][]int64) int64 {
	n := len(matrix)
	res := int64(1)
	for i := 0; i < n; i++ {
		pivot := i
		for j := i + 1; j < n; j++ {
			if matrix[j][i] != 0 {
				pivot = j
				break
			}
		}
		if matrix[pivot][i] == 0 {
			return 0
		}
		if pivot != i {
			matrix[i], matrix[pivot] = matrix[pivot], matrix[i]
			res = (K - res) % K
		}
		res = (res * matrix[i][i]) % K
		invPivot := inverse(matrix[i][i])
		for j := i + 1; j < n; j++ {
			mult := (matrix[j][i] * invPivot) % K
			for k := i; k < n; k++ {
				matrix[j][k] = (matrix[j][k] - mult*matrix[i][k]%K + K) % K
			}
		}
	}
	return res
}

func hookFormula(lambda []int) int64 {
	n := 0
	for _, x := range lambda {
		n += x
	}
	m := len(lambda)
	matrix := make([][]int64, m)
	for i := 0; i < m; i++ {
		matrix[i] = make([]int64, m)
		for j := 0; j < m; j++ {
			val := lambda[i] - i + j
			if val >= 0 {
				matrix[i][j] = inv[val]
			} else {
				matrix[i][j] = 0
			}
		}
	}
	d := det(matrix)
	return (d * fact[n]) % K
}

func solve() {
	fmt.Scan(&C, &D, &K)
	N := C*D - 1
	precompute(N + 10)
	total := int64(0)

	for i := 1; i <= D; i++ {
		for j := 1; j <= C; j++ {
			lambda := make([]int, D)
			for r := 0; r < D; r++ {
				lambda[r] = C
			}
			lambda[i-1]--

			if i < D && lambda[i-1] < lambda[i] {
				continue
			}

			f := hookFormula(lambda)
			term := (f * f) % K
			total = (total + term) % K
		}
	}

	fmt.Println(total)
}

