struct BigInt {
    vector<long long> digits;
    static const long long BASE = 1e15;

    BigInt(long long v = 0) {
        if (v == 0) digits.push_back(0);
        while (v > 0) {
            digits.push_back(v % BASE);
            v /= BASE;
        }
    }

    void add(const BigInt& other) {
        int n = max(digits.size(), other.digits.size());
        long long carry = 0;
        for (int i = 0; i < n || carry; ++i) {
            if (i == digits.size()) digits.push_back(0);
            long long cur = digits[i] + carry + (i < other.digits.size() ? other.digits[i] : 0);
            digits[i] = cur % BASE;
            carry = cur / BASE;
        }
    }

    void multiply(int v) {
        long long carry = 0;
        for (int i = 0; i < digits.size() || carry; ++i) {
            if (i == digits.size()) digits.push_back(0);
            long long cur = digits[i] * v + carry;
            digits[i] = cur % BASE;
            carry = cur / BASE;
        }
        while (digits.size() > 1 && digits.back() == 0) digits.pop_back();
    }

    string to_string() const {
        if (digits.empty()) return "0";
        string res = std::to_string(digits.back());
        for (int i = (int)digits.size() - 2; i >= 0; --i) {
            string s = std::to_string(digits[i]);
            res += string(15 - s.size(), '0') + s;
        }
        return res;
    }
};

