type Query struct {
	l, r, id int
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n, q int
	fmt.Fscan(reader, &n, &q)

	h := make([]int, n+1)
	for i := 1; i <= n; i++ {
		fmt.Fscan(reader, &h[i])
	}

	queries := make([]Query, q)
	queriesByR := make([][]Query, n+1)
	for i := 0; i < q; i++ {
		fmt.Fscan(reader, &queries[i].l, &queries[i].r)
		queries[i].id = i
		queriesByR[queries[i].r] = append(queriesByR[queries[i].r], queries[i])
	}

	nextGreater := make([]int, n+1)
	stack := []int{}
	for i := n; i >= 1; i-- {
		for len(stack) > 0 && h[stack[len(stack)-1]] < h[i] {
			stack = stack[:len(stack)-1]
		}
		if len(stack) == 0 {
			nextGreater[i] = n + 1
		} else {
			nextGreater[i] = stack[len(stack)-1]
		}
		stack = append(stack, i)
	}

	tree := make([]int, n+2)
	update := func(idx int, val int) {
		for idx <= n+1 {
			tree[idx] += val
			idx += idx & -idx
		}
	}
	queryBit := func(idx int) int {
		res := 0
		for idx > 0 {
			res += tree[idx]
			idx -= idx & -idx
		}
		return res
	}

	ans := make([]int, q)
	activeSets := make([][]int, n+2)

	for r := n; r >= 1; r-- {
		curr := nextGreater[r]
		for curr <= n {
			update(curr, 1)
			activeSets[r] = append(activeSets[r], curr)
			curr = nextGreater[curr]
		}

		for _, qry := range queriesByR[r] {
			l := qry.l
			count := 0
			currL := nextGreater[l]
			for currL <= n {
				if currL > r {
					count = queryBit(n) - queryBit(currL-1)
					break
				}
				currL = nextGreater[currL]
			}
			ans[qry.id] = count
		}

		for _, idx := range activeSets[r] {
			update(idx, -1)
		}
	}

	for i := 0; i < q; i++ {
		fmt.Fprintln(writer, ans[i])
	}
}

