    queries = []
    ptr = N + 2
    for i in range(Q):
        l = int(input_data[ptr]) - 1
        r = int(input_data[ptr+1]) - 1
        queries.append((l, r, i))
        ptr += 2

    next_greater = [N] * N
    stack = []
    for i in range(N):
        while stack and H[stack[-1]] < H[i]:
            next_greater[stack.pop()] = i
        stack.append(i)

    LOG = 18
    up = [[N] * LOG for _ in range(N + 1)]
    for i in range(N):
        up[i][0] = next_greater[i]
    for j in range(1, LOG):
        for i in range(N + 1):
            if up[i][j-1] != N:
                up[i][j] = up[up[i][j-1]][j-1]
            else:
                up[i][j] = N

    def get_first_visible(start_idx, min_h):
        curr = start_idx
        if H[curr] > min_h:
            return curr
        for j in range(LOG - 1, -1, -1):
            nxt = up[curr][j]
            if nxt < N and H[nxt] < min_h:
                curr = nxt
        return up[curr][0]

    query_buckets = [[] for _ in range(N)]
    for i in range(Q):
        l, r, q_idx = queries[i]
        first_v = get_first_visible(r + 1, H[l]) if r + 1 < N else N
        if first_v < N:
            query_buckets[first_v].append((r, q_idx))

    ans = [0] * Q
    bit = [0] * (N + 1)

    def bit_add(idx, val):
        idx += 1
        while idx <= N:
            bit[idx] += val
            idx += idx & (-idx)

    def bit_query(idx):
        idx += 1
        s = 0
        while idx > 0:
            s += bit[idx]
            idx -= idx & (-idx)
        return s

    v_stack = []
    for j in range(N - 1, -1, -1):
        while v_stack and H[v_stack[-1]] < H[j]:
            bit_add(v_stack.pop(), -1)
        v_stack.append(j)
        bit_add(j, 1)

        for r_val, q_idx in query_buckets[j]:
            ans[q_idx] = bit_query(N - 1) - bit_query(r_val)

    sys.stdout.write('\n'.join(map(str, ans)) + '\n')

