    int c = question_marks[idx].second;

    for (char ch : {'A', 'B', 'C'}) {
        if (isValid(r, c, ch)) {
            grid[r][c] = ch;
            backtrack(idx + 1);
            grid[r][c] = '?';
        }
    }
}

