			}
		}
	}

	if !isValidFixed() {
		fmt.Println(0)
		return
	}

	result := backtrack(0)
	fmt.Println(result)
}

func isValidFixed() bool {
	for i := 0; i < R; i++ {
		for j := 0; j < C; j++ {
			if matrix[i][j] != '?' {
				if i > 0 && matrix[i-1][j] != '?' && matrix[i-1][j] == matrix[i][j] {
					return false
				}
				if j > 0 && matrix[i][j-1] != '?' && matrix[i][j-1] == matrix[i][j] {
					return false
				}
			}
		}
	}
	return true
}

func backtrack(pos int) int {
	if pos == len(questionMarks) {
		return 1
	}

	r := questionMarks[pos][0]
	c := questionMarks[pos][1]

	count := 0
	for _, char := range []byte{'A', 'B', 'C'} {
		matrix[r][c] = char

		valid := true
		if r > 0 && matrix[r-1][c] == char {
			valid = false
		}
		if r < R-1 && matrix[r+1][c] != '?' && matrix[r+1][c] == char {
			valid = false
		}
		if c > 0 && matrix[r][c-1] == char {
			valid = false
		}
		if c < C-1 && matrix[r][c+1] != '?' && matrix[r][c+1] == char {
			valid = false
		}

		if valid {
			count = (count + backtrack(pos+1)) % MOD
		}
	}

	matrix[r][c] = '?'
	return count
}

