        for (int r = 0; r < R; ++r) {
            for (int c = 0; c < C; ++c) {
                newM[c][r] = M[r][c];
            }
        }
        swap(R, C);
        M = newM;
    }

    int MOD = 998244353;
    int num_states = 1;
    for (int i = 0; i < C; ++i) num_states *= 3;

    vector<int> dp(num_states, 0);
    dp[0] = 1;

    vector<int> powers(C + 1);
    powers[0] = 1;
    for (int i = 1; i <= C; ++i) powers[i] = powers[i - 1] * 3;

    for (int r = 0; r < R; ++r) {
        for (int c = 0; c < C; ++c) {
            vector<int> next_dp(num_states, 0);
            for (int state = 0; state < num_states; ++state) {
                if (dp[state] == 0) continue;

                int up = (state / powers[c]) % 3;
                int left = (c == 0) ? -1 : (state / powers[c - 1]) % 3;

                for (int val = 0; val < 3; ++val) {
                    char char_val = (char)('A' + val);
                    if (M[r][c] != '?' && M[r][c] != char_val) continue;
                    if (val == up) continue;
                    if (val == left) continue;

                    int next_state = state - (up * powers[c]) + (val * powers[c]);
                    next_dp[next_state] = (next_dp[next_state] + dp[state]) % MOD;
                }
            }
            dp = move(next_dp);
        }
    }

    long long ans = 0;
    for (int val : dp) ans = (ans + val) % MOD;
