		for i := 0; i < R; i++ {
			grid[i] = string(newGrid[i])
		}
	}

	limit := 1
	for i := 0; i < C; i++ {
		limit *= 3
	}

	dp := make([]int, limit)
	dp[0] = 1

	charToVal := map[byte]int{'A': 0, 'B': 1, 'C': 2, '?': -1}
	pow3 := make([]int, C+1)
	pow3[0] = 1
	for i := 1; i <= C; i++ {
		pow3[i] = pow3[i-1] * 3
	}

	for r := 0; r < R; r++ {
		for c := 0; c < C; c++ {
			newDp := make([]int, limit)
			targetChar := charToVal[grid[r][c]]

			for mask := 0; mask < limit; mask++ {
				if dp[mask] == 0 {
					continue
				}

				upVal := (mask / pow3[c]) % 3
				leftVal := -1
				if c > 0 {
					leftVal = (mask / pow3[c-1]) % 3
				}

				for val := 0; val < 3; val++ {
					if targetChar != -1 && targetChar != val {
						continue
					}
					if r > 0 && val == upVal {
						continue
					}
					if c > 0 && val == leftVal {
						continue
					}

					newMask := mask - (upVal * pow3[c]) + (val * pow3[c])
					newDp[newMask] = (newDp[newMask] + dp[mask]) % MOD
				}
			}
			dp = newDp
		}
	}

	ans := 0
	for _, v := range dp {
		ans = (ans + v) % MOD
	}
	fmt.Println(ans)
