func solve(M string, K int64) byte {
	n := int64(len(M))


	pos := K - 1
	flips := 0


	for pos >= n {

		currentLen := n


		power := int64(0)
		tempLen := n
		for tempLen <= pos {
			tempLen *= 2
			power++
		}



		halfLen := tempLen / 2

		if pos >= halfLen {

