public class Main {

    static String initialString;

    static char solve(long k) {
        return solveRecursive(k, initialString.length(), false);
    }

    static char solveRecursive(long k, long currentLength, boolean flipped) {
        if (currentLength == initialString.length()) {
            char c = initialString.charAt((int)(k - 1));
            if (flipped) {
                if (Character.isUpperCase(c)) {
                    return Character.toLowerCase(c);
                } else {
                    return Character.toUpperCase(c);
                }
            }
            return c;
        }

        long halfLength = currentLength / 2;

        if (k <= halfLength) {
            return solveRecursive(k, halfLength, flipped);
        } else {
            return solveRecursive(k - halfLength, halfLength, !flipped);
        }
    }

