public class Main {
    static class FastReader {
        BufferedReader br;
        StringTokenizer st;

        public FastReader() {
            br = new BufferedReader(new InputStreamReader(System.in));
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }
    }

    static class Segment implements Comparable<Segment> {
        int l, r, c;

        Segment(int l, int r, int c) {
            this.l = l;
            this.r = r;
            this.c = c;
        }

        @Override
        public int compareTo(Segment other) {
            return Integer.compare(this.l, other.l);
        }
    }

    public static void main(String[] args) {
        FastReader sc = new FastReader();
        PrintWriter out = new PrintWriter(System.out);

        int N = sc.nextInt();
        int Q = sc.nextInt();

        TreeSet<Segment> set = new TreeSet<>();
        int[] counts = new int[N + 1];
        for (int i = 1; i <= N; i++) {
            set.add(new Segment(i, i, i));
            counts[i] = 1;
        }

        for (int q = 0; q < Q; q++) {
            int type = sc.nextInt();
            if (type == 1) {
                int x = sc.nextInt();
                int c = sc.nextInt();

                Segment floor = set.floor(new Segment(x, x, 0));
                if (floor.c == c) continue;

                int L = floor.l;
                int R = floor.r;
                int oldC = floor.c;

                counts[oldC] -= (R - L + 1);
                set.remove(floor);

                while (true) {
                    Segment next = set.ceiling(new Segment(R + 1, R + 1, 0));
                    if (next != null && next.l == R + 1 && next.c == c) {
                        R = next.r;
                        set.remove(next);
                    } else {
                        break;
                    }
                }

                while (true) {
                    Segment prev = set.floor(new Segment(L - 1, L - 1, 0));
                    if (prev != null && prev.r == L - 1 && prev.c == c) {
                        L = prev.l;
                        set.remove(prev);
                    } else {
                        break;
                    }
                }

                set.add(new Segment(L, R, c));
                counts[c] += (R - L + 1);

            } else {
                int c = sc.nextInt();
                out.println(counts[c]);
            }
        }
        out.flush();
        out.close();
    }
