    if (memo.count(state)) {
        return memo[state];
    }

    vector<int>& current = (turn == 1) ? p1 : p2;

    if (current.empty()) {
        return memo[state] = false;
    }

    for (int i = 0; i < current.size(); i++) {
        int token = current[i];

        vector<int> new_current = current;
        new_current.erase(new_current.begin() + i);

        vector<int> new_board = board;
        new_board.push_back(token);

        vector<int> smaller;
        for (int j = 0; j < board.size(); j++) {
            if (board[j] < token) {
                smaller.push_back(j);
            }
        }

        if (smaller.empty()) {
            vector<int> new_p1 = (turn == 1) ? new_current : p1;
            vector<int> new_p2 = (turn == 2) ? new_current : p2;
            if (!canWin(3 - turn, new_p1, new_p2, new_board)) {
                return memo[state] = true;
            }
        } else {
            for (int j : smaller) {
                vector<int> final_current = new_current;
                final_current.push_back(board[j]);

                vector<int> final_board = new_board;
                final_board.erase(final_board.begin() + j);

                vector<int> final_p1 = (turn == 1) ? final_current : p1;
                vector<int> final_p2 = (turn == 2) ? final_current : p2;

                if (!canWin(3 - turn, final_p1, final_p2, final_board)) {
                    return memo[state] = true;
                }
            }
        }
    }

    return memo[state] = false;
}

