bool solve(vector<int> state, int turn) {
    if (memo.count({state, turn})) return memo[{state, turn}];

    bool can_move = false;
    for (int i = 0; i < state.size(); ++i) {
        if (state[i] == turn) {
            can_move = true;
            break;
        }
    }

    if (!can_move) return memo[{state, turn}] = false;

    for (int i = 0; i < state.size(); ++i) {
        if (state[i] == turn) {
            vector<int> next_state = state;
            next_state[i] = 2; 

            bool win = false;
            if (!solve(next_state, 1 - turn)) win = true;

            for (int j = 0; j < state.size(); ++j) {
                if (next_state[j] == 2 && all_values[j] < all_values[i]) {
                    vector<int> take_state = next_state;
                    take_state[j] = turn;
                    if (!solve(take_state, 1 - turn)) win = true;
                }
            }

            if (win) return memo[{state, turn}] = true;
        }
    }

    return memo[{state, turn}] = false;
}

