var memo map[string]bool

func encode(p1, p2, board []int, turn int) string {
	res := fmt.Sprintf("%v|%v|%v|%d", p1, p2, board, turn)
	return res
}

func solve(p1, p2, board []int, turn int) bool {
	state := encode(p1, p2, board, turn)
	if v, ok := memo[state]; ok {
		return v
	}

	var current, other []int
	if turn == 0 {
		current, other = p1, p2
	} else {
		current, other = p2, p1
	}

	if len(current) == 0 {
		memo[state] = false
		return false
	}

	for i := 0; i < len(current); i++ {
		val := current[i]
		newCurrentBase := make([]int, 0, len(current)-1)
		newCurrentBase = append(newCurrentBase, current[:i]...)
		newCurrentBase = append(newCurrentBase, current[i+1:]...)

		newBoardBase := make([]int, 0, len(board)+1)
		newBoardBase = append(newBoardBase, board...)
		newBoardBase = append(newBoardBase, val)

		canTake := false
		for j := 0; j < len(newBoardBase); j++ {
			if newBoardBase[j] < val {
				canTake = true
				takeVal := newBoardBase[j]
				newBoard := make([]int, 0, len(newBoardBase)-1)
				newBoard = append(newBoard, newBoardBase[:j]...)
				newBoard = append(newBoard, newBoardBase[j+1:]...)

				newCurrent := make([]int, 0, len(newCurrentBase)+1)
				newCurrent = append(newCurrent, newCurrentBase...)
				newCurrent = append(newCurrent, takeVal)

				sortInts(newCurrent)
				sortInts(newBoard)

				var win bool
				if turn == 0 {
					win = !solve(newCurrent, other, newBoard, 1)
				} else {
					win = !solve(other, newCurrent, newBoard, 0)
				}
				if win {
					memo[state] = true
					return true
				}
			}
		}

		newBoardNoTake := make([]int, len(newBoardBase))
		copy(newBoardNoTake, newBoardBase)
		sortInts(newBoardNoTake)
		sortInts(newCurrentBase)

		var win bool
		if turn == 0 {
			win = !solve(newCurrentBase, other, newBoardNoTake, 1)
		} else {
			win = !solve(other, newCurrentBase, newBoardNoTake, 0)
		}
		if win {
			memo[state] = true
			return true
		}
	}

	memo[state] = false
	return false
}

func sortInts(arr []int) {
	for i := 0; i < len(arr); i++ {
		for j := i + 1; j < len(arr); j++ {
			if arr[i] > arr[j] {
				arr[i], arr[j] = arr[j], arr[i]
			}
		}
	}
}

