        if (S[i] == 'S') s_indices.push_back(i + 1);
        else if (S[i] == 'E') e_indices.push_back(i + 1);
        else if (S[i] == '/') slash_indices.push_back(i + 1);

        s_pref[i + 1] = s_pref[i] + (S[i] == 'S' ? 1 : 0);
        e_pref[i + 1] = e_pref[i] + (S[i] == 'E' ? 1 : 0);
    }

    while (Q--) {
