        cin >> L >> R;

        auto it_start = lower_bound(slash_indices.begin(), slash_indices.end(), L);
        auto it_end = upper_bound(slash_indices.begin(), slash_indices.end(), R);

        if (it_start == it_end) {
            cout << 0 << "\n";
            continue;
        }

        int low = 0, high = N, best_k = 0;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (mid == 0) {
                best_k = max(best_k, 0);
                low = mid + 1;
                continue;
            }

            auto it_s = lower_bound(s_indices.begin(), s_indices.end(), L);
            int s_pos = -1;
            if (it_s != s_indices.end() && (it_s + mid - 1) < s_indices.end()) {
                s_pos = *(it_s + mid - 1);
