                if (it_slash != slash_indices.end() && *it_slash < e_pos) {
                    best_k = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            } else {
                high = mid - 1;
            }
        }

        if (best_k == 0) {
