func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n, q int
	fmt.Fscanf(reader, "%d %d\n", &n, &q)

	s, _ := reader.ReadString('\n')
	if len(s) > 0 && s[len(s)-1] == '\n' {
		s = s[:len(s)-1]
	}
	if len(s) > 0 && s[len(s)-1] == '\r' {
		s = s[:len(s)-1]
	}

	posS := make([]int, 0, n)
	posE := make([]int, 0, n)
	posSlash := make([]int, 0, n)

	prefixS := make([]int, n+1)
	prefixE := make([]int, n+1)

	for i := 0; i < n; i++ {
		prefixS[i+1] = prefixS[i]
		prefixE[i+1] = prefixE[i]
		if s[i] == 'S' {
			posS = append(posS, i+1)
			prefixS[i+1]++
		} else if s[i] == 'E' {
			posE = append(posE, i+1)
			prefixE[i+1]++
		} else if s[i] == '/' {
			posSlash = append(posSlash, i+1)
		}
	}

	for i := 0; i < q; i++ {
		var l, r int
		fmt.Fscanf(reader, "%d %d\n", &l, &r)

		low := 0
		high := (r - l + 1) / 2
		ans := 0

		firstSlashIdx := lowerBound(posSlash, l)
		lastSlashIdx := upperBound(posSlash, r) - 1

		if firstSlashIdx > lastSlashIdx {
			fmt.Fprintln(writer, 0)
			continue
		}

		low = 0
		high = (r - l) / 2
		bestK := 0

		for low <= high {
			k := (low + high) / 2
			if k == 0 {
				bestK = max(bestK, 0)
				low = k + 1
				continue
			}

			found := false

			sIdx := lowerBound(posS, l)
			if sIdx + k - 1 < len(posS) {
				leftSBound := posS[sIdx+k-1]

				eIdx := upperBound(posE, r) - 1
				if eIdx - k + 1 >= 0 {
					rightEBound := posE[eIdx-k+1]

					slashIdx := lowerBound(posSlash, leftSBound + 1)
					if slashIdx < len(posSlash) && posSlash[slashIdx] < rightEBound {
						found = true
					}
				}
			}

			if found {
				bestK = k
				low = k + 1
			} else {
				high = k - 1
			}
		}

		ans = 2*bestK + 1
		fmt.Fprintln(writer, ans)
	}
}

func lowerBound(arr []int, target int) int {
	low, high := 0, len(arr)
	for low < high {
		mid := low + (high-low)/2
		if arr[mid] < target {
			low = mid + 1
		} else {
			high = mid
		}
	}
	return low
}

func upperBound(arr []int, target int) int {
	low, high := 0, len(arr)
	for low < high {
		mid := low + (high-low)/2
		if arr[mid] <= target {
			low = mid + 1
		} else {
			high = mid
		}
	}
	return low
}

