using namespace std;

struct Tile {
    int id;
    int r, c, l;
};

struct Segment {
    int l, r, val;
    bool operator<(const Segment& other) const {
        if (l != other.l) return l < other.l;
        return r < other.r;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int H, W, N;
    cin >> H >> W >> N;

    vector<Tile> tiles(N);
    vector<vector<int>> tiles_by_row(H + 1);
    for (int i = 0; i < N; ++i) {
        tiles[i].id = i;
        cin >> tiles[i].r >> tiles[i].c >> tiles[i].l;
        tiles_by_row[tiles[i].r].push_back(i);
    }

    set<Segment> odt;
    odt.insert({1, W, H + 1});

    auto split = [&](int pos) {
        auto it = odt.lower_bound({pos, 0, 0});
        if (it != odt.end() && it->l == pos) return it;
        --it;
        int l = it->l, r = it->r, v = it->val;
        odt.erase(it);
        odt.insert({l, pos - 1, v});
        return odt.insert({pos, r, v}).first;
    };

    vector<int> final_r(N);
    for (int r = H; r >= 1; --r) {
        for (int idx : tiles_by_row[r]) {
            int c_start = tiles[idx].c;
            int c_end = tiles[idx].c + tiles[idx].l - 1;

            auto it_end = split(c_end + 1);
            auto it_start = split(c_start);

            int min_h = H + 1;
            for (auto it = it_start; it != it_end; ++it) {
                min_h = min(min_h, it->val);
            }

            int target_r = min_h - 1;
            final_r[idx] = target_r;

            odt.erase(it_start, it_end);
            odt.insert({c_start, c_end, target_r});
        }
    }

    for (int i = 0; i < N; ++i) {
        cout << final_r[i] << "\n";
    }

    return 0;
}

