type SegmentTree struct {
	n    int
	tree []int
}

func newSegmentTree(n int) *SegmentTree {
	size := 1
	for size < n {
		size *= 2
	}
	t := make([]int, 2*size)
	for i := range t {
		t[i] = 1 << 30
	}
	return &SegmentTree{n: size, tree: t}
}

func (st *SegmentTree) update(l, r, val int) {
	l += st.n
	r += st.n
	for l < r {
		if l&1 == 1 {
			if val < st.tree[l] {
				st.tree[l] = val
			}
			l++
		}
		if r&1 == 1 {
			r--
			if val < st.tree[r] {
				st.tree[r] = val
			}
		}
		l >>= 1
		r >>= 1
	}
}

func (st *SegmentTree) query(idx int) int {
	idx += st.n
	res := 1 << 30
	for idx > 0 {
		if st.tree[idx] < res {
			res = st.tree[idx]
		}
		idx >>= 1
	}
	return res
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var H, W, N int
	fmt.Fscan(reader, &H, &W, &N)

	R := make([]int, N)
	C := make([]int, N)
	L := make([]int, N)
	for i := 0; i < N; i++ {
		fmt.Fscan(reader, &R[i], &C[i], &L[i])
	}

	st := newSegmentTree(W + 1)
	st.update(1, W+1, H+1)

	ans := make([]int, N)
	for i := N - 1; i >= 0; i-- {
		minY := 1 << 30
		for j := C[i]; j < C[i]+L[i]; j++ {
			y := st.query(j)
			if y < minY {
				minY = y
			}
		}
		ans[i] = minY - 1
		st.update(C[i], C[i]+L[i], ans[i])
	}

	for i := 0; i < N; i++ {
		fmt.Fprintln(writer, ans[i])
	}
}

