public class Main {
    static class SegmentTree {
        int n;
        int[] tree;

        SegmentTree(int n) {
            this.n = n;
            tree = new int[4 * n];
            Arrays.fill(tree, Integer.MAX_VALUE);
        }

        void update(int node, int start, int end, int l, int r, int val) {
            if (start > end || start > r || end < l) return;
            if (start >= l && end <= r) {
                tree[node] = Math.min(tree[node], val);
                return;
            }
            int mid = (start + end) / 2;
            update(2 * node, start, mid, l, r, val);
            update(2 * node + 1, mid + 1, end, l, r, val);
        }

        int query(int node, int start, int end, int idx) {
            if (start == end) return tree[node];
            int mid = (start + end) / 2;
            int res = tree[node];
            if (idx <= mid) res = Math.min(res, query(2 * node, start, mid, idx));
            else res = Math.min(res, query(2 * node + 1, mid + 1, end, idx));
            return res;
        }
    }

    public static void main(String[] args) throws IOException {
        FastReader sc = new FastReader(System.in);
        int H = sc.nextInt();
        int W = sc.nextInt();
        int N = sc.nextInt();

        int[] R = new int[N];
        int[] C = new int[N];
        int[] L = new int[N];
        Integer[] p = new Integer[N];

        for (int i = 0; i < N; i++) {
            R[i] = sc.nextInt();
            C[i] = sc.nextInt();
            L[i] = sc.nextInt();
            p[i] = i;
        }

        Arrays.sort(p, (a, b) -> Integer.compare(R[b], R[a]));

        SegmentTree st = new SegmentTree(W);
        int[] ans = new int[N];

        for (int idx : p) {
            int r = R[idx];
            int c = C[idx];
            int l = L[idx];

            int minNext = H + 1;
            for (int j = c; j < c + l; ) {
                int val = st.query(1, 1, W, j);
                minNext = Math.min(minNext, val);
                j++;
            }

            ans[idx] = minNext - 1;
            st.update(1, 1, W, c, c + l - 1, ans[idx]);
        }

        PrintWriter out = new PrintWriter(System.out);
        for (int i = 0; i < N; i++) {
            out.println(ans[i]);
        }
        out.flush();
    }

    static class FastReader {
        BufferedReader br;
        StringTokenizer st;

        public FastReader(InputStream in) {
            br = new BufferedReader(new InputStreamReader(in));
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }
    }
