	if x < 0 {
		return -x
	}
	return x
}

func findCell(x, y, C int64) (int64, int64, int64) {
	a := x / C
	b := y / C

	if (a%2 == b%2) {
		c := y - b*C
		return a, b, c
	} else {
		c := x - a*C
		return a, b, c
	}
}

func getAdjacent(a, b, c, C int64) [][3]int64 {
	var adj [][3]int64

	sameParity := (a%2 == b%2)

	if sameParity {
		for dc := int64(-1); dc <= 1; dc += 2 {
			nc := c + dc
			if nc >= 0 && nc < C {
				adj = append(adj, [3]int64{a, b, nc})
			}
		}

		for da := int64(-1); da <= 1; da += 2 {
			na := a + da
			adj = append(adj, [3]int64{na, b, c})
		}
	} else {
		for dc := int64(-1); dc <= 1; dc += 2 {
			nc := c + dc
			if nc >= 0 && nc < C {
				adj = append(adj, [3]int64{a, b, nc})
			}
		}

		for db := int64(-1); db <= 1; db += 2 {
			nb := b + db
			adj = append(adj, [3]int64{a, nb, c})
		}
	}

	return adj
}

func solve(C, startX, startY, endX, endY int64) int64 {
	startA, startB, startC := findCell(startX, startY, C)
	endA, endB, endC := findCell(endX, endY, C)

	if startA == endA && startB == endB && startC == endC {
		return 0
	}

	queue := [][4]int64{{startA, startB, startC, 0}}
	visited := make(map[[3]int64]bool)
	visited[[3]int64{startA, startB, startC}] = true

	for len(queue) > 0 {
		curr := queue[0]
		queue = queue[1:]

		a, b, c, dist := curr[0], curr[1], curr[2], curr[3]

		adj := getAdjacent(a, b, c, C)
		for _, next := range adj {
			na, nb, nc := next[0], next[1], next[2]

			if na == endA && nb == endB && nc == endC {
				return dist + 1
			}

			key := [3]int64{na, nb, nc}
			if !visited[key] {
				visited[key] = true
				queue = append(queue, [4]int64{na, nb, nc, dist + 1})
			}
		}
	}

	return -1
}

