func divFloor(a, b int64) int64 {
	if a >= 0 {
		return a / b
	}
	return (a - b + 1) / b
}

func mod(a, b int64) int64 {
	res := a % b
	if res < 0 {
		res += b
	}
	return res
}

type cell struct {
	a, b, c int64
}

func getCell(x, y, C int64) cell {
	a := divFloor(x, C)
	b := divFloor(y, C)
	if (a+b)%2 == 0 || (a+b)%2 == -0 {
		return cell{a, b, mod(y, C)}
	}
	return cell{a, b, mod(x, C)}
}

func abs(x int64) int64 {
	if x < 0 {
		return -x
	}
	return x
}

