		s := getCell(sx, sy, C)
		e := getCell(ex, ey, C)

		da := abs(s.a - e.a)
		db := abs(s.b - e.b)

		var dist int64
		if da == 0 && db == 0 {
			dist = abs(s.c - e.c)
		} else if da >= db {
			dist = da + db
			var sc, ec int64
			if (s.a+s.b)%2 == 0 {
				sc = 0
			} else {
				sc = s.c
			}
			if (e.a+e.b)%2 == 0 {
				ec = 0
			} else {
				ec = e.c
			}
			dist += abs(sc - ec)
		} else {
			dist = da + db
			var sc, ec int64
			if (s.a+s.b)%2 != 0 {
				sc = 0
			} else {
				sc = s.c
			}
			if (e.a+e.b)%2 != 0 {
				ec = 0
			} else {
				ec = e.c
			}
			dist += abs(sc - ec)
		}
		fmt.Println(dist)
	}
}

