public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;
        int T = sc.nextInt();
        while (T-- > 0) {
            long C = sc.nextLong();
            long sx = sc.nextLong();
            long sy = sc.nextLong();
            long ex = sc.nextLong();
            long ey = sc.nextLong();

            long[] start = getABC(C, sx, sy);
            long[] end = getABC(C, ex, ey);

            long sa = start[0], sb = start[1];
            long ea = end[0], eb = end[1];

            long da = Math.abs(sa - ea);
            long db = Math.abs(sb - eb);

            long dist;
            if (da >= db) {
                dist = 2 * da;
                if ((sa + sb) % 2 != 0) dist++;
                if ((ea + eb) % 2 != 0) dist--;
            } else {
                dist = 2 * db;
                if ((sa + sb) % 2 == 0) dist++;
                if ((ea + eb) % 2 == 0) dist--;
            }
            System.out.println(dist);
        }
    }

    private static long[] getABC(long C, long x, long y) {
        long a, b, c;
        long a_cand = floorDiv(x, C);
        long b_cand = floorDiv(y, C);

        if ((a_cand + b_cand) % 2 == 0) {
            a = a_cand;
            b = b_cand;
            c = floorMod(y, C);
        } else {
            long a_alt = floorDiv(x - floorMod(y, C), C);
            if (a_alt == a_cand) {
                a = a_cand;
                b = b_cand;
                c = floorMod(x, C);
            } else {
                a = a_cand;
                b = b_cand;
                c = floorMod(x, C);
            }
        }
        return new long[]{a, b, c};
    }

    private static long floorDiv(long n, long d) {
        long r = n / d;
        if ((n ^ d) < 0 && (r * d != n)) r--;
        return r;
    }

    private static long floorMod(long n, long d) {
        return n - floorDiv(n, d) * d;
    }
}

