                if (da + db) % 2 == 0:
                    return da + db + abs(c1 - c2)
                else:
                    return da + db + abs(c1 + c2 - (C - 1))
            else:
                return da + db + min(c1 + c2, (C - 1 - c1) + (C - 1 - c2), c1 + (C - 1 - c2), (C - 1 - c1) + c2)

        results.append(str(get_dist_refined(sa, sb, sc, ea, eb, ec, C)))

    sys.stdout.write("\n".join(results) + "\n")

