			if grid[i][j] == '.' {
				openCells = append(openCells, Point{i, j})
			}
		}
	}

	nOpen := len(openCells)
	masks := make([]uint64, nOpen)
	numWords := (nOpen + 63) / 64
	coverage := make([][]uint64, nOpen)

	for i := 0; i < nOpen; i++ {
		coverage[i] = make([]uint64, numWords)
		for j := 0; j < nOpen; j++ {
			dist := abs(openCells[i].x-openCells[j].x) + abs(openCells[i].y-openCells[j].y)
			if dist <= R {
				coverage[i][j/64] |= (1 << (uint(j) % 64))
			}
		}
	}

	maxCovered := 0
	for i := 0; i < nOpen; i++ {
		for j := i + 1; j < nOpen; j++ {
			currentCovered := 0
			for k := 0; k < numWords; k++ {
				combined := coverage[i][k] | coverage[j][k]
				currentCovered += popcount(combined)
			}
			if currentCovered > maxCovered {
				maxCovered = currentCovered
			}
		}
	}

	fmt.Println(maxCovered)
}

func abs(a int) int {
	if a < 0 {
		return -a
	}
	return a
}

func popcount(x uint64) int {
	x = (x & 0x5555555555555555) + ((x >> 1) & 0x5555555555555555)
	x = (x & 0x3333333333333333) + ((x >> 2) & 0x3333333333333333)
	x = (x & 0x0f0f0f0f0f0f0f0f) + ((x >> 4) & 0x0f0f0f0f0f0f0f0f)
	x = (x & 0x00ff00ff00ff00ff) + ((x >> 8) & 0x00ff00ff00ff00ff)
	x = (x & 0x0000ffff0000ffff) + ((x >> 16) & 0x0000ffff0000ffff)
	x = (x & 0x00000000ffffffff) + ((x >> 32) & 0x00000000ffffffff)
	return int(x)
}

