public class Main {
    static class Cell {
        int r, c;
        Cell(int r, int c) {
            this.r = r;
            this.c = c;
        }
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] line1 = br.readLine().split(" ");
        int M = Integer.parseInt(line1[0]);
        int N = Integer.parseInt(line1[1]);
        int R = Integer.parseInt(line1[2]);

        List<Cell> openCells = new ArrayList<>();
        for (int i = 0; i < M; i++) {
            String row = br.readLine();
            for (int j = 0; j < N; j++) {
                if (row.charAt(j) == '.') {
                    openCells.add(new Cell(i, j));
                }
            }
        }

        int K = openCells.size();
        long[] masks = new long[K];
        for (int i = 0; i < K; i++) {
            Cell router = openCells.get(i);
            for (int j = 0; j < K; j++) {
                Cell target = openCells.get(j);
                if (Math.abs(router.r - target.r) + Math.abs(router.c - target.c) <= R) {
                    masks[i] |= (1L << j);
                }
            }
        }

        int maxCovered = 0;
        if (K <= 62) {
            for (int i = 0; i < K; i++) {
                for (int j = i + 1; j < K; j++) {
                    maxCovered = Math.max(maxCovered, Long.bitCount(masks[i] | masks[j]));
                }
            }
        } else {
            BitSet[] bsets = new BitSet[K];
            for (int i = 0; i < K; i++) {
                bsets[i] = new BitSet(K);
                Cell router = openCells.get(i);
                for (int j = 0; j < K; j++) {
                    Cell target = openCells.get(j);
                    if (Math.abs(router.r - target.r) + Math.abs(router.c - target.c) <= R) {
                        bsets[i].set(j);
                    }
                }
            }
            for (int i = 0; i < K; i++) {
                for (int j = i + 1; j < K; j++) {
                    BitSet combined = (BitSet) bsets[i].clone();
                    combined.or(bsets[j]);
                    maxCovered = Math.max(maxCovered, combined.cardinality());
                }
            }
        }

        System.out.println(maxCovered);
    }
}

