    open_cells = []
    for r in range(M):
        for c in range(N):
            if grid[r][c] == '.':
                open_cells.append((r, c))

    num_open = len(open_cells)
    masks = []
    for r, c in open_cells:
        mask = 0
        for i in range(num_open):
            or_r, or_c = open_cells[i]
            if abs(r - or_r) + abs(c - or_c) <= R:
                mask |= (1 << i)
        masks.append(mask)

    max_covered = 0

    if num_open <= 25:
        for i in range(num_open):
            m1 = masks[i]
            for j in range(i + 1, num_open):
                combined = m1 | masks[j]
                count = bin(combined).count('1')
                if count > max_covered:
                    max_covered = count
    else:
        unique_masks = list(set(masks))
        num_unique = len(unique_masks)
        for i in range(num_unique):
            m1 = unique_masks[i]
            for j in range(i, num_unique):
                combined = m1 | unique_masks[j]
                count = bin(combined).count('1')
                if count > max_covered:
                    max_covered = count

    sys.stdout.write(str(max_covered) + '\n')

