type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool { return pq[i].maxWeight < pq[j].maxWeight }
func (pq PriorityQueue) Swap(i, j int) { pq[i], pq[j] = pq[j], pq[i] }
func (pq *PriorityQueue) Push(x interface{}) { *pq = append(*pq, x.(*Item)) }
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func dijkstra(graph [][]Edge, start int, n int) []int {
	dist := make([]int, n+1)
	for i := range dist {
		dist[i] = 1e9
	}
	dist[start] = 0

	pq := &PriorityQueue{}
	heap.Init(pq)
	heap.Push(pq, &Item{start, 0})

	for pq.Len() > 0 {
		current := heap.Pop(pq).(*Item)
		node := current.node
		maxWeight := current.maxWeight

		if maxWeight > dist[node] {
			continue
		}

		for _, edge := range graph[node] {
			newMaxWeight := maxWeight
			if edge.weight > newMaxWeight {
				newMaxWeight = edge.weight
			}

			if newMaxWeight < dist[edge.to] {
				dist[edge.to] = newMaxWeight
				heap.Push(pq, &Item{edge.to, newMaxWeight})
			}
		}
	}

	return dist
}

