struct DSU {
    vector<int> parent;
    vector<int> a_count;
    vector<int> b_count;
    DSU(int n) {
        parent.resize(n + 1);
        a_count.assign(n + 1, 0);
        b_count.assign(n + 1, 0);
        for (int i = 1; i <= n; ++i) parent[i] = i;
    }
    int find(int i) {
        if (parent[i] == i) return i;
        return parent[i] = find(parent[i]);
    }
    void unite(int i, int j, int weight, long long &total_cost) {
        int root_i = find(i);
        int root_j = find(j);
        if (root_i != root_j) {
            long long pairs_before = min((long long)a_count[root_i], (long long)b_count[root_i]) + 
                                     min((long long)a_count[root_j], (long long)b_count[root_j]);

            parent[root_i] = root_j;
            a_count[root_j] += a_count[root_i];
            b_count[root_j] += b_count[root_i];

            long long pairs_after = min((long long)a_count[root_j], (long long)b_count[root_j]);
            total_cost += (pairs_after - pairs_before) * weight;
        }
    }
};

