func newDSU(n int) *DSU {
	p := make([]int, n+1)
	s := make([]int, n+1)
	for i := 1; i <= n; i++ {
		p[i] = i
		s[i] = 1
	}
	return &DSU{parent: p, size: s, aCount: make([]int, n+1), bCount: make([]int, n+1)}
}

func (d *DSU) find(i int) int {
	if d.parent[i] == i {
		return i
	}
	d.parent[i] = d.find(d.parent[i])
	return d.parent[i]
}

func (d *DSU) union(i, j int) (int, int, bool) {
	rootI := d.find(i)
	rootJ := d.find(j)
	if rootI != rootJ {
		if d.size[rootI] < d.size[rootJ] {
			rootI, rootJ = rootJ, rootI
		}
		d.parent[rootJ] = rootI
		d.size[rootI] += d.size[rootJ]
		oldA, oldB := d.aCount[rootI], d.bCount[rootI]
		d.aCount[rootI] += d.aCount[rootJ]
		d.bCount[rootI] += d.bCount[rootJ]
		return oldA, oldB, true
	}
	return 0, 0, false
}

