        }

        long target = s % totalSum;
        if (target == 0) {
            System.out.println("Yes");
            return;
        }

        long[] prefixSums = new long[2 * n + 1];
        for (int i = 0; i < 2 * n; i++) {
            prefixSums[i + 1] = prefixSums[i] + l[i % n];
        }

        int right = 0;
        for (int left = 0; left < n; left++) {
            while (right < 2 * n && prefixSums[right] - prefixSums[left] < target) {
                right++;
