	fmt.Fscan(reader, &p, &q)
	p--
	q--

	grid := make([][]int64, h)
	for i := 0; i < h; i++ {
		grid[i] = make([]int64, w)
		for j := 0; j < w; j++ {
			fmt.Fscan(reader, &grid[i][j])
		}
