def can_partition(weights, k, target):
    if k == 1:
        return sum(weights) == target
    if k > len(weights):
        return target == 0
    if not weights:
        return k == 0 and target == 0


    if weights[0] <= target:
        remaining = weights[1:]
        if weights[0] == target:
            if can_partition(remaining, k-1, target):
                return True
        else:
            if can_partition(remaining, k, target - weights[0]):
                return True


    if len(weights) > k:
        if can_partition(weights[1:], k, target):
            return True

    return False

def solve(W, X, Y):
    total = W + X + Y
    weights = [W, X, Y]


    for k in range(2, total + 1):
        if total % k == 0:
            target = total
            if can_partition(weights, k, target):
                return True

    return False

