        for (int j = 0; j < sz; ++j) {
            int i = j - 1;
            int k = j + 1;
            while (i >= 0 && k < sz) {
                int diff1 = indices[j] - indices[i];
                int diff2 = indices[k] - indices[j];

                if (diff1 == diff2) {
                    dp[j][k] = dp[i][j] + 1;
                    if (dp[j][k] > max_trees) max_trees = dp[j][k];
                    i--;
                    k++;
                } else if (diff1 > diff2) {
                    k++;
                } else {
                    i--;
                }
            }
        }
    }

