public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] firstLine = br.readLine().split(" ");
        int K = Integer.parseInt(firstLine[0]);
        int N = Integer.parseInt(firstLine[1]);
        long Px = Long.parseLong(firstLine[2]);
        long Py = Long.parseLong(firstLine[3]);

        Set<String> waypoints = new HashSet<>();
        for (int i = 0; i < N; i++) {
            String[] coords = br.readLine().split(" ");
            long a = Long.parseLong(coords[0]);
            long b = Long.parseLong(coords[1]);
            waypoints.add(a + "," + b);
        }

        Set<String> visited = new HashSet<>();
        long x = Px, y = Py;

        for (int i = 0; i < K; i++) {
            String[] command = br.readLine().split(" ");
            char direction = command[0].charAt(0);
            long distance = Long.parseLong(command[1]);

            long newX = x, newY = y;
            if (direction == 'N') {
                newY = y + distance;
            } else if (direction == 'S') {
                newY = y - distance;
            } else if (direction == 'W') {
                newX = x - distance;
            } else if (direction == 'E') {
                newX = x + distance;
            }

            for (String waypoint : waypoints) {
                String[] parts = waypoint.split(",");
                long wx = Long.parseLong(parts[0]);
                long wy = Long.parseLong(parts[1]);

                if (isOnPath(x, y, newX, newY, wx, wy)) {
                    visited.add(waypoint);
                }
            }

            x = newX;
            y = newY;
        }

        System.out.println(x + " " + y + " " + visited.size());
    }

    private static boolean isOnPath(long x1, long y1, long x2, long y2, long px, long py) {
        if (x1 == x2) {
            if (px != x1) return false;
            long minY = Math.min(y1, y2);
            long maxY = Math.max(y1, y2);
            return py >= minY && py <= maxY;
        } else {
            if (py != y1) return false;
            long minX = Math.min(x1, x2);
            long maxX = Math.max(x1, x2);
            return px >= minX && px <= maxX;
        }
    }
}

