}

func getSubtreeSize(adj [][]int, root, parent int) int {
    size := 1
    for _, child := range adj[root] {
        if child != parent {
            size += getSubtreeSize(adj, child, root)
        }
    }
    return size
}

func tryAllSubsets(subtreeSizes []int) int {
    n := len(subtreeSizes)
    maxKeep := 0

    for mask := 1; mask < (1 << n); mask++ {
        selected := []int{}
        for i := 0; i < n; i++ {
            if (mask & (1 << i)) != 0 {
                selected = append(selected, subtreeSizes[i])
            }
        }

        keep := tryAsGalaxy(selected)
        if keep > maxKeep {
            maxKeep = keep
        }
    }

    return maxKeep
}

func tryAsGalaxy(branchSizes []int) int {
    if len(branchSizes) == 0 {
        return 0
    }

    maxKeep := 0

    for y := 1; y <= 300000; y++ {
        keep := 1
        valid := true

        for _, size := range branchSizes {
            if size < 1+y {
                valid = false
                break
            }
            keep += 1 + y
        }

        if valid && keep > maxKeep {
            maxKeep = keep
        }
    }

    return maxKeep
}

