            String[] parts = br.readLine().split(" ");
            int u = Integer.parseInt(parts[0]);
            int v = Integer.parseInt(parts[1]);
            adj[u].add(v);
            adj[v].add(u);
        }

        int maxKeep = 0;

        for (int center = 1; center <= n; center++) {
            maxKeep = Math.max(maxKeep, calculateMaxKeep(center));
        }

        System.out.println(n - maxKeep);
    }

    static int calculateMaxKeep(int center) {
        List<Integer> branches = adj[center];
        if (branches.isEmpty()) return 1;

        List<Integer> satelliteCounts = new ArrayList<>();

        for (int branch : branches) {
            int satellites = 0;
            for (int neighbor : adj[branch]) {
                if (neighbor != center) {
                    if (adj[neighbor].size() == 1) {
                        satellites++;
                    }
                }
            }
            satelliteCounts.add(satellites);
        }

        int maxNodes = 0;

        for (int y = 0; y <= 300000; y++) {
            int validBranches = 0;
            int totalSatellites = 0;

            for (int satCount : satelliteCounts) {
                if (satCount >= y) {
                    validBranches++;
                    totalSatellites += y;
                }
            }

            if (validBranches > 0) {
                int totalNodes = 1 + validBranches + totalSatellites;
                maxNodes = Math.max(maxNodes, totalNodes);
            }
        }

        return maxNodes;
    }
}

