        FastReader fr = new FastReader();
        n = fr.nextInt();
        adj = new ArrayList[n + 1];
        for (int i = 1; i <= n; i++) adj[i] = new ArrayList<>();
        for (int i = 0; i < n - 1; i++) {
            int u = fr.nextInt();
            int v = fr.nextInt();
            adj[u].add(v);
            adj[v].add(u);
        }

        if (n < 3) {
            System.out.println(0);
            return;
        }

        int minDeleted = n;

        for (int center = 1; center <= n; center++) {
            if (adj[center].size() < 1) continue;

            int totalNodesInStructure = 1;
            List<Integer> childContributions = new ArrayList<>();

            for (int neighbor : adj[center]) {
                int deg = adj[neighbor].size();
                if (deg >= 1) {
                    childContributions.add(deg);
                }
            }

            Collections.sort(childContributions);

            int m = childContributions.size();
            int[] suffixSum = new int[m + 1];
            for (int i = m - 1; i >= 0; i--) {
                suffixSum[i] = suffixSum[i + 1] + childContributions.get(i);
            }

            for (int k = 1; k <= m; k++) {
                int y = childContributions.get(m - k) - 1;
                if (y < 1) continue;

                int currentStructureSize = 1 + k + k * y;
                minDeleted = Math.min(minDeleted, n - currentStructureSize);
            }
        }

        System.out.println(minDeleted);
    }

    static class FastReader {
        BufferedReader br;
        StringTokenizer st;

        public FastReader() {
            br = new BufferedReader(new InputStreamReader(System.in));
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }
    }
