        } else {
            System.out.printf("%.20f\n", Math.max(0.0, maxH));
        }
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean hasNextByte() {
            if (pointer < bufferLength) return true;
            pointer = 0;
            try {
                bufferLength = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            return bufferLength > 0;
        }

        private int readByte() {
            return hasNextByte() ? buffer[pointer++] : -1;
        }

        public int nextInt() {
            int b = readByte();
            while (b != -1 && b <= 32) b = readByte();
            if (b == -1) return -1;
            int n = 0;
            boolean minus = false;
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            while (b >= '0' && b <= '9') {
                n = n * 10 + (b - '0');
                b = readByte();
            }
            return minus ? -n : n;
        }

        public long nextLong() {
            int b = readByte();
            while (b != -1 && b <= 32) b = readByte();
            if (b == -1) return -1;
            long n = 0;
            boolean minus = false;
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            while (b >= '0' && b <= '9') {
                n = n * 10 + (b - '0');
                b = readByte();
            }
            return minus ? -n : n;
        }
    }
}

