    }

    static boolean isSweetCombo(Map<Integer, Integer> count) {
        List<Integer> frequencies = new ArrayList<>(count.values());
        Collections.sort(frequencies, Collections.reverseOrder());

        return frequencies.size() == 2 && 
               frequencies.get(0) == 3 && 
               frequencies.get(1) == 2;
    }
