using namespace std;

bool is_sweet_combo(vector<int> candies) {
    map<int, int> counts;
    for (int x : candies) {
        counts[x]++;
    }
    if (counts.size() != 2) return false;
    vector<int> v;
    for (auto const& [key, val] : counts) {
        v.push_back(val);
    }
    sort(v.begin(), v.end());
