func isSweetCombo(nums []int) bool {
	counts := make(map[int]int)
	for _, val := range nums {
		counts[val]++
	}

	if len(counts) != 2 {
		return false
	}

	var freq []int
	for _, v := range counts {
		freq = append(freq, v)
	}
	sort.Ints(freq)

	return freq[0] == 2 && freq[1] == 3
}

