                if (p.charAt(i) != q.charAt(i)) {
                    diffCount++;
                }
            }
            return diffCount <= 1;
        }

        if (n < m) {
            return checkOneInsertion(p, q);
        } else {
            return checkOneInsertion(q, p);
        }
    }

    private static boolean checkOneInsertion(String shorter, String longer) {
        int n = shorter.length();
        int m = longer.length();
        int i = 0;
        int j = 0;
        boolean skipped = false;

        while (i < n && j < m) {
            if (shorter.charAt(i) == longer.charAt(j)) {
                i++;
                j++;
            } else {
                if (skipped) {
                    return false;
                }
                skipped = true;
                j++;
            }
        }
        return true;
    }
