func backtrack(idx, rem int, currentXor uint64, a []uint64, maxVal *uint64) {
	if rem == 0 {
		if currentXor > *maxVal {
			*maxVal = currentXor
		}
		return
	}
	if idx+rem > len(a) {
		return
	}

	backtrack(idx+1, rem-1, currentXor^a[idx], a, maxVal)
	backtrack(idx+1, rem, currentXor, a, maxVal)
}

