    input_data = sys.stdin.read().split()
    if not input_data:
        return
    M = int(input_data[0])
    B = [int(x) for x in input_data[1:]]

    def get_type(k):
        if k % 2 == 1:
            if (k
                return 1
            else:
                return 0
        else:
            return get_type(k

    def is_pinnacle(idx):
        return get_type(idx) == 1

    memo = {}

    def find_max(active_indices, depth):
        if not active_indices:
            return 0

        state = tuple(sorted(active_indices))
        if state in memo:
            return memo[state]

        even_indices = []
        odd_indices = []
        for b in active_indices:
            if b % 2 == 0:
                even_indices.append(b
            else:
                odd_indices.append(b)

        res = 0

        for j_mod_2 in [0, 1]:
            current_active = []
            current_p_count = 0

            for b_idx in even_indices:
                current_active.append(b_idx)

            for b_val in odd_indices:
                if is_pinnacle(j_mod_2 + b_val):
                    current_p_count += 1

            res = max(res, current_p_count + find_max(current_active, depth + 1))

        memo[state] = res
        return res

    print(find_max(B, 0))

