		dp[i] = make([][]int, n+2)
		for j := range dp[i] {
			dp[i][j] = make([]int, n+2)
		}
	}

	dp[0][0][n+1] = 1

	for i := 0; i < n; i++ {
		for low := 0; low <= n; low++ {
