func applyR(config []int) []int {
	result := make([]int, len(config))
	sum := 0
	for i := 0; i < len(config); i++ {
		sum ^= config[i]
		result[i] = sum
	}
	return result
}

func configToString(config []int) string {
	result := ""
	for _, v := range config {
		if v == 0 {
			result += "0"
		} else {
			result += "1"
		}
	}
	return result
}

func findG(config1, config2 []int) int {
	c1 := make([]int, len(config1))
	c2 := make([]int, len(config2))
	copy(c1, config1)
	copy(c2, config2)

	seen := make(map[string]int)

	for steps := 0; steps < 1000000; steps++ {
		s1 := configToString(c1)
		s2 := configToString(c2)

		if s1 == s2 {
			return steps
		}

		key := s1 + "|" + s2
		if _, exists := seen[key]; exists {
			return 0
		}
		seen[key] = steps

		c1 = applyR(c1)
		c2 = applyR(c2)
	}

	return 0
}

