typedef long long ll;

const int MOD = 998244353;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, M;
    if (!(cin >> N >> M)) return 0;

    vector<vector<int>> configs(N, vector<int>(M));
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < M; ++j) {
            cin >> configs[i][j];
        }
    }

    auto get_state = [&](vector<int> c) {
        int first_one = -1;
        for (int j = 0; j < M; ++j) {
            if (c[j] == 1) {
                first_one = j;
                break;
            }
        }
        if (first_one == -1) return make_pair(-1, vector<int>());

        vector<int> rel(M - first_one);
        rel[0] = 1;
        for (int j = 1; j < M - first_one; ++j) {
            rel[j] = (c[first_one + j] ^ c[first_one + j - 1]);
        }
        return make_pair(first_one, rel);
    };

    map<vector<int>, vector<int>> groups;
    for (int i = 0; i < N; ++i) {
        auto res = get_state(configs[i]);
        if (res.first != -1) {
            groups[res.second].push_back(res.first);
        }
    }

    ll total_g = 0;
    for (auto const& [pattern, pos_list] : groups) {
        map<int, int> counts;
        for (int p : pos_list) counts[p]++;

        vector<pair<int, int>> sorted_counts(counts.begin(), counts.end());
        int sz = sorted_counts.size();

        for (int i = 0; i < sz; ++i) {
            ll c1 = sorted_counts[i].second;
            ll g_ii = 0;
            total_g = (total_g + (c1 * (c1 + 1) / 2) % MOD * g_ii) % MOD;

            for (int j = i + 1; j < sz; ++j) {
                ll c2 = sorted_counts[j].second;
                int diff = sorted_counts[j].first - sorted_counts[i].first;

                int x = 0;
                if (diff > 0) {
                    int k = 0;
                    while ((1 << k) <= diff) {
                        if ((diff >> k) & 1) x |= (1 << k);
                        k++;
                    }
                }
                total_g = (total_g + (c1 * c2) % MOD * x) % MOD;
            }
        }
    }

    cout << total_g << endl;

    return 0;
}

