import (
	"bufio"
	"fmt"
	"os"
)

func main() {
	reader := bufio.NewReader(os.Stdin)
	var n, m int
	fmt.Fscan(reader, &n, &m)

	configs := make([][]int, n)
	for i := 0; i < n; i++ {
		configs[i] = make(int, m)
		for j := 0; j < m; j++ {
			fmt.Fscan(reader, &configs[i][j])
		}
	}

	pow2 := 1
	for pow2 < m {
		pow2 <<= 1
	}

	type Node struct {
		children [2]*Node
		count    int
	}
	root := &Node{}

	for i := 0; i < n; i++ {
		curr := root
		for j := 0; j < m; j++ {
			v := configs[i][j]
			if curr.children[v] == nil {
				curr.children[v] = &Node{}
			}
			curr = curr.children[v]
		}
		curr.count++
	}

	ans := 0
	mod := 998244353

	var solve func(nodes []*Node, depth int, x int)
	solve = func(nodes []*Node, depth int, x int) {
		if depth == m {
			cnts := make([]int, len(nodes))
			total := 0
			for i, node := range nodes {
				cnts[i] = node.count
				total += node.count
			}
			for i := 0; i < len(nodes); i++ {
				for j := i; j < len(nodes); j++ {
					term := (int64(cnts[i]) * int64(cnts[j])) % int64(mod)
					ans = (ans + int(term)*x) % mod
				}
			}
			return
		}

		groups := make(map[string][]*Node)
		for _, node := range nodes {
			c0, c1 := node.children[0], node.children[1]
			var key string
			if c0 == nil && c1 == nil {
				key = "nil"
			} else if c0 != nil && c1 != nil {
				key = "both"
			} else if c0 != nil {
				key = "0"
			} else {
				key = "1"
			}
			groups[key] = append(groups[key], node)
		}

		if nodes0, ok := groups["0"]; ok {
			next := make([]*Node, 0)
			for _, n := range nodes0 {
				next = append(next, n.children[0])
			}
			solve(next, depth+1, x)
		}
		if nodes1, ok := groups["1"]; ok {
			next := make([]*Node, 0)
			for _, n := range nodes1 {
				next = append(next, n.children[1])
			}
			solve(next, depth+1, x)
		}
		if nodesBoth, ok := groups["both"]; ok {
			step := 1
			for (depth+1+step) <= m && ((depth+1)%step == 0) {
				step <<= 1
			}
			step >>= 1

			if x == 0 {
				newX := 1
				for newX < (depth + 1) {
					newX <<= 1
				}

				for _, n := range nodesBoth {
					solve([]*Node{n.children[0], n.children[1]}, depth+1, newX)
				}
			} else {
				next := make([]*Node, 0)
				for _, n := range nodesBoth {
					next = append(next, n.children[0], n.children[1])
				}
				solve(next, depth+1, x)
			}
		}
	}

	solve([]*Node{root}, 0, 0)
	fmt.Println(ans)
}

