                System.out.println("Yes");
            } else {
                System.out.println("No");
            }
        }
    }

    static boolean canMakeNonDecreasing(long[] A) {
        int N = A.length;
        long[] B = A.clone();


        for (int i = N - 2; i >= 0; i--) {

            if (B[i] > B[i+1]) {

                long excess = B[i] - B[i+1];
                B[i] = B[i+1];


                for (int j = i + 1; j < N && excess > 0; j++) {
                    long canAdd = excess;
                    B[j] += canAdd;
                    excess -= canAdd;
                }

                if (excess > 0) {
                    return false;
                }
            }
        }


        long originalSum = 0, newSum = 0;
        for (int i = 0; i < N; i++) {
            originalSum += A[i];
            newSum += B[i];
        }

        return originalSum == newSum;
    }
}

