    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 16];
        private int ptr = 0;
        private int len = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean hasNextByte() {
            if (ptr < len) return true;
            ptr = 0;
            try {
                len = in.read(buffer);
            } catch (IOException e) {
                return false;
            }
            return len > 0;
        }

        private int readByte() {
            return hasNextByte() ? buffer[ptr++] : -1;
        }

        public int nextInt() {
            int n = 0;
            int b = readByte();
            while (b != -1 && (b < '0' || b > '9')) b = readByte();
            while (b >= '0' && b <= '9') {
                n = n * 10 + (b - '0');
                b = readByte();
            }
            return n;
        }
    }
