    static int[] computeFailure(int[] pattern) {
        int m = pattern.length;
        int[] failure = new int[m];
        failure[0] = 0;

        int j = 0;
        for (int i = 1; i < m; i++) {
            while (j > 0 && pattern[i] != pattern[j]) {
                j = failure[j - 1];
            }
            if (pattern[i] == pattern[j]) {
                j++;
            }
            failure[i] = j;
        }

        return failure;
    }

    static int getNextState(int[] pattern, int[] failure, int currentState, int color) {
        int j = currentState;

        while (j > 0 && pattern[j] != color) {
            j = failure[j - 1];
        }

        if (j < pattern.length && pattern[j] == color) {
            j++;
        }

        return j;
    }
}

