                must_same[y].push_back(x);
            } else {
                must_diff[x].push_back(y);
                must_diff[y].push_back(x);
            }
        } else {
            if (z == 0) {
                must_diff[x].push_back(y);
                must_diff[y].push_back(x);
            } else {
                must_same[x].push_back(y);
                must_same[y].push_back(x);
            }
        }
    }

    vector<int> color(n, -1);

    for (int start = 0; start < n; start++) {
        if (color[start] != -1) continue;

        vector<int> stack = {start};
        color[start] = 0;

        while (!stack.empty()) {
            int u = stack.back();
            stack.pop_back();

            for (int v : must_same[u]) {
                if (color[v] == -1) {
                    color[v] = color[u];
                    stack.push_back(v);
