public class Main {
    static class Edge {
        int to, type;
        Edge(int to, int type) {
            this.to = to;
            this.type = type;
        }
    }

    public static void main(String[] args) throws IOException {
        FastReader sc = new FastReader(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();

        List<Edge>[] adj = new ArrayList[n + 1];
        for (int i = 1; i <= n; i++) adj[i] = new ArrayList<>();

        for (int i = 0; i < m; i++) {
            int x = sc.nextInt();
            int y = sc.nextInt();
            int z = sc.nextInt();
            adj[x].add(new Edge(y, z));
        }

        int[] color = new int[n + 1];
        Arrays.fill(color, -1);
        int[] erratic = new int[n + 1];

        for (int i = 1; i <= n; i++) {
            if (color[i] == -1) {
                if (!solveComponent(i, adj, color, erratic)) {
                    System.out.println("-1");
                    return;
                }
            }
        }

        StringBuilder sb = new StringBuilder();
        for (int i = 1; i <= n; i++) {
            sb.append(erratic[i]);
        }
        System.out.println(sb.toString());
    }

    private static boolean solveComponent(int start, List<Edge>[] adj, int[] color, int[] erratic) {
        int[] tempColor = new int[color.length];
        int[] tempErratic = new int[color.length];

        for (int startVal = 0; startVal <= 1; startVal++) {
            boolean possible = true;
            Queue<Integer> q = new LinkedList<>();

            for(int i=0; i<color.length; i++) tempColor[i] = -1;

            tempColor[start] = startVal;
            tempErratic[start] = 0;
            q.add(start);

            Set<Integer> visited = new HashSet<>();
            visited.add(start);

            while (!q.isEmpty()) {
                int u = q.poll();
                for (Edge e : adj[u]) {
                    int v = e.to;
                    int expectedVColor = tempColor[u] ^ e.type ^ tempErratic[u];
                    if (tempColor[v] == -1) {
                        tempColor[v] = expectedVColor;
                        tempErratic[v] = 0;
                        q.add(v);
                        visited.add(v);
                    } else {
                        if (tempColor[v] != expectedVColor) {
                            if (tempErratic[v] == 0) {
                                tempErratic[v] = 1;
                            } else {
                                possible = false;
                                break;
                            }
                        }
                    }
                }
                if (!possible) break;
            }

            if (possible) {
                for (int node : visited) {
                    color[node] = tempColor[node];
                    erratic[node] = tempErratic[node];
                }
                return true;
            }
        }
        return false;
    }

    static class FastReader {
        BufferedReader br;
        StringTokenizer st;

        public FastReader(InputStream in) {
            br = new BufferedReader(new InputStreamReader(in));
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }
    }
}

