func solve(current []int, target []int, memo map[string]int) int {
	key := stateToString(current)
	if val, exists := memo[key]; exists {
		return val
	}

	if equal(current, target) {
		memo[key] = 1
		return 1
	}

	n := len(current)
	count := 0

	for l := 0; l < n; l++ {
		for r := l + 2; r < n; r++ {
			if current[l] == current[r] {
				canApply := true
				for i := l + 1; i < r; i++ {
					if current[i] == current[l] {
						canApply = false
						break
					}
				}

				if canApply {
					newState := make([]int, n)
					copy(newState, current)
					for i := l + 1; i < r; i++ {
						newState[i] = current[l]
					}

					count = (count + solve(newState, target, memo)) % MOD
				}
			}
		}
	}

	memo[key] = count
	return count
}

func equal(a, b []int) bool {
	if len(a) != len(b) {
		return false
	}
	for i := 0; i < len(a); i++ {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}

func stateToString(state []int) string {
	result := ""
	for _, val := range state {
		if val == 0 {
			result += "0"
		} else {
			result += "1"
		}
	}
	return result
}

