    inv[total_ops] = pow(fact[total_ops], mod - 2, mod)
    for i in range(total_ops - 1, -1, -1):
        inv[i] = (inv[i+1] * (i + 1)) % mod

    ans = fact[total_ops]
    for count in ops_needed:
        ans = (ans * inv[count]) % mod

    for count in ops_needed:
        if count > 0:
            ans = (ans * pow(count, count - 1, mod)) % mod

