map<vector<long long>, long long> memo;

long long solve(vector<long long> p) {
    if (memo.count(p)) return memo[p];

    long long n = p.size();
    if (n < 4) {
        long long sum = 0;
        for (long long x : p) sum += x;
        return memo[p] = sum;
    }

    long long sum = 0;
    for (long long x : p) sum += x;
    long long result = sum;

    for (int i = 0; i <= n - 4; i++) {
        vector<long long> np = p;
        long long mid = p[i] + p[i+3];
        np[i+1] = mid - p[i+1];
        np[i+2] = mid - p[i+2];
        sort(np.begin(), np.end());
        result = min(result, solve(np));
    }

    return memo[p] = result;
}

