import java.util.*;
import java.io.*;

public class Main {
    static class FastReader {
        BufferedReader br;
        StringTokenizer st;

        public FastReader() {
            br = new BufferedReader(new InputStreamReader(System.in));
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }
    }

    public static void main(String[] args) {
        FastReader fr = new FastReader();
        int N = fr.nextInt();
        int X = fr.nextInt() - 1;
        int[] A = new int[N];
        for (int i = 0; i < N; i++) A[i] = fr.nextInt();
        int[] B = new int[N];
        for (int i = 0; i < N; i++) B[i] = fr.nextInt();
        int[] P = new int[N];
        for (int i = 0; i < N; i++) P[i] = fr.nextInt() - 1;
        int[] Q = new int[N];
        for (int i = 0; i < N; i++) Q[i] = fr.nextInt() - 1;

        int[] distP = getDist(N, P, X);
        int[] distQ = getDist(N, Q, X);

        int ans = 0;
        for (int i = 0; i < N; i++) {
            if (A[i] > 0) {
                if (distP[i] == -1) {
                    System.out.println("-1");
                    return;
                }
                ans = Math.max(ans, distP[i]);
            }
            if (B[i] > 0) {
                if (distQ[i] == -1) {
                    System.out.println("-1");
                    return;
                }
                ans = Math.max(ans, distQ[i]);
            }
        }
        System.out.println(ans);
    }

    private static int[] getDist(int N, int[] perm, int target) {
        int[] inv = new int[N];
        for (int i = 0; i < N; i++) inv[perm[i]] = i;

        int[] dist = new int[N];
        Arrays.fill(dist, -1);

        boolean[] visited = new boolean[N];
        List<Integer> cycle = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            if (!visited[i]) {
                cycle.clear();
                int curr = i;
                while (!visited[curr]) {
                    visited[curr] = true;
                    cycle.add(curr);
                    curr = perm[curr];
                }

                int targetIdx = -1;
                for (int j = 0; j < cycle.size(); j++) {
                    if (cycle.get(j) == target) {
                        targetIdx = j;
                        break;
                    }
                }

                if (targetIdx != -1) {
                    int len = cycle.size();
                    for (int j = 0; j < len; j++) {
                        int node = cycle.get(j);
                        int d = (targetIdx - j + len) % len;
                        dist[node] = d;
                    }
                }
            }
        }
        return dist;
    }
}

