        for (int k = 0; k < n; k++) {
            results[k] = solve(a, k);
        }

        for (int i = 0; i < n; i++) {
            if (i > 0) System.out.print(" ");
            System.out.print(results[i]);
        }
        System.out.println();
    }

    static int solve(int[] original, int startPos) {
        ArrayList<Integer> aliens = new ArrayList<>();
        for (int x : original) {
            aliens.add(x);
        }

        int jordanPos = startPos;
        int jordanSize = aliens.get(jordanPos);

        while (true) {
            boolean absorbed = false;


            if (jordanPos > 0 && aliens.get(jordanPos - 1) < jordanSize) {
                jordanSize += aliens.get(jordanPos - 1);
                aliens.remove(jordanPos - 1);
                jordanPos--;
                aliens.set(jordanPos, jordanSize);
                absorbed = true;
            }

            else if (jordanPos < aliens.size() - 1 && aliens.get(jordanPos + 1) < jordanSize) {
                jordanSize += aliens.get(jordanPos + 1);
                aliens.remove(jordanPos + 1);
                aliens.set(jordanPos, jordanSize);
                absorbed = true;
            }

            if (!absorbed) break;
        }

        return jordanSize;
    }
}

