typedef long long ll;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    if (!(cin >> N)) return 0;

    vector<ll> A(N);
    for (int i = 0; i < N; ++i) {
        cin >> A[i];
    }

    vector<ll> pref(N + 1, 0);
    for (int i = 0; i < N; ++i) {
        pref[i + 1] = pref[i] + A[i];
    }

    auto get_sum = [&](int l, int r) {
        return pref[r + 1] - pref[l];
    };

    vector<int> L(N), R(N);
    stack<int> s;

    for (int i = 0; i < N; ++i) {
        while (!s.empty() && A[s.top()] < A[i]) {
            s.pop();
        }
        L[i] = s.empty() ? -1 : s.top();
        s.push(i);
    }

    while (!s.empty()) s.pop();

    for (int i = N - 1; i >= 0; --i) {
        while (!s.empty() && A[s.top()] < A[i]) {
            s.pop();
        }
        R[i] = s.empty() ? N : s.top();
        s.push(i);
    }

    vector<ll> ans(N);
    vector<int> reachL(N), reachR(N);

    for (int i = 0; i < N; ++i) {
        reachL[i] = i;
        reachR[i] = i;
    }

    vector<int> p(N);
    for (int i = 0; i < N; ++i) p[i] = i;
    sort(p.begin(), p.end(), [&](int i, int j) {
        return A[i] < A[j];
    });

    for (int i : p) {
        int curL = i, curR = i;
        while (true) {
            bool changed = false;
            ll curSum = get_sum(curL, curR);

            int nextL = L[curL];
            if (nextL != -1 && A[nextL] < curSum) {
                curR = max(curR, reachR[nextL]);
                curL = reachL[nextL];
                changed = true;
            }

            curSum = get_sum(curL, curR);
            int nextR = R[curR];
            if (nextR != N && A[nextR] < curSum) {
                curL = min(curL, reachL[nextR]);
                curR = reachR[nextR];
                changed = true;
            }

            if (!changed) break;
        }
        reachL[i] = curL;
        reachR[i] = curR;
        ans[i] = get_sum(curL, curR);
    }

    for (int i = 0; i < N; ++i) {
        cout << ans[i] << (i == N - 1 ? "" : " ");
    }
    cout << endl;

    return 0;
}

