func solve() {
	in := bufio.NewReader(os.Stdin)
	out := bufio.NewWriter(os.Stdout)
	defer out.Flush()

	var n int
	fmt.Fscan(in, &n)

	a := make([]int64, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(in, &a[i])
	}

	pref := make([]int64, n+1)
	for i := 0; i < n; i++ {
		pref[i+1] = pref[i] + a[i]
	}

	getSum := func(l, r int) int64 {
		return pref[r+1] - pref[l]
	}

	lft := make([]int, n)
	rgt := make([]int, n)
	stack := make([]int, 0, n)

	for i := 0; i < n; i++ {
		for len(stack) > 0 && a[stack[len(stack)-1]] < a[i] {
			stack = stack[:len(stack)-1]
		}
		if len(stack) == 0 {
			lft[i] = -1
		} else {
			lft[i] = stack[len(stack)-1]
		}
		stack = append(stack, i)
	}

	stack = stack[:0]
	for i := n - 1; i >= 0; i-- {
		for len(stack) > 0 && a[stack[len(stack)-1]] < a[i] {
			stack = stack[:len(stack)-1]
		}
		if len(stack) == 0 {
			rgt[i] = n
		} else {
			rgt[i] = stack[len(stack)-1]
		}
		stack = append(stack, i)
	}

	res := make([]int64, n)
	for i := 0; i < n; i++ {
		res[i] = a[i]
	}

	type rangeNode struct {
		l, r int
		val  int64
	}

	for i := 0; i < n; i++ {
		cl, cr := i, i
		cv := a[i]
		for {
			nl, nr := cl, cr
			canExpand := false
			if cl > 0 && a[cl-1] < cv {
				nl = lft[cl-1] + 1
				canExpand = true
			}
			if cr < n-1 && a[cr+1] < cv {
				nr = rgt[cr+1] - 1
				canExpand = true
			}

			if !canExpand {
				break
			}

			nv := getSum(nl, nr)
			if nv == cv {
				break
			}
			cl, cr, cv = nl, nr, nv
		}
		res[i] = cv
	}

	for i := 0; i < n; i++ {
		fmt.Fprint(out, res[i])
		if i < n-1 {
			fmt.Fprint(out, " ")
		}
	}
	fmt.Fprintln(out)
}

