import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    a = list(map(int, input_data[1:]))

    left_nearest_greater = [-1] * n
    stack = []
    for i in range(n):
        while stack and a[stack[-1]] < a[i]:
            stack.pop()
        if stack:
            left_nearest_greater[i] = stack[-1]
        stack.append(i)

    right_nearest_greater = [n] * n
    stack = []
    for i in range(n - 1, -1, -1):
        while stack and a[stack[-1]] < a[i]:
            stack.pop()
        if stack:
            right_nearest_greater[i] = stack[-1]
        stack.append(i)

    prefix_sum = [0] * (n + 1)
    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + a[i]

    def get_sum(l, r):
        if l > r:
            return 0
        return prefix_sum[r + 1] - prefix_sum[l]

    ans = [0] * n
    memo = {}

    def get_max_size(i, l, r):
        state = (l, r)
        if state in memo:
            return memo[state]

        current_sum = get_sum(l, r)

        can_expand_l = l > 0 and a[l-1] < current_sum
        can_expand_r = r < n - 1 and a[r+1] < current_sum

        if not can_expand_l and not can_expand_r:
            memo[state] = current_sum
            return current_sum

        nl, nr = l, r
        while True:
            changed = False
            if nl > 0 and a[nl-1] < current_sum:
                nl = left_nearest_greater[nl-1] + 1
                current_sum = get_sum(nl, nr)
                changed = True
            if nr < n - 1 and a[nr+1] < current_sum:
                nr = right_nearest_greater[nr+1] - 1
                current_sum = get_sum(nl, nr)
                changed = True
            if not changed:
                break

        res = get_max_size(i, nl, nr)
        memo[state] = res
        return res

    for i in range(n):
        l, r = i, i
        current_sum = a[i]
        while True:
            changed = False
            if l > 0 and a[l-1] < current_sum:
                l = left_nearest_greater[l-1] + 1
                current_sum = get_sum(l, r)
                changed = True
            if r < n - 1 and a[r+1] < current_sum:
                r = right_nearest_greater[r+1] - 1
                current_sum = get_sum(l, r)
                changed = True
            if not changed:
                break
        ans[i] = current_sum

    print(*(ans))

